        m_systematicFits_Isolated_NotInvariant_Plus[partIndex][centIndex][rapIndex] = NULL;
        m_totalSpectra_Minus[partIndex][centIndex][rapIndex] = NULL;
        m_totalSpectra_NotInvariant_Minus[partIndex][centIndex][rapIndex] = NULL;
        //m_totalSpectraInclusive_Minus[partIndex][centIndex][rapIndex] = NULL;
        //m_totalSpectraInclusive_NotInvariant_Minus[partIndex][centIndex][rapIndex] = NULL;
        m_totalSpectra_Minus_RapVals[partIndex][centIndex][rapIndex] = 0.0;
        m_nominalFits_Minus[partIndex][centIndex][rapIndex] = NULL;
        m_nominalFits_NotInvariant_Minus[partIndex][centIndex][rapIndex] = NULL;
        m_systematicFits_Minus[partIndex][centIndex][rapIndex] = NULL;
        m_systematicFits_NotInvariant_Minus[partIndex][centIndex][rapIndex] = NULL;
        m_SimPartBWFits_Minus[partIndex][centIndex][rapIndex] = NULL;
        m_nominalFits_Isolated_Minus[partIndex][centIndex][rapIndex] = NULL;
        m_nominalFits_Isolated_NotInvariant_Minus[partIndex][centIndex][rapIndex] = NULL;
        m_systematicFits_Isolated_Minus[partIndex][centIndex][rapIndex] = NULL;
        m_systematicFits_Isolated_NotInvariant_Minus[partIndex][centIndex][rapIndex] = NULL;
        m_totalSpectra_Symmetric_Plus[partIndex][centIndex][rapIndex] = NULL;
