        m_systematicFits_Symmetric_Minus[partIndex][centIndex][rapIndex] = NULL;
        m_SimPartBWFits_Symmetric_Minus[partIndex][centIndex][rapIndex] = NULL;
        m_bootstrapData_Nom_Plus[partIndex][centIndex][rapIndex] = NULL;
        m_bootstrapData_Nom_Minus[partIndex][centIndex][rapIndex] = NULL;
        m_bootstrapData_Sys_Plus[partIndex][centIndex][rapIndex] = NULL;
        m_bootstrapData_Sys_Minus[partIndex][centIndex][rapIndex] = NULL;
        m_bootstrapData_SimPartBW_Plus[partIndex][centIndex][rapIndex] = NULL;
        m_bootstrapData_SimPartBW_Minus[partIndex][centIndex][rapIndex] = NULL;

        m_nominalFitsCovMat_Isolated_Plus[partIndex][centIndex][rapIndex] = NULL;
