double SpectraFitter::blastWaveModelFit(double *x, double *par){

  //double mTm0  = x[0]; //mT-m0
  //double Amp   = par[0]; //Amplitude
  //double T     = par[1]; //Tkin
  //double betaS = par[2]; //Surface Velocity
  //double n     = par[3]; //Power in the Tranverse Velocity factor (betaT) (Fixed to 1.0)
  //double R     = par[4]; //Upper Limit of Radial Integral (SHOULD BE FIXED)
  //double mass  = par[5]; //Should be FIXED

  //######  Radial Integral for the Blast Wave Model  ########
  m_blastWaveIntegrand->FixParameter(0,x[0]);
  m_blastWaveIntegrand->FixParameter(1,fabs(par[1]));
  m_blastWaveIntegrand->FixParameter(2,par[2]);
  m_blastWaveIntegrand->FixParameter(3,par[3]);
  m_blastWaveIntegrand->FixParameter(4,par[5]); //bc removed R parameter
  #ifdef _SPECTRA_FITTER_NUMERIC_BLASTWAVE_INTEGRATION_
    double integral = 0.5*m_blastWaveIntegrand->Eval(0.0);
    for(double evalPoint = 0.04; evalPoint < 0.999; evalPoint+= 0.04){
      integral += m_blastWaveIntegrand->Eval(evalPoint);
    }
    integral += 0.5*m_blastWaveIntegrand->Eval(1.0);
    integral = integral*0.04;
    return par[0] * integral / (par[1]);
  #else
    return par[0] * m_blastWaveIntegrand->Integral(0.0,1.0) / (par[1]);
  #endif
}






//_________________________________________________________________________________________________________________________________________________________________________________________________________
double SpectraFitter::blastWaveModelFit_NotInvariant(double *x, double *par){
  /*double r   = 0.0; //Integration Variable The lower limit of integration is 0.0
  double sum = 0.0;
  double rho = 0.0;
  double mT  = x[0] + par[5];
  for(unsigned int iStep = 0; iStep < 200; iStep++){
    rho  = TMath::ATanH(par[2] * pow(r,par[3]));
    sum += r * mT * TMath::BesselI0((sqrt((mT*mT)-(par[5]*par[5]))/par[1]) * TMath::SinH(rho)) * TMath::BesselK1((mT/par[1]) * TMath::CosH(rho)) * 0.005;
    r   += 0.005;
  }
  return 2.0 * TMath::Pi() * mT * par[0] * sum / (par[1]);*/

  //######  Radial Integral for the Blast Wave Model  ########
  m_blastWaveIntegrand->FixParameter(0,x[0]);
  m_blastWaveIntegrand->FixParameter(1,par[1]);
  m_blastWaveIntegrand->FixParameter(2,par[2]);
  m_blastWaveIntegrand->FixParameter(3,par[3]);
  m_blastWaveIntegrand->FixParameter(4,par[5]); //bc removed R parameter

  #ifdef _SPECTRA_FITTER_NUMERIC_BLASTWAVE_INTEGRATION_
    double integral = 0.0;
    for(double evalPoint = 0.0; evalPoint < 0.9999; evalPoint+= 0.01){
      integral += m_blastWaveIntegrand->Eval(evalPoint);
    }
    integral = integral*0.01;
    return 2.0 * TMath::Pi() * (x[0] + par[5]) * par[0] * integral / (par[1]);
  #else
    return 2.0 * TMath::Pi() * (x[0] + par[5]) * par[0] * m_blastWaveIntegrand->Integral(0.0,1.0) / (par[1]);
  #endif
}

