double SpectraFitter::blastWaveModelFit_NotInvariant_WithLegendreTempAndBetaS(double *x, double *par){
  //######  Radial Integral for the Blast Wave Model  ########
  double Temp = par[1] + par[2]*PhysMath::legendre(2,2.0*par[11]/par[4]) + par[3]*PhysMath::legendre(4,2.0*par[11]/par[4]);
  m_blastWaveIntegrand->FixParameter(0,x[0]);
  m_blastWaveIntegrand->FixParameter(1,Temp);
  m_blastWaveIntegrand->FixParameter(2,par[5] + par[6]*PhysMath::legendre(2,2.0*par[11]/par[8]) + par[7]*PhysMath::legendre(4,2.0*par[11]/par[8]));
  m_blastWaveIntegrand->FixParameter(3,par[9]);
  m_blastWaveIntegrand->FixParameter(4,par[10]); //bc removed R parameter
  return 2.0 * TMath::Pi() * (x[0] + par[10]) * par[0] * m_blastWaveIntegrand->Integral(0.0,1.0) / Temp;
}


//_________________________________________________________________________________________________________________________________________________________________________________________________________
double SpectraFitter::doubleBoseEinstein_VC_fit(double *x, double *par){

  double mTm0     = x[0]; //mT-m0
  double ampLow   = par[0]; //Amplitude
  double TLow     = par[1]; //Tkin
  double mass     = par[2]; //Should be FIXED
  double VC       = par[3]; // VC
  double ampHigh  = par[4]; //Amplitude High
  double THigh    = par[5]; //Tkin High


  double Tpro_amp[7] = {0.252297,0.23596,0.20449,0.188534,0.163917,0.13915,0.127722};
  double Tpro_sig[7] = {1.57028,1.44414,1.37874,1.43276,1.37272,1.35113,1.46965};

  //Compute mT and pT
  double mT = mTm0 + mass;
  double mom = PhysMath::pTot_from_y_mTm0(m_currentRapValue - m_cuts->getYCM(),mTm0,mass);
  double Ef = mT*TMath::CosH(m_currentRapValue - m_cuts->getYCM());
  double Tp = Tpro_amp[m_currentCentIndex]/TMath::CosH(Tpro_sig[m_currentCentIndex]*(m_currentRapValue - m_cuts->getYCM()));
  double mPro = m_partInfo->GetParticleMass(2);
  double Emax = sqrt(pow(mPro*mom/mass,2)+pow(mPro,2))-mPro;
  double Veff = VC*(1-exp(-Emax/Tp));

  //if(m_currentCharge == 1) return (sqrt(pow(Ef-Veff,2)-mass*mass)*(Ef-Veff)/(mom*Ef))*(ampLow/(exp((Ef-Veff)/TLow)-1.0) + ampHigh/(exp((Ef-Veff)/THigh)-1.0));
  //else return (sqrt(pow(Ef+Veff,2)-mass*mass)*(Ef+Veff)/(mom*Ef))*(ampLow/(exp((Ef+Veff)/TLow)-1.0) + ampHigh/(exp((Ef+Veff)/THigh)-1.0));

  if(m_currentCharge == 1) return (Ef*sqrt(pow(Ef-Veff,2)-mass*mass)*(Ef-Veff)/(mom*Ef))*(ampLow/(exp((Ef-Veff)/TLow)-1.0)/(6.283185307179586 * TLow) + ampHigh/(exp((Ef-Veff)/THigh)-1.0)/(6.283185307179586 * THigh));
  else return (Ef*sqrt(pow(Ef+Veff,2)-mass*mass)*(Ef+Veff)/(mom*Ef))*(ampLow/(exp((Ef+Veff)/TLow)-1.0)/(6.283185307179586 * TLow) + ampHigh/(exp((Ef+Veff)/THigh)-1.0)/(6.283185307179586 * THigh));
}

