      double x1 = 0;
      double y1 = 0;
      m_currentSpectra->GetPoint(p1,x1,y1);

      int p2 = HistogramUtilities::getPointClosestToVal(m_currentSpectra,0.8);
      double x2 = 0;
      double y2 = 0;
      m_currentSpectra->GetPoint(p2,x2,y2);

      double tempHigh = (x1-x2)/log(y2/y1);
      double invTempHigh = 1.0/tempHigh;

