    double temp = (x1-x2)/log(y2/y1);
    if(temp <= 0.0 || !std::isfinite(temp)){
      temp = 0.2;
      cout << "Warning: Temperature initialization failed for boltzmann function, setting temp to " << temp << endl;
    }
    if(m_temperatureSeed > 0.0) temp = m_temperatureSeed;
    funct_to_initialize->SetParameter(0,1.0);
    //funct_to_initialize->SetParLimits(0,0.1*countPredict,10.0*countPredict);
