void SpectraFitter::init_simul_blastWave(){
  cout << "Initializing Simultaneous Blast Wave" << endl;

  m_liveRapidityProtonSpectra.clear();
  vector<double> initAmps;
  int numSpectraToFit = 0;

  double betaS_init = 0.65;
  double avgTemp = 0.0;

  if(m_currentCharge == 1){
    for(int rapIndex = 0; rapIndex < g_SpecFit_MaxNumRapBins; rapIndex++){
      TGraphErrors* spectrum = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][rapIndex];
      if(!spectrum) continue;
      double numPoints = spectrum->GetN();
      if(numPoints > 4){
        cout << "   RapIndex " << rapIndex << " will be included in the fit with N: " << spectrum->GetN() << endl;
        m_liveRapidityProtonSpectra.push_back(rapIndex);
        int p1 = numPoints/3;
        double x1 = 0;
        double y1 = 0;
        spectrum->GetPoint(p1,x1,y1);

        int p2 = 2*numPoints/3;
        double x2 = 0;
        double y2 = 0;
        spectrum->GetPoint(p2,x2,y2);



        double temp = (x1-x2)/log(y2/y1);
        if(m_temperatureSeed > 0.0) temp = m_temperatureSeed;
        avgTemp += temp;


        m_blastWave->SetParameter(0,1.0);
        m_blastWave->SetParameter(1,temp);
        m_blastWave->SetParameter(2,betaS_init);
        initAmps.push_back( y1/m_blastWave->Eval(x1) );

        numSpectraToFit++;

        cout << "   Amp: " << initAmps[initAmps.size()-1] << " Temp: " << temp << " Beta_S: " << betaS_init << endl;
      }
    }
  }else{
    for(int rapIndex = 0; rapIndex < g_SpecFit_MaxNumRapBins; rapIndex++){
      TGraphErrors* spectrum = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][rapIndex];
      if(!spectrum) continue;
      double numPoints = spectrum->GetN();
      if(numPoints > 4){
        cout << "   RapIndex " << rapIndex << " will be included in the fit with N: " << spectrum->GetN() << endl;
        m_liveRapidityProtonSpectra.push_back(rapIndex);
        int p1 = numPoints/3;
        double x1 = 0;
        double y1 = 0;
        spectrum->GetPoint(p1,x1,y1);

        int p2 = 2*numPoints/3;
        double x2 = 0;
        double y2 = 0;
        spectrum->GetPoint(p2,x2,y2);

        double temp = (x1-x2)/log(y2/y1);


        if(m_temperatureSeed > 0.0) temp = m_temperatureSeed;
        avgTemp += temp;

        m_blastWave->SetParameter(0,1.0);
        m_blastWave->SetParameter(1,temp);
        m_blastWave->SetParameter(2,betaS_init); //limits already set in constructor [0,1]

        initAmps.push_back( y1/m_blastWave->Eval(x1) );

        numSpectraToFit++;

        cout << "   Amp: " << initAmps[initAmps.size()-1] << " Temp: " << temp << " Beta_S: " << betaS_init << endl;
      }
    }
  }
  cout << "Now setting up the minimizer " << endl;

  avgTemp = avgTemp/((double) numSpectraToFit);

  cout << "Avg: Temp: " << avgTemp << endl;

  m_minimizer = ROOT::Math::Factory::CreateMinimizer();
  cout << "Created Minimizer " << m_minimizer << endl;
  m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_blastWave_ChiSqr,(2*numSpectraToFit) + 1);
  cout << "created chi squared functor with NDim " << m_chiSqrdFunctor->NDim() << "  functor: " << &SpectraFitter::simultaneous_blastWave_ChiSqr  << endl;
  m_minimizer->SetFunction(*m_chiSqrdFunctor);


  cout << "InitAmpSize " << initAmps.size() << "  numYToFit " << numSpectraToFit << " numParams " << (2*numSpectraToFit) + 1 << endl;
  cout << "Live Spectra Indicies: ";
  for(int iii = 0; iii < 2*initAmps.size(); iii += 2 ){
     //cout << "initAmp: " << initAmps[iii] << endl;
     cout << " " << m_liveRapidityProtonSpectra[iii/2];
     m_minimizer->SetVariable(iii, Form("A_%02d",m_liveRapidityProtonSpectra[iii/2]), initAmps[iii/2], 1.0);
     m_minimizer->SetVariableLimits(iii, 0.01*initAmps[iii/2], 100.0*initAmps[iii/2]);
     m_minimizer->SetVariable(iii+1, Form("Beta_S_%02d", m_liveRapidityProtonSpectra[iii/2]), betaS_init, 1.0);
     m_minimizer->SetVariableLimits(iii+1, 0.00, 1.0);
     //m_minimizer->SetVariable(0.0,10000.0*initAmps[iii]);
  }
  cout << endl;

  m_minimizer->SetVariable(2*initAmps.size(), "T" ,avgTemp, 1.0);
  m_minimizer->SetVariableLimits(2*initAmps.size(),0.0, 2.0);
  //m_minimizer->SetVariable(0.0,10.0 * avgTemp);

  //m_minimizer->SetVariable(initAmps.size() + 1,"betaS", betaS_init, betaS_init/10000.0);
  //m_minimizer->SetVariableLimits(initAmps.size() + 1, 0.01, betaS_init*10.0 );
  //m_minimizer->SetVariable(0.0,1.0);


}

