void SpectraFitter::init_simul_particle_blastWave(){
  cout << "Initializing Simultaneous Particle Blast Wave" << endl;

  double betaS_init = 0.65;
  double avgTemp = 0.0;

  vector<double> initAmps;
  for(int partIndex = 0; partIndex < 3; partIndex++){

    m_blastWave->SetParameter(0,1.0);
    m_blastWave->SetParameter(1,0.1);
    m_blastWave->SetParameter(2,betaS_init);
    m_blastWave->FixParameter(3,0.5);
    m_blastWave->FixParameter(4,1.0);
    m_blastWave->FixParameter(5,m_partInfo->GetParticleMass(partIndex));
    //Positive
    TGraphErrors* spectrum = m_totalSpectra_Plus[partIndex][m_currentCentIndex][m_currentRapIndex];
    double numPoints = spectrum->GetN();
    int p1 = numPoints/3;
    double x1 = 0;
    double y1 = 0;
    spectrum->GetPoint(p1,x1,y1);
    int p2 = 2*numPoints/3;
    double x2 = 0;
    double y2 = 0;
    spectrum->GetPoint(p2,x2,y2);

    double temp = (x1-x2)/log(y2/y1);
    if(m_temperatureSeed > 0.0) temp = m_temperatureSeed;
    avgTemp += temp;
    m_blastWave->SetParameter(1,temp);

    initAmps.push_back( y1/m_blastWave->Eval(x1) );
    cout << "  " << m_partInfo->GetParticleName(partIndex,1).Data() << "  Amp: " << initAmps[initAmps.size()-1] << " Temp: " << temp << " Beta_S: " << betaS_init << endl;

    //Negative
    spectrum = m_totalSpectra_Minus[partIndex][m_currentCentIndex][m_currentRapIndex];
    numPoints = spectrum->GetN();
    p1 = numPoints/3;
    spectrum->GetPoint(p1,x1,y1);
    p2 = 2*numPoints/3;
    spectrum->GetPoint(p2,x2,y2);

    temp = (x1-x2)/log(y2/y1);
    if(m_temperatureSeed > 0.0) temp = m_temperatureSeed;
    avgTemp += temp;
    m_blastWave->SetParameter(1,temp);

    initAmps.push_back( y1/m_blastWave->Eval(x1) );
    cout << "  " << m_partInfo->GetParticleName(partIndex,-1).Data() << "  Amp: " << initAmps[initAmps.size()-1] << " Temp: " << temp << " Beta_S: " << betaS_init << endl;

  }

  avgTemp = avgTemp/6.0;
  cout << "Avg: Temp: " << avgTemp << endl;
  cout << "Now setting up the minimizer " << endl;
  //if(m_minimizer) delete m_minimizer;
  m_minimizer = ROOT::Math::Factory::CreateMinimizer();
  cout << "Created Minimizer " << m_minimizer << endl;
  //if(m_chiSqrdFunctor) delete m_chiSqrdFunctor;
  m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneousParticle_blastWave_ChiSqr,8);
  cout << "created chi squared functor with NDim " << m_chiSqrdFunctor->NDim() << "  functor: " << &SpectraFitter::simultaneousParticle_blastWave_ChiSqr  << endl;
  m_minimizer->SetFunction(*m_chiSqrdFunctor);


  m_minimizer->SetVariable(0, "A_PionPlus", initAmps[0], 0.1*initAmps[0]);
  m_minimizer->SetVariableLimits(0, 0.05*initAmps[0], 20.0*initAmps[0]);
  m_minimizer->SetVariable(1, "A_PionMinus", initAmps[1], 0.1*initAmps[1]);
  m_minimizer->SetVariableLimits(1, 0.05*initAmps[1], 20.0*initAmps[1]);
  m_minimizer->SetVariable(2, "A_KaonPlus", initAmps[2], 0.1*initAmps[2]);
  m_minimizer->SetVariableLimits(2, 0.05*initAmps[2], 20.0*initAmps[2]);
  m_minimizer->SetVariable(3, "A_KaonMinus", initAmps[3], 0.1*initAmps[3]);
  m_minimizer->SetVariableLimits(3, 0.05*initAmps[3], 20.0*initAmps[3]);
  m_minimizer->SetVariable(4, "A_ProtonPlus", initAmps[4], 0.1*initAmps[4]);
  m_minimizer->SetVariableLimits(4, 0.05*initAmps[4], 20.0*initAmps[4]);
  m_minimizer->SetVariable(5, "A_ProtonMinus", initAmps[5], 0.1*initAmps[5]);
  m_minimizer->SetVariableLimits(5, 0.05*initAmps[5], 20.0*initAmps[5]);

  m_minimizer->SetVariable(6, "T" ,avgTemp, 0.1);
  m_minimizer->SetVariableLimits(6,0.0, 2.5);

  m_minimizer->SetVariable(7, "Beta_S", betaS_init, 0.1);
  m_minimizer->SetVariableLimits(7, 0.0, 1.0);


}


