double SpectraFitter::simultaneous_blastWave_betaConstr_ChiSqr(const double* a_param){
  double chiSquared = 0.0;

  if(m_currentCharge == 1){
    for(int iii = 0; iii < m_liveRapidityProtonSpectra.size(); iii++){
      //cout << "Trying yIndex=" << m_liveRapidityProtonSpectra[iii] << endl;
      TGraphErrors* spectrum = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]];
      m_blastWave->SetParameter(0,a_param[iii]);
      m_blastWave->SetParameter(1,a_param[m_liveRapidityProtonSpectra.size()]);


      m_blastWave->SetParameter(2,a_param[m_liveRapidityProtonSpectra.size()+1]*pow(m_liveRapidityValueProtonSpectra[iii]- a_param[m_liveRapidityProtonSpectra.size()+2],4)+a_param[m_liveRapidityProtonSpectra.size()+3]*pow(m_liveRapidityValueProtonSpectra[iii]- a_param[m_liveRapidityProtonSpectra.size()+2],2)+a_param[m_liveRapidityProtonSpectra.size()+4]);

      if(SpectraFitter::getBlastWaveNFix() > 0) m_blastWave->FixParameter(3,a_param[m_liveRapidityProtonSpectra.size()+5]);
      else m_blastWave->SetParameter(3,a_param[m_liveRapidityProtonSpectra.size()+5]);

/*
      cout << "chiSq bS A4: " << a_param[m_liveRapidityProtonSpectra.size()+1] << endl;
      cout << "chiSq bS mu: " << a_param[m_liveRapidityProtonSpectra.size()+2] << endl;
      cout << "chiSq bS A2: " << a_param[m_liveRapidityProtonSpectra.size()+3] << endl;
      cout << "chiSq bS C: " << a_param[m_liveRapidityProtonSpectra.size()+4] << endl;

      cout << "chiSq bS x-mu: " << m_liveRapidityValueProtonSpectra[iii]- a_param[m_liveRapidityProtonSpectra.size()+2] << endl;

      cout << "chiSq bS 4 term: " << a_param[m_liveRapidityProtonSpectra.size()+1]*pow(m_liveRapidityValueProtonSpectra[iii]- a_param[m_liveRapidityProtonSpectra.size()+2],4) << endl;
      cout << "chiSq bS 2 term: " << a_param[m_liveRapidityProtonSpectra.size()+3]*pow(m_liveRapidityValueProtonSpectra[iii]- a_param[m_liveRapidityProtonSpectra.size()+2],2) << endl;
      cout << "chiSq betaS: " << m_blastWave->GetParameter(2) << endl;
*/
      //cout << "  Set BlastWave Parameters" << endl;
      //cout << "  Number of Points = " << spectrum->GetN() << endl;
      for(int pointIndex = 0; pointIndex < spectrum->GetN(); pointIndex++){
        double X_ofPoint = spectrum->GetX()[pointIndex];
        double Y_ofPoint = spectrum->GetY()[pointIndex];
        //cout << "got xy of point " << pointIndex << endl;
        double errorY = spectrum->GetErrorY(pointIndex);
        double expected = m_blastWave->Eval(X_ofPoint);
        //cout << "  calc expected " << expected << endl;
        chiSquared+=(Y_ofPoint - expected)*(Y_ofPoint - expected)/ (errorY*errorY);
      }//loop over points
    }
  }else{
    for(int iii = 0; iii < m_liveRapidityProtonSpectra.size(); iii++){
      TGraphErrors* spectrum = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]];
      m_blastWave->SetParameter(0,a_param[iii]);
      m_blastWave->SetParameter(1,a_param[m_liveRapidityProtonSpectra.size()]);
      m_blastWave->SetParameter(2,a_param[m_liveRapidityProtonSpectra.size()+1]*pow(m_liveRapidityValueProtonSpectra[iii]- a_param[m_liveRapidityProtonSpectra.size()+2],4)+a_param[m_liveRapidityProtonSpectra.size()+3]*pow(m_liveRapidityValueProtonSpectra[iii]- a_param[m_liveRapidityProtonSpectra.size()+2],2)+a_param[m_liveRapidityProtonSpectra.size()+4]);
      if(SpectraFitter::getBlastWaveNFix() > 0) m_blastWave->FixParameter(3,a_param[m_liveRapidityProtonSpectra.size()+5]);
      else m_blastWave->SetParameter(3,a_param[m_liveRapidityProtonSpectra.size()+5]);
      for(int pointIndex = 0; pointIndex < spectrum->GetN(); pointIndex++){
        double X_ofPoint = spectrum->GetX()[pointIndex];
        double Y_ofPoint = spectrum->GetY()[pointIndex];
        double errorY = spectrum->GetErrorY(pointIndex);
        double expected = m_blastWave->Eval(X_ofPoint);
        chiSquared+=(Y_ofPoint - expected)*(Y_ofPoint - expected)/ (errorY*errorY);
      }//loop over points
    }
  }
  return chiSquared;
}

//############################################################################################################

double SpectraFitter::simultaneous_blastWave_betaConstr_forceSymmetry_ChiSqr(const double* a_param){
  double chiSquared = 0.0;

  int numSpectraToFit = m_liveRapidityProtonSpectra.size() - m_currentMidRapIndex;

  if(m_currentCharge == 1){
    for(int iii = m_currentMidRapIndex; iii < m_liveRapidityProtonSpectra.size(); iii++){
      //cout << "Trying yIndex=" << m_liveRapidityProtonSpectra[iii] << endl;
      TGraphErrors* spectrum = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]];
      m_blastWave->SetParameter(0,a_param[iii - m_currentMidRapIndex]);
      m_blastWave->SetParameter(1,a_param[numSpectraToFit]);


      m_blastWave->SetParameter(2,a_param[numSpectraToFit+1]*pow(m_liveRapidityValueProtonSpectra[iii]- a_param[numSpectraToFit+2],4)+a_param[numSpectraToFit+3]*pow(m_liveRapidityValueProtonSpectra[iii]- a_param[numSpectraToFit+2],2)+a_param[numSpectraToFit+4]);

      if(SpectraFitter::getBlastWaveNFix() > 0) m_blastWave->FixParameter(3,a_param[numSpectraToFit+5]);
      else m_blastWave->SetParameter(3,a_param[numSpectraToFit+5]);

      for(int pointIndex = 0; pointIndex < spectrum->GetN(); pointIndex++){
        double X_ofPoint = spectrum->GetX()[pointIndex];
        double Y_ofPoint = spectrum->GetY()[pointIndex];
        //cout << "got xy of point " << pointIndex << endl;
        double errorY = spectrum->GetErrorY(pointIndex);
        double expected = m_blastWave->Eval(X_ofPoint);
        //cout << "  calc expected " << expected << endl;
        chiSquared+=(Y_ofPoint - expected)*(Y_ofPoint - expected)/ (errorY*errorY);
      }//loop over points

      if(iii != m_currentMidRapIndex && (2*m_currentMidRapIndex - iii) >= 0 && m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[2*m_currentMidRapIndex - iii]]){
        spectrum = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[2*m_currentMidRapIndex - iii]];
        for(int pointIndex = 0; pointIndex < spectrum->GetN(); pointIndex++){
          double X_ofPoint = spectrum->GetX()[pointIndex];
          double Y_ofPoint = spectrum->GetY()[pointIndex];
          //cout << "got xy of point " << pointIndex << endl;
          double errorY = spectrum->GetErrorY(pointIndex);
          double expected = m_blastWave->Eval(X_ofPoint);
          //cout << "  calc expected " << expected << endl;
          chiSquared+=(Y_ofPoint - expected)*(Y_ofPoint - expected)/ (errorY*errorY);
        }//loop over points
      }

    }
  }else{
    for(int iii = 0; iii < m_liveRapidityProtonSpectra.size(); iii++){
      TGraphErrors* spectrum = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]];
      m_blastWave->SetParameter(0,a_param[iii]);
      m_blastWave->SetParameter(1,a_param[m_liveRapidityProtonSpectra.size()]);
      m_blastWave->SetParameter(2,a_param[m_liveRapidityProtonSpectra.size()+1]*pow(m_liveRapidityValueProtonSpectra[iii]- a_param[m_liveRapidityProtonSpectra.size()+2],4)+a_param[m_liveRapidityProtonSpectra.size()+3]*pow(m_liveRapidityValueProtonSpectra[iii]- a_param[m_liveRapidityProtonSpectra.size()+2],2)+a_param[m_liveRapidityProtonSpectra.size()+4]);
      if(SpectraFitter::getBlastWaveNFix() > 0) m_blastWave->FixParameter(3,a_param[m_liveRapidityProtonSpectra.size()+5]);
      else m_blastWave->SetParameter(3,a_param[m_liveRapidityProtonSpectra.size()+5]);
      for(int pointIndex = 0; pointIndex < spectrum->GetN(); pointIndex++){
        double X_ofPoint = spectrum->GetX()[pointIndex];
        double Y_ofPoint = spectrum->GetY()[pointIndex];
        double errorY = spectrum->GetErrorY(pointIndex);
        double expected = m_blastWave->Eval(X_ofPoint);
        chiSquared+=(Y_ofPoint - expected)*(Y_ofPoint - expected)/ (errorY*errorY);
      }//loop over points
    }
  }
  return chiSquared;
}


//############################################################################################################
//############################################################################################################


double SpectraFitter::simultaneous_blastWave_Legendre_BetaS_And_Temp_Plus_ChiSqr(const double* a_param){
  // 0                   -> numSpectraToFit - 1   : Amplitudes
  // numSpectraToFit     -> numSpectraToFit + 3   : legendre for temp   1 + x^2 + x^4 + widthparam
  // numSpectraToFit + 4 -> numSpectraToFit + 7   : legendre for betaS  1 + x^2 + x^4 + widthparam
  double chiSquared = 0.0;
  unsigned int numSpectraToFit = m_liveRapiditySpectra.size();
  for(int spectrumIndex = 0; spectrumIndex < numSpectraToFit; spectrumIndex++){
    TGraphErrors* spectrum = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapiditySpectra[spectrumIndex]];
    double TwoRap = 2.0*m_liveRapidityValueSpectra[spectrumIndex];
    m_blastWave->SetParameter(0, a_param[spectrumIndex]);
    m_blastWave->SetParameter(1, a_param[numSpectraToFit]
                                 + a_param[numSpectraToFit+1]*PhysMath::legendre(2,TwoRap/a_param[numSpectraToFit+3])
                                 + a_param[numSpectraToFit+2]*PhysMath::legendre(4,TwoRap/a_param[numSpectraToFit+3])     );
    m_blastWave->SetParameter(2, a_param[numSpectraToFit+4]
                                 + a_param[numSpectraToFit+5]*PhysMath::legendre(2,TwoRap/a_param[numSpectraToFit+7])
                                 + a_param[numSpectraToFit+6]*PhysMath::legendre(4,TwoRap/a_param[numSpectraToFit+7])     );
    for(int pointIndex = 0; pointIndex < spectrum->GetN(); pointIndex++){
      if(m_currentLowFitRange < spectrum->GetX()[pointIndex] && spectrum->GetX()[pointIndex] < m_currentHighFitRange){
        chiSquared+=pow((spectrum->GetY()[pointIndex] - m_blastWave->Eval(spectrum->GetX()[pointIndex]))/spectrum->GetErrorY(pointIndex),2);
      }
    }//loop over points
  }
  return chiSquared;
}


