double SpectraFitter::simultaneous_doubleBoseEinstein_CoulombCorrected_FreeTemps_noMem_ChiSqr(const double* a_param){
  double chiSquared = 0.0;

  int numUnconstrainedParams = (int) 4*m_liveRapidityPionSpectra_charge[1].size();
  int pmOffset = -999;

//  for(int iii = 0; iii < 2*m_liveRapidityPionSpectra.size(); iii+=2){
  for(int iii = 0; iii < (int) (4*m_liveRapidityPionSpectra_charge[1].size()); iii+=4){
    //cout << "Trying yIndex=" << m_liveRapidityProtonSpectra[iii] << endl;

    m_currentRapValue = m_liveRapidityValuePionSpectra_charge[1][iii/4];
    //m_currentRapValue = m_cuts->getYCM();


    if(pmOffset == -999 && m_liveRapidityPionSpectra_charge[1][iii/4] == m_liveRapidityPionSpectra_charge[0][0]) pmOffset = iii/4;

    //cout << "pmOffset: " << pmOffset << endl;
    //cout << "m_liveRapidityPionSpectra_charge[1][" << iii/5 << "]: " << m_liveRapidityPionSpectra_charge[1][iii/5] << endl;
    //cout << "m_liveRapidityPionSpectra_charge[0][" << 0 << "]: " << m_liveRapidityPionSpectra_charge[0][0] << endl;

    TGraphErrors* spectrum[2] = {NULL,NULL};
    spectrum[1] = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityPionSpectra_charge[1][iii/4]];
    if(pmOffset != -999) spectrum[0] = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityPionSpectra_charge[1][iii/4]];

    double tempHigh = a_param[numUnconstrainedParams+2]/TMath::CosH(a_param[numUnconstrainedParams+3]*(m_liveRapidityValuePionSpectra_charge[1][iii/4] - m_cuts->getYCM()));

    double tempPro = m_Tpro_amp[m_currentCentIndex]/TMath::CosH(m_Tpro_sig[m_currentCentIndex]*(m_currentRapValue - m_cuts->getYCM()));

    m_currentCharge = -1;

    m_doubleBoseEinstein_CoulombCorrected->SetParameter(0,a_param[iii]); // pim amp low
    m_doubleBoseEinstein_CoulombCorrected->SetParameter(1,a_param[numUnconstrainedParams+1]);
    m_doubleBoseEinstein_CoulombCorrected->FixParameter(2,m_partInfo->GetParticleMass(0)); // m_pi
    m_doubleBoseEinstein_CoulombCorrected->SetParameter(3,a_param[numUnconstrainedParams]); // VC
    m_doubleBoseEinstein_CoulombCorrected->SetParameter(4,a_param[iii+1]); // pim amp high
    m_doubleBoseEinstein_CoulombCorrected->SetParameter(5,tempHigh);
    m_doubleBoseEinstein_CoulombCorrected->SetParameter(6,tempPro);//ben tPro
    m_doubleBoseEinstein_CoulombCorrected->SetParameter(7,m_currentRapValue - m_cuts->getYCM());
    m_doubleBoseEinstein_CoulombCorrected->SetParameter(8,m_currentCharge);



    //cout << "  Set double Thermal Parameters" << endl;
    //cout << "  Number of Points = " << spectrum->GetN() << endl;
    for(int pointIndex = 0; pointIndex < spectrum[1]->GetN(); pointIndex++){
      m_currentCharge = -1;
      double X_ofPoint = spectrum[1]->GetX()[pointIndex];
      double Y_ofPoint = spectrum[1]->GetY()[pointIndex];
      //cout << "got xy of point " << pointIndex << endl;
      double errorY = spectrum[1]->GetErrorY(pointIndex);
      double expected = m_doubleBoseEinstein_CoulombCorrected->Eval(X_ofPoint);
      //cout << "minus expected: " << expected << endl;
      //m_currentCharge = 1;
      //cout << "plus expected: " << m_doubleBoseEinstein_CoulombCorrected->Eval(X_ofPoint) << endl;
      //cout << "  calc expected " << expected << endl;
      chiSquared+=(Y_ofPoint - expected)*(Y_ofPoint - expected)/ (errorY*errorY);
    }//loop over points

    if(pmOffset == -999 || !spectrum[0]) continue;
    m_currentCharge = 1;


    m_doubleBoseEinstein_CoulombCorrected->SetParameter(0,a_param[iii+2]); // pip amp low
    m_doubleBoseEinstein_CoulombCorrected->SetParameter(1,a_param[numUnconstrainedParams+1]);
    m_doubleBoseEinstein_CoulombCorrected->SetParameter(3,a_param[numUnconstrainedParams]); // VC
    m_doubleBoseEinstein_CoulombCorrected->SetParameter(4,a_param[iii+3]); // pip amp high
    m_doubleBoseEinstein_CoulombCorrected->SetParameter(5,tempHigh);
    m_doubleBoseEinstein_CoulombCorrected->SetParameter(8,m_currentCharge);


    for(int pointIndex = 0; spectrum[0] && pointIndex < spectrum[0]->GetN(); pointIndex++){
      double X_ofPoint = spectrum[0]->GetX()[pointIndex];
      double Y_ofPoint = spectrum[0]->GetY()[pointIndex];
      //cout << "got xy of point " << pointIndex << endl;
      double errorY = spectrum[0]->GetErrorY(pointIndex);
      double expected = m_doubleBoseEinstein_CoulombCorrected->Eval(X_ofPoint);
      //cout << "  calc expected " << expected << endl;
      chiSquared+=(Y_ofPoint - expected)*(Y_ofPoint - expected)/ (errorY*errorY);
    }//loop over points
  }
  return chiSquared;
}


