double SpectraFitter::simultaneous_mTm0Exponential_BE_ChiSqr(const double* a_param){
  double chiSquared = 0.0;

  for(int iii = 0; iii < m_liveRapidityPionSpectra.size(); iii++){

    TGraphErrors* spectrum = NULL;

    if(m_currentCharge == 1) spectrum = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityPionSpectra[iii]];
    else spectrum = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityPionSpectra[iii]];


    m_mTm0Exponential_BE->FixParameter(2,m_partInfo->GetParticleMass(0)); // m_pi


    m_mTm0Exponential_BE->SetParameter(0,a_param[0]*exp(-0.5*pow((m_liveRapidityValuePionSpectra[iii] - a_param[1])/a_param[2],2)));

    m_mTm0Exponential_BE->SetParameter(3,a_param[3]*exp(-0.5*pow((m_liveRapidityValuePionSpectra[iii] - a_param[4])/a_param[5],2)));

    m_mTm0Exponential_BE->SetParameter(1,a_param[6]/TMath::CosH(a_param[8]*(m_liveRapidityValuePionSpectra[iii]-a_param[7])));

    m_mTm0Exponential_BE->SetParameter(4,a_param[9]/TMath::CosH(a_param[11]*(m_liveRapidityValuePionSpectra[iii]-a_param[10])));


    for(int pointIndex = 0; pointIndex < spectrum->GetN(); pointIndex++){
      double X_ofPoint = spectrum->GetX()[pointIndex];
      double Y_ofPoint = spectrum->GetY()[pointIndex];
      //cout << "got xy of point " << pointIndex << endl;
      double errorY = spectrum->GetErrorY(pointIndex);
      double expected = m_mTm0Exponential_BE->Eval(X_ofPoint);
      //cout << "  calc expected " << expected << endl;
      chiSquared+=(Y_ofPoint - expected)*(Y_ofPoint - expected)/ (errorY*errorY);
    }//loop over points
  }
  return chiSquared;
}


