double SpectraFitter::simultaneous_BoseEinstein_ChiSqr(const double* a_param){
  double chiSquared = 0.0;
  unsigned int temperatureIndex = m_currentDnDyParameters;
  for(int spectraIndex = 0; spectraIndex < m_liveRapiditySpectra.size(); spectraIndex++){
    int paramIndex = m_liveRapSpec_to_ParamIndex[spectraIndex];
    TGraphErrors* spectrum = NULL;
    if(m_currentCharge == 1) spectrum = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapiditySpectra[spectraIndex]];
    else spectrum = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapiditySpectra[spectraIndex]];
    m_boseEinstein->SetParameter(0,a_param[paramIndex]);
    m_boseEinstein->SetParameter(1,a_param[temperatureIndex]/TMath::CosH(a_param[temperatureIndex+2]*(m_liveRapidityValueSpectra[spectraIndex]-a_param[temperatureIndex+1])));
    m_boseEinstein->SetParameter(2,m_partInfo->GetParticleMass(0));
    for(int pointIndex = 0; pointIndex < spectrum->GetN(); pointIndex++){
      double mTm0_ofPoint  = spectrum->GetX()[pointIndex];
      double yield_ofPoint = spectrum->GetY()[pointIndex];
      double errorX = spectrum->GetEX()[pointIndex];
      double errorY = spectrum->GetEY()[pointIndex];
      double expected = m_boseEinstein->Eval(mTm0_ofPoint);
      chiSquared += (yield_ofPoint - expected)*(yield_ofPoint - expected)/ (errorY*errorY + pow(errorX*m_boseEinstein->Derivative(mTm0_ofPoint),2.0) );
    }//loop over points
  }//live spectra loop
  return chiSquared;
}




