void SpectraFitter::fitPionSpectra(bool a_constrainTemperature, int a_numTrialsForDnDyBootstrap, int a_centIndex, int a_charge){
  cout << "Fitting Pion Spectra" << endl;
  m_currentPartIndex = 0;
  m_currentParticleMass = m_partInfo->GetParticleMass(m_currentPartIndex);

  TCanvas* fittingCanvas = new TCanvas("fittingCanvas","Fitting Canvas");
  fittingCanvas->SetWindowSize(1300,700);
  fittingCanvas->SetCanvasSize(1200,600);

  double pionMass = m_partInfo->GetParticleMass(0);
  m_currentCentIndex = a_centIndex;
  m_currentCharge = a_charge;
  int pmIndex = 0;
  if(m_currentCharge < 0) pmIndex = 1;

  m_isTemperatureConstrained = false;
  for(unsigned int yIndex = 0; yIndex < m_cuts->getRapMtM0BinStructure(0, 1)->GetNbinsX(); yIndex++){
    m_currentRapValue = m_cuts->getRapMtM0BinStructure(0, 1)->GetBinCenter(yIndex+1);
    m_currentRapIndex = yIndex;
    TGraphErrors* specPM[2];
    specPM[0] = m_totalSpectra_Plus[0][m_currentCentIndex][yIndex];
    specPM[1] = m_totalSpectra_Minus[0][m_currentCentIndex][yIndex];
    if( !specPM[pmIndex] || specPM[pmIndex]->GetN() <= 0 ) continue;

    cout << "Pion Fitting: Cent " << m_currentCentIndex << " yIndex " << yIndex << " charge: " << m_currentCharge << " ptr: " << specPM[pmIndex] << " N: " << specPM[pmIndex]->GetN() <<  endl;
    cout << "TGraph Title : " << specPM[pmIndex]->GetTitle() << endl;

    //##########  FIT WITH NOMINAL FIT FUNCTION ##########
    cout << "Nominal Fit" << endl;
    m_isCurrentFitNominal = true;
    m_currentSpectra = specPM[pmIndex];
    //m_currentSpectra = (TGraphErrors*) specPM[pmIndex]->Clone();
    cout << "Working with graph named " << m_currentSpectra->GetTitle() << endl;;
    //scaleTGraphByInvFactor(m_currentSpectra, pionMass);
    //HistogramUtilities::shiftTGraph(m_currentSpectra, pionMass);
    init_boseEinstein();

    TF1* initial_BE_fit = (TF1*) m_boseEinstein->Clone();
    initial_BE_fit->SetLineColor(kYellow);
    initial_BE_fit->SetName("initial_BE_fit");
    int status= m_currentSpectra->Fit("m_boseEinstein","E EX0","",0,10);
    TF1* fitResult = m_currentSpectra->GetFunction("m_boseEinstein");

    //make the fit image
    fittingCanvas->cd();
    double smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
    double largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
    if(smallYVal < 0.0) smallYVal = 1e-6;
    TH1F *frame = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
    frame->SetTitle(Form("#pi^{%s} Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
      m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
      m_cuts->getLowCentPercent(m_currentCentIndex),m_cuts->getHighCentPercent(m_currentCentIndex)));
    //frame->GetXaxis()->SetTitle("m_{T} (GeV/c^{2})");
    //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
    frame->GetXaxis()->SetTitle("m_{T}-m_{#pi} (GeV/c^{2})");
    frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
    gPad->SetLogy();
    gPad->SetRightMargin(0.4);
    initial_BE_fit->Draw("same");
    m_currentSpectra->Draw("P");

    fittingCanvas->Update();
    fittingCanvas->SaveAs(Form("%s/%s/Fit_Nom_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));
    //delete initial_BE_fit;

    if(status == 0){
      //push the fit results back
      double dNdy = fitResult->GetParameter(0);
      double dNdyErr = fitResult->GetParError(0);
      cout << "dNdy: " << dNdy << " +/- " << dNdyErr/dNdy*100.0 << "%" << endl;
      if(m_currentCharge == 1){
        if(!std::isnan(dNdy) && !std::isnan(dNdyErr)){
          m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdy);
          m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
        }
      }else{
        if(!std::isnan(dNdy) && !std::isnan(dNdyErr)){
          m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdy);
          m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
        }
      }

      double Temp = fitResult->GetParameter(1);
      double Temp_err = fitResult->GetParError(1);
      cout << "Temp: " << Temp << " +/- " << Temp_err/Temp*100.0 << "%" << endl;
      if(m_currentCharge == 1){
        if(!std::isnan(Temp) && !std::isnan(Temp_err)){
          m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,Temp);
          m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,Temp_err);
          cout << "temp rap index: " << yIndex << " bin center: " << m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->GetBinCenter(yIndex+1) << endl;
        }
      }else{
        if(!std::isnan(Temp) && !std::isnan(Temp_err)){
          m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,Temp);
          m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,Temp_err);
        }
      }
    }








    //##########  FIT WITH SYSTEMATIC FIT FUNCTION ##########
    cout << "Systematic Fit" << endl;
    m_isCurrentFitNominal = false;
    //m_currentSpectra = (TGraphErrors*) specPM[pmIndex]->Clone();
    //scaleTGraphByInvFactor(m_currentSpectra, pionMass);
    //HistogramUtilities::shiftTGraph(m_currentSpectra,pionMass);
    //m_currentSpectraAsymm = HistogramUtilities::convertPlot_mT_to_pT(m_currentSpectra, pionMass);
    //m_currentSpectraAsymm->SetMarkerSize(0.5);
    //m_currentSpectraAsymm->SetMarkerStyle(20);
    //m_currentSpectra = HistogramUtilities::convertAsymToNoAsym(ptSpecWithError);
    init_pTExponential();
    TF1* initial_PE_fit = (TF1*) m_pTExponential->Clone();
    initial_PE_fit->SetLineColor(kYellow);
    initial_PE_fit->SetName("initial_PE_fit");
    //int status_sys = m_currentSpectraAsymm->Fit("m_pTExponential","E","",0,10);
    //TF1* fitResultSys = m_currentSpectraAsymm->GetFunction("m_pTExponential");
    int status_sys = m_currentSpectra->Fit("m_pTExponential","E EX0","",0,10);
    TF1* fitResultSys = m_currentSpectra->GetFunction("m_pTExponential");
    //make the fit image
    fittingCanvas->cd();
    smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
    largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
    if(smallYVal < 0.0) smallYVal = 1e-6;
    frame = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
    frame->SetTitle(Form("#pi^{%s} Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
      m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
      m_cuts->getLowCentPercent(m_currentCentIndex),m_cuts->getHighCentPercent(m_currentCentIndex)));
    //frame->GetXaxis()->SetTitle("p_{T} (GeV/c)");
    //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dp_{T}dy}");
    frame->GetXaxis()->SetTitle("m_{T}-m_{#pi} (GeV/c^{2})");
    frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");

    gPad->SetLogy();
    gPad->SetRightMargin(0.4);
    initial_PE_fit->Draw("same");
    m_currentSpectra->Draw("P");
    fittingCanvas->Update();
    fittingCanvas->SaveAs(Form("%s/%s/Fit_Sys_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));
    //delete initial_PE_fit;

    //push the fit results back
    if(status_sys == 0){
      double dNdy = fitResultSys->GetParameter(0);
      double dNdyErr = fitResultSys->GetParError(0);
      cout << "dNdy: " << dNdy << " +/- " << dNdyErr/dNdy*100.0 << "%" << endl;
      if(m_currentCharge == 1){
        if(!std::isnan(dNdy) && !std::isnan(dNdyErr)){
          m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdy);
          m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
        }
      }else{
        if(!std::isnan(dNdy) && !std::isnan(dNdyErr)){
          m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdy);
          m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
        }
      }

      double Temp = fitResultSys->GetParameter(1);
      double Temp_err = fitResultSys->GetParError(1);
      cout << "Temp: " << Temp << " +/- " << Temp_err/Temp*100.0 << "%" << endl;
      if(m_currentCharge == 1){
        if(!std::isnan(Temp) && !std::isnan(Temp_err)){
          m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,Temp);
          m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,Temp_err);
        }
      }else{
        if(!std::isnan(Temp) && !std::isnan(Temp_err)){
          m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,Temp);
          m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,Temp_err);
        }
      }
    }

  } // end rapidity loop

  if(!a_constrainTemperature) return;






  //##########  CONSTRAIN NOMINAL TEMPERATURE ##########
  TH1D* temperature_histo_nom = NULL;
  TH1D* temperature_histo_sys = NULL;
  if(m_currentCharge == 1){
    temperature_histo_nom = m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex];
    temperature_histo_sys = m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex];
  }else{
    temperature_histo_nom = m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex];
    temperature_histo_sys = m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex];
  }

  m_currentTemperatureHisto = temperature_histo_nom;
  init_gausFunctForTemp();
  int status_temp = temperature_histo_nom->Fit("m_gausFunct","E");
  TF1* fitResult_Nom = temperature_histo_nom->GetFunction("m_gausFunct");
  cout << "TempConstraint :  N:" << fitResult_Nom->GetParameter(0) << " mean:" << fitResult_Nom->GetParameter(1) << " stdDev:" << fitResult_Nom->GetParameter(2) << endl;
  fittingCanvas->cd();
  gPad->SetLogy(false);
  temperature_histo_nom->Draw("E");
  fittingCanvas->SaveAs(Form("%s/%s/TemperatureFit_Nominal_Cent%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));

  m_currentTemperatureHisto = temperature_histo_sys;
  init_gausFunctForTemp();
  int status_temp_sys = temperature_histo_sys->Fit("m_gausFunct","E");
  TF1* fitResult_Sys = temperature_histo_sys->GetFunction("m_gausFunct");
  #ifdef _SPECTRA_FITTER_DEBUG_
    cout << "Systematic Temp Fit Status: " << status_temp_sys << endl;
    if(fitResult_Sys) cout << "TempConstraint :  N:" << fitResult_Sys->GetParameter(0) << " mean:" << fitResult_Sys->GetParameter(1) << " stdDev:" << fitResult_Sys->GetParameter(2) << endl;
  #endif


  fittingCanvas->cd();
  gPad->SetLogy(false);
  temperature_histo_sys->Draw("E");
  if(fitResult_Sys) fitResult_Sys->Draw("SAME");
  fittingCanvas->SaveAs(Form("%s/%s/TemperatureFit_Systematic_Cent%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));






  //##########    REFIT WITH TEMPERATURE CONSTRAINED ################
  m_isTemperatureConstrained = true;
  for(unsigned int yIndex = 0; yIndex < m_cuts->getRapMtM0BinStructure(0, 1)->GetNbinsX(); yIndex++){
    //m_currentRapValue = m_cuts->getRapMtM0BinStructure(0, 1)->GetBinCenter(yIndex+1);
    m_currentRapValue = m_cuts->getRapidityRangeCenter(yIndex,0,1);
    m_currentRapIndex = yIndex;

    TGraphErrors* specPM[2];
    specPM[0] = m_totalSpectra_Plus[0][m_currentCentIndex][yIndex];
    specPM[1] = m_totalSpectra_Minus[0][m_currentCentIndex][yIndex];
    if( !specPM[pmIndex] || specPM[pmIndex]->GetN() <= 0 ) continue;

    cout << "Pion Fitting: Cent " << m_currentCentIndex << " yIndex " << yIndex << " ptr: " << specPM[pmIndex] << " N: " << specPM[pmIndex]->GetN() <<  endl;
    cout << "spec title: " << specPM[pmIndex]->GetTitle() << endl;
    cout << "rapidity: " << m_currentRapValue << endl;

    //##########  FIT WITH NOMINAL FIT FUNCTION ##########
    cout << "Nominal Fit" << endl;
    m_isCurrentFitNominal = true;
    m_currentSpectra = specPM[pmIndex];
    //m_currentSpectra = (TGraphErrors*) specPM[pmIndex]->Clone();
    //scaleTGraphByInvFactor(m_currentSpectra, pionMass);
    //HistogramUtilities::shiftTGraph(m_currentSpectra, pionMass);
    init_boseEinstein();
    TF1* initial_BE_fit = (TF1*) m_boseEinstein->Clone();
    initial_BE_fit->SetLineColor(kYellow);
    initial_BE_fit->SetName("initial_BE_fit");
    TFitResultPtr resultPtr = m_currentSpectra->Fit("m_boseEinstein","ES EX0","",0,10);
    TF1* fitResult = m_currentSpectra->GetFunction("m_boseEinstein");

    //make the fit image
    fittingCanvas->cd();
    double smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
    double largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
    if(smallYVal < 0.0) smallYVal = 1e-6;
    TH1F *frame = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
    frame->SetTitle(Form("#pi^{%s} Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
      m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
      m_cuts->getLowCentPercent(m_currentCentIndex),m_cuts->getHighCentPercent(m_currentCentIndex)));
    //frame->GetXaxis()->SetTitle("m_{T} (GeV/c^{2})");
    //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
    frame->GetXaxis()->SetTitle("m_{T}-m_{#pi} (GeV/c^{2})");
    frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
    gPad->SetLogy();
    gPad->SetRightMargin(0.4);
    initial_BE_fit->Draw("same");
    m_currentSpectra->Draw("P");
    fittingCanvas->Update();
    fittingCanvas->SaveAs(Form("%s/%s/Fit_Nom_TempConstrained_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));
    //delete initial_BE_fit;

    //push the fit results back
    double Amp = fitResult->GetParameter(0);
    double AmpErr = fitResult->GetParError(0);
    cout << "Amp: " << Amp << " +/- " << AmpErr/Amp*100.0 << "%" << endl;




    //###### BOOTSTRAP THE FIT FUNCTION FOR dN/dy ###########        double dNdy = 0;
    double dNdy = 0;
    double dNdyAvg = 0;
    double dNdyErr = 0;
    vector<double> integralListNom = FitUtilities::bootstrapIntegralSingleParameter(dNdy,dNdyAvg, dNdyErr, fitResult, resultPtr.Get(),pionMass,0,a_numTrialsForDnDyBootstrap);
    double smallest = *min_element(integralListNom.begin(), integralListNom.end());
    double biggest = *max_element(integralListNom.begin(), integralListNom.end());
    TH1D* integralHistoryHisto_Nom = new TH1D("paramHisto","Sampled Integrals; Integral Value;Counts",100,0.98*smallest, 1.02*biggest);
    for(int iii = 0; iii < (int) integralListNom.size(); iii++) integralHistoryHisto_Nom->Fill(integralListNom[iii]);
    integralHistoryHisto_Nom->SetName(Form("dNdy_Nom_History_%s_Cent%02d_Rap%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));
    HistogramUtilities::makeSqrtNErrors(integralHistoryHisto_Nom);
    m_gausFunct->SetRange(integralHistoryHisto_Nom->GetBinLowEdge(1),integralHistoryHisto_Nom->GetBinLowEdge(integralHistoryHisto_Nom->GetNbinsX()+1));
    double mean = integralHistoryHisto_Nom->GetMean();
    double stdDev = integralHistoryHisto_Nom->GetStdDev();
    double counts = integralHistoryHisto_Nom->GetBinContent(integralHistoryHisto_Nom->FindBin(mean))*stdDev/0.3989422804;
    m_gausFunct->SetParameter(0,counts);
    m_gausFunct->SetParLimits(0,0.5*counts,2.0*counts);
    m_gausFunct->SetParameter(1,mean);
    m_gausFunct->SetParLimits(1,integralHistoryHisto_Nom->GetBinLowEdge(1),integralHistoryHisto_Nom->GetBinLowEdge(integralHistoryHisto_Nom->GetNbinsX()+1));
    m_gausFunct->SetParameter(2,stdDev);
    m_gausFunct->SetParLimits(2,0.5*stdDev,2.0*stdDev);
    int statusDnDy = integralHistoryHisto_Nom->Fit("m_gausFunct","EQ");
    TF1* fitResultDnDyBootstrap = integralHistoryHisto_Nom->GetFunction("m_gausFunct");
    if(fitResultDnDyBootstrap && !std::isnan(fitResultDnDyBootstrap->GetParameter(1)) && !std::isnan(fitResultDnDyBootstrap->GetParameter(2))){
      dNdyAvg = fitResultDnDyBootstrap->GetParameter(1);
      dNdyErr = fitResultDnDyBootstrap->GetParameter(2);
      cout << "dNdy: " << dNdy << " dNdyAvg: " << dNdyAvg << " +/- " << dNdyErr/dNdyAvg*100.0 << "%" << endl;
      //########  STORE THE dN/dy DATA IN MEMBER VARIBLES #########
      if(m_currentCharge == 1){
        m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdyAvg);
        //m_dNdy_Plus_Nominal_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdyAvg);
        m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
        //m_dNdy_Plus_Nominal_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
        TF1* fitResultClone = (TF1*) fitResult->Clone();
        fitResultClone->SetName(Form("NominalFit_Cent%02d_yIndex%02d",m_currentCentIndex,yIndex));
        fitResultClone->SetTitle(Form("#pi^{%s} Bose-Einstein Fit y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
          m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),m_cuts->getLowCentPercent(m_currentCentIndex),m_cuts->getHighCentPercent(m_currentCentIndex)));
        m_nominalFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitResultClone;
        m_bootstrapData_Nom_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
      }else{
        m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdyAvg);
        //m_dNdy_Minus_Nominal_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdyAvg);
        m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
        //m_dNdy_Minus_Nominal_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
        TF1* fitResultClone = (TF1*) fitResult->Clone();
        fitResultClone->SetName(Form("NominalFit_Cent%02d_yIndex%02d",m_currentCentIndex,yIndex));
        fitResultClone->SetTitle(Form("#pi^{%s} Bose-Einstein Fit y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
          m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),m_cuts->getLowCentPercent(m_currentCentIndex),m_cuts->getHighCentPercent(m_currentCentIndex)));
        m_nominalFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitResultClone;
        m_bootstrapData_Nom_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
      }
    }else{
      cout << "Fitting of Bootstrap Integral History Failed... " << endl;
      cout << "dNdy: " << dNdy << " dNdyAvg: " << dNdyAvg << " +/- " << dNdyErr/dNdyAvg*100.0 << "%" << endl;
      //########  STORE THE dN/dy DATA IN MEMBER VARIBLES #########
      if(m_currentCharge == 1){
        m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,0.0);
        m_dNdy_Plus_Nominal_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,0.0);
        m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,0.0);
        m_dNdy_Plus_Nominal_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,0.0);
        m_bootstrapData_Nom_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
      }else{
        m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,0.0);
        m_dNdy_Minus_Nominal_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,0.0);
        m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,0.0);
        m_dNdy_Minus_Nominal_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,0.0);
        m_bootstrapData_Nom_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;

      }
    }



    //##########  FIT WITH SYSTEMATIC FIT FUNCTION ##########
    m_isCurrentFitNominal = false;
    //m_currentSpectra = (TGraphErrors*) specPM[pmIndex]->Clone();
    //scaleTGraphByInvFactor(m_currentSpectra, pionMass);
    //HistogramUtilities::shiftTGraph(m_currentSpectra,pionMass);
    //m_currentSpectraAsymm = HistogramUtilities::convertPlot_mT_to_pT(m_currentSpectra, pionMass);
    //m_currentSpectraAsymm->SetMarkerSize(0.5);
    //m_currentSpectraAsymm->SetMarkerStyle(20);
    //m_currentSpectra = HistogramUtilities::convertAsymToNoAsym(ptSpecWithError);
    init_pTExponential();
    TF1* initial_PE_fit = (TF1*) m_pTExponential->Clone();
    initial_PE_fit->SetLineColor(kYellow);
    initial_PE_fit->SetName("initial_PE_fit");
    TFitResultPtr resultPtrSys = m_currentSpectra->Fit("m_pTExponential","ES EX0","",0,10);
    TF1* fitResultSys = m_currentSpectra->GetFunction("m_pTExponential");



    //make the fit image
    fittingCanvas->cd();
    smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
    largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
    if(smallYVal < 0.0) smallYVal = 1e-6;
    frame = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
    frame->SetTitle(Form("#pi^{%s} Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
      m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
      m_cuts->getLowCentPercent(m_currentCentIndex),m_cuts->getHighCentPercent(m_currentCentIndex)));
    //frame->GetXaxis()->SetTitle("p_{T} (GeV/c)");
    //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dp_{T}dy}");
    frame->GetXaxis()->SetTitle("m_{T}-m_{#pi} (GeV/c^{2})");
    frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
    gPad->SetLogy();
    gPad->SetRightMargin(0.4);
    initial_PE_fit->Draw("same");
    m_currentSpectra->Draw("P");
    fittingCanvas->Update();
    fittingCanvas->SaveAs(Form("%s/%s/Fit_Sys_TempConstrained_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));
    //delete initial_PE_fit;

    //push the fit results back
    Amp = fitResultSys->GetParameter(0);
    AmpErr = fitResultSys->GetParError(0);
    cout << "Amp: " << Amp << " +/- " << AmpErr/Amp*100.0 << "%" << endl;


    //###### BOOTSTRAP THE FIT FUNCTION FOR dN/dy ###########
    vector<double> integralListSys = FitUtilities::bootstrapIntegralSingleParameter(dNdy,dNdyAvg, dNdyErr, fitResultSys, resultPtrSys.Get(), pionMass,0,a_numTrialsForDnDyBootstrap);
    smallest = *min_element(integralListSys.begin(), integralListSys.end());
    biggest = *max_element(integralListSys.begin(), integralListSys.end());
    TH1D* integralHistoryHistoSys = new TH1D("paramHisto","Sampled Integrals; Integral Value;Counts",100,0.98*smallest, 1.02*biggest);
    for(int iii = 0; iii < (int) integralListSys.size(); iii++) integralHistoryHistoSys->Fill(integralListSys[iii]);
    integralHistoryHistoSys->SetName(Form("dNdy_Sys_History_%s_Cent%02d_Rap%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));
    HistogramUtilities::makeSqrtNErrors(integralHistoryHistoSys);
    m_gausFunct->SetRange(integralHistoryHistoSys->GetBinLowEdge(1),integralHistoryHistoSys->GetBinLowEdge(integralHistoryHistoSys->GetNbinsX()+1));
    mean = integralHistoryHistoSys->GetMean();
    stdDev = integralHistoryHistoSys->GetStdDev();
    counts = integralHistoryHistoSys->GetBinContent(integralHistoryHistoSys->FindBin(mean))*stdDev/0.3989422804;
    m_gausFunct->SetParameter(0,counts);
    m_gausFunct->SetParLimits(0,0.5*counts,2.0*counts);
    m_gausFunct->SetParameter(1,mean);
    m_gausFunct->SetParLimits(1,integralHistoryHistoSys->GetBinLowEdge(1),integralHistoryHistoSys->GetBinLowEdge(integralHistoryHistoSys->GetNbinsX()+1));
    m_gausFunct->SetParameter(2,stdDev);
    m_gausFunct->SetParLimits(2,0.5*stdDev,2.0*stdDev);
    int statusDnDySys = integralHistoryHistoSys->Fit("m_gausFunct","EQ");
    TF1* fitResultDnDyBootstrapSys = integralHistoryHistoSys->GetFunction("m_gausFunct");

    if(fitResultDnDyBootstrapSys && !std::isnan(fitResultDnDyBootstrapSys->GetParameter(1)) && !std::isnan(fitResultDnDyBootstrapSys->GetParameter(2))){
      dNdyAvg = fitResultDnDyBootstrapSys->GetParameter(1);
      dNdyErr = fitResultDnDyBootstrapSys->GetParameter(2);
      cout << "dNdy: " << dNdy << " dNdyAvg: " << dNdyAvg << " +/- " << dNdyErr/dNdyAvg*100.0 << "%" << endl;
      //########  STORE THE dN/dy DATA IN MEMBER VARIBLES #########
      if(m_currentCharge == 1){
        m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdyAvg);
        //m_dNdy_Plus_Systematic_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdyAvg);
        m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
        //m_dNdy_Plus_Systematic_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
        TF1* fitResultClone = (TF1*) fitResultSys->Clone();
        fitResultClone->SetName(Form("SystematicFit_Cent%02d_yIndex%02d",m_currentCentIndex,yIndex));
        fitResultClone->SetTitle(Form("#pi^{%s} p_{T} Exponential Fit y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
          m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),m_cuts->getLowCentPercent(m_currentCentIndex),m_cuts->getHighCentPercent(m_currentCentIndex)));
        m_systematicFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitResultClone;
        m_bootstrapData_Sys_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHistoSys;
      }else{
        m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdyAvg);
        //m_dNdy_Minus_Systematic_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdyAvg);
        m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
        //m_dNdy_Minus_Systematic_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
        TF1* fitResultClone = (TF1*) fitResultSys->Clone();
        fitResultClone->SetName(Form("SystematicFit_Cent%02d_yIndex%02d",m_currentCentIndex,yIndex));
        fitResultClone->SetTitle(Form("#pi^{%s} p_{T} Exponential Fit y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
          m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),m_cuts->getLowCentPercent(m_currentCentIndex),m_cuts->getHighCentPercent(m_currentCentIndex)));
        m_systematicFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitResultClone;
        m_bootstrapData_Sys_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHistoSys;

      }
    }else{
      cout << "Fitting of Bootstrap Integral History Failed... " << endl;
      cout << "dNdy: " << dNdy << " dNdyAvg: " << dNdyAvg << " +/- " << dNdyErr/dNdyAvg*100.0 << "%" << endl;
      //########  STORE THE dN/dy DATA IN MEMBER VARIBLES #########
      if(m_currentCharge == 1){
        m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,0.0);
        m_dNdy_Plus_Systematic_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,0.0);
        m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,0.0);
        m_dNdy_Plus_Systematic_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,0.0);
        m_bootstrapData_Sys_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHistoSys;
      }else{
        m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,0.0);
        m_dNdy_Minus_Systematic_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,0.0);
        m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,0.0);
        m_dNdy_Minus_Systematic_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,0.0);
        m_bootstrapData_Sys_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHistoSys;
      }
    } // end if gaus fit funciton exists
  } // end rapidity loop
}

//########################################################################################################################################################################################################################
//########################################################################################################################################################################################################################

void SpectraFitter::fitPionSpectraSimultaneous_BoseEinstein(bool a_isNominal, bool a_enforceDnDySymmetry, bool a_saveFinalFits){
  cout << "#####################  Starting SpectraFitter::fitPionSpectraSimultaneous_BoseEinstein() ########################" << endl;
  TVirtualFitter::SetMaxIterations( 1000000 );
  m_currentPartIndex = 0;
  m_currentParticleMass = m_partInfo->GetParticleMass(m_currentPartIndex);
  m_enforceDnDySymmetry = a_enforceDnDySymmetry;
  TCanvas* fittingCanvas = new TCanvas("fittingCanvas_Pion","Fitting Canvas");
  fittingCanvas->SetWindowSize(1300,700);
  fittingCanvas->SetCanvasSize(1200,600);
  double pionMass = m_partInfo->GetParticleMass(m_currentPartIndex);

  for(unsigned int centIndex = 0; centIndex < 16; centIndex++){
    m_currentCentIndex = centIndex;
    for(int pmIndex = 0; pmIndex < 2; pmIndex++){
      m_currentCharge = 1;
      if(pmIndex == 1) m_currentCharge = -1;

      cout << "######################################################################" << endl;
      cout << "          STAGE 1   Pion Fitting - Fit Mid-Rapidity as Seed to Simultaneous Fitter" << endl;
      m_pionFittingStage = 1;
      m_isTemperatureConstrained = false;
      m_currentRapIndex = m_cuts->getRapMtM0BinStructure(m_currentPartIndex, 1)->FindBin(m_cuts->getYCM());
      m_currentMidRapIndex = m_currentRapIndex;
      m_currentRapValue = m_cuts->getRapMtM0BinStructure(m_currentPartIndex, 1)->GetBinCenter(m_currentRapIndex);
      if(m_currentCharge == 1) m_currentSpectra = (TGraphErrors*) m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex]->Clone();
      else                     m_currentSpectra = (TGraphErrors*) m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex]->Clone();
      double storage_tempSeed = m_temperatureSeed;
      m_temperatureSeed = -1;
      init_boseEinstein();
      m_temperatureSeed = storage_tempSeed;

      string fitOptions = "E";
      #ifdef _SPECTRA_FITTER_DEBUG_
        fitOptions = fitOptions + "V";
      #endif
      int status = m_currentSpectra->Fit("m_boseEinstein",fitOptions.c_str(),"",0,10);
      TF1* fitResult = m_currentSpectra->GetFunction("m_boseEinstein");
      if(!fitResult){
        cout << " ERROR: midrapidity fit of pion FAILED" << endl;
        return;
      }
      double dNdy_initial = fitResult->GetParameter(0);
      double Temp_initial = fitResult->GetParameter(1);

      m_liveRapiditySpectra.clear();
      m_liveRapidityValueSpectra.clear();
      m_liveRapSpec_to_ParamIndex.clear();
      m_ParamIndex_to_LiveRapSpec.clear();

      //#######   FIND THE SECTRA WITH DATA POINTS ########
      for(unsigned int yIndex = 0; yIndex < m_cuts->getRapMtM0BinStructure(m_currentPartIndex, 1)->GetNbinsX(); yIndex++){
        m_currentRapValue = m_cuts->getRapMtM0BinStructure(m_currentPartIndex, 1)->GetBinCenter(yIndex+1);
        m_currentRapIndex = yIndex;
        TGraphErrors* specPM[2];
        specPM[0] = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][yIndex];
        specPM[1] = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][yIndex];
        if( !specPM[pmIndex] || specPM[pmIndex]->GetN() < 1 ) continue;
        m_liveRapiditySpectra.push_back(yIndex);
        m_liveRapidityValueSpectra.push_back(m_currentRapValue);
        #ifdef _SPECTRA_FITTER_DEBUG_
          cout << "Pion Fitting: Cent " << m_currentCentIndex << " yIndex " << yIndex
             << " charge: " << m_currentCharge << " ptr: " << specPM[pmIndex] << " charge: " << m_currentCharge
             << " N: " << specPM[pmIndex]->GetN() <<  endl;
        #endif
      }

      //####################   setup minimizer #######################
      int numSpectraToFit = (int) m_liveRapiditySpectra.size();
      m_currentDnDyParameters = numSpectraToFit;

      if(m_enforceDnDySymmetry){
        m_currentDnDyParameters = 0;
        for(int spectraIndex = 0; spectraIndex < numSpectraToFit; spectraIndex++){
          if( m_liveRapiditySpectra[spectraIndex] <= m_currentMidRapIndex ){
            m_liveRapSpec_to_ParamIndex.push_back(spectraIndex);
            m_currentDnDyParameters++;
          }else{
            //does the mirror index exist in list?
            int mirrorIndex = 2*m_currentMidRapIndex - m_liveRapiditySpectra[spectraIndex];
            bool mirrorIndexExists = false;
            int mirrorParIndex = -1;
            for(int iii = 0; iii < m_liveRapiditySpectra.size(); iii++){
              if(m_liveRapiditySpectra[iii] == mirrorIndex){
                mirrorIndexExists = true;
                mirrorParIndex = iii;
                break;
              }
            }
            if(mirrorIndexExists){
              m_liveRapSpec_to_ParamIndex.push_back(mirrorParIndex);
            }else{
              m_liveRapSpec_to_ParamIndex.push_back(m_currentDnDyParameters);
              m_currentDnDyParameters++;
            }

            #ifdef _SPECTRA_FITTER_DEBUG_
              cout << " Now, m_currentDnDyParameters is " << m_currentDnDyParameters
              << " spectraIndex: " << spectraIndex
              << " paramIndex: " << m_liveRapSpec_to_ParamIndex[m_liveRapSpec_to_ParamIndex.size()-1] << endl;
            #endif

          }
        }
      }
      m_minimizer = ROOT::Math::Factory::CreateMinimizer();
      m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_BoseEinstein_ChiSqr, m_currentDnDyParameters + 3 );
      cout << "created chi squared functor with NDim " << m_chiSqrdFunctor->NDim() << "  functor: " << &SpectraFitter::simultaneous_BoseEinstein_ChiSqr  << endl;
      m_minimizer->SetFunction(*m_chiSqrdFunctor);
      for(int iii = 0; iii < m_currentDnDyParameters; iii++){
        m_minimizer->SetVariable(iii, Form("dN/dy_%02d",m_liveRapSpec_to_ParamIndex[iii]), dNdy_initial , 0.1*dNdy_initial);
        m_minimizer->SetVariableLimits(iii, 0.0, dNdy_initial*10000.0);
      }

      m_minimizer->SetVariable(m_currentDnDyParameters,"T_Amp", Temp_initial , 0.1*Temp_initial);
      m_minimizer->SetVariableLimits(m_currentDnDyParameters, 0.0, Temp_initial*100.0);
      m_minimizer->SetVariable(m_currentDnDyParameters+1,"T_Mean", m_cuts->getYCM(),0.1);
      m_minimizer->FixVariable(m_currentDnDyParameters+1);
      m_minimizer->SetVariable(m_currentDnDyParameters,"T_Sigma", 2.0 , 0.5);
      m_minimizer->SetVariableLimits(m_currentDnDyParameters, 0.0, 300.0);



      cout << "######################################################################" << endl;
      cout << "          STAGE 2   Pion Fitting - Fit with Simultaneous Fitter" << endl;
      m_pionFittingStage = 2;
      int printLevel = 1;
      #ifdef _SPECTRA_FITTER_DEBUG_
        printLevel = 5;
      #endif
      m_minimizer->SetPrintLevel(printLevel);
      m_minimizer->SetMaxIterations(3000);
      m_minimizer->SetMaxFunctionCalls(200000);
      m_minimizer->SetValidError(true);
      m_minimizer->Minimize();
      int status_Minimizer = m_minimizer->Status();
      const double* finalParams = m_minimizer->X();
      if(status_Minimizer == 0){
        cout << "### Pion Fit Status: " << status_Minimizer << endl;
      }
      else{
        cout << "################################  Simultaneous Fit:  STATUS OF FIT = " << status_Minimizer << "   IS BAD!!!!!  ################################" << endl;
        cout << "Current Parameters: " << endl;
        for(int iii = 0; iii < numSpectraToFit + 3; iii++){
          cout << "  " << finalParams[iii];
        }
        cout << endl;
        continue;
      }


      cout << "######################################################################" << endl;
      cout << "          STAGE 3   Pion Fitting - Save Single Fit Functions" << endl;

      double tempAmpErr = sqrt(m_minimizer->CovMatrix(numSpectraToFit,numSpectraToFit));
      double tempMeanErr = sqrt(m_minimizer->CovMatrix(numSpectraToFit+1,numSpectraToFit+1));
      double tempSigmaErr  = sqrt(m_minimizer->CovMatrix(numSpectraToFit+2,numSpectraToFit+2));
      for(int iii = 0; iii < m_currentDnDyParameters; iii++){
        int spectraIndex = m_ParamIndex_to_LiveRapSpec[iii];
        double rapidity = m_liveRapidityValueSpectra[spectraIndex];
        int rapIndex = m_liveRapiditySpectra[spectraIndex];

        #ifdef _SPECTRA_FITTER_DEBUG_
          cout << "Extracting data for rap: " << rapidity<< "par: " << iii << " rapIndex: " << rapIndex << "  spectraIndex: " << spectraIndex << endl;
        #endif

        TF1* singleFunct = (TF1*) m_boseEinstein->Clone();
        if(a_isNominal) singleFunct->SetName(Form("NominalFit_Cent%02d_yIndex%02d",m_currentCentIndex,rapIndex));
        else            singleFunct->SetName(Form("SystematicFit_Cent%02d_yIndex%02d",m_currentCentIndex,rapIndex));
        singleFunct->SetParameter(0,finalParams[iii]);
        singleFunct->SetParError(0,sqrt(m_minimizer->CovMatrix(iii,iii)));
        double temperature = finalParams[m_currentDnDyParameters]/TMath::CosH(finalParams[m_currentDnDyParameters+2]*(m_liveRapidityValueSpectra[spectraIndex]-finalParams[m_currentDnDyParameters+1]));
        double tempErr = sqrt( pow(temperature*tempAmpErr/finalParams[m_currentDnDyParameters],2.0)
          + pow(temperature*tempSigmaErr*TMath::TanH(finalParams[m_currentDnDyParameters+2]*(rapidity
            - finalParams[m_currentDnDyParameters+1]))*(rapidity - finalParams[m_currentDnDyParameters+1]),2.0) );
        singleFunct->SetParameter(1,temperature);
        singleFunct->SetParError(1,tempErr);
        singleFunct->SetParameter(2,pionMass);
        singleFunct->SetParError(2,0.0);


        TGraphErrors* spectrum = NULL;
        if(m_currentCharge == 1) spectrum = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][rapIndex];
        else                     spectrum = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][rapIndex];

        if(a_saveFinalFits){

          fittingCanvas->cd();

          double smallYVal =  HistogramUtilities::findSmallestYVal(spectrum)*0.25;
          double largeXVal =  HistogramUtilities::findLargestXVal(spectrum)*1.3;
          if(smallYVal < 0.0) smallYVal = 1e-6;
          TH1F *frame = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(spectrum)*4.0);
          frame->SetTitle(Form("#pi^{%s} Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
            m_cuts->getRapidityRangeLow(rapIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(rapIndex,m_currentPartIndex,1),
            m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
          frame->GetXaxis()->SetTitle("m_{T}-m_{#pi} (GeV/c^{2})");
          frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
          gPad->SetLogy();
          gPad->SetRightMargin(0.4);

          spectrum->SetMarkerStyle(20);
          spectrum->Draw("P");
          singleFunct->Draw("same");

          TPaveText *fitParsTxt = new TPaveText(0.65,0.15,0.95,0.85,"NDC");
          fitParsTxt->AddText(Form("dN/dy \t %f#pm%f",singleFunct->GetParameter(0),singleFunct->GetParError(0)));
          fitParsTxt->AddText(Form("T_{low} \t %f#pm%f",temperature,tempErr));
          fitParsTxt->AddText(Form("m_{#pi} \t %f#pm%f",m_partInfo->GetParticleMass(0),0.0));

          fitParsTxt->SetFillStyle(0);
          fitParsTxt->SetBorderSize(5);

          fitParsTxt->Draw("same");

          fittingCanvas->Update();
          fittingCanvas->SaveAs(Form("%s/%s/FinalFit_Nom_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,rapIndex));

        }

        if(m_currentCharge == 1){
          if(a_isNominal){
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(rapIndex+1, finalParams[iii]);
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(rapIndex+1,singleFunct->GetParError(0));
            m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(rapIndex+1,temperature);
            m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(rapIndex+1,tempErr);
            m_nominalFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = singleFunct;
          }else{
            m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(rapIndex+1, finalParams[iii]);
            m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(rapIndex+1,singleFunct->GetParError(0));
            m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(rapIndex+1,temperature);
            m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(rapIndex+1,tempErr);
            m_systematicFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = singleFunct;
          }
        }else{
          if(a_isNominal){
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(rapIndex+1, finalParams[iii]);
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(rapIndex+1,singleFunct->GetParError(0));
            m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(rapIndex+1,temperature);
            m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(rapIndex+1,tempErr);
            m_nominalFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = singleFunct;
          }else{
            m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(rapIndex+1, finalParams[iii]);
            m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(rapIndex+1,singleFunct->GetParError(0));
            m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(rapIndex+1,temperature);
            m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(rapIndex+1,tempErr);
            m_systematicFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = singleFunct;
          }
        }//is plus or minus
      }//rap loop
    }// pm index
  }// cent index

}


