        BE_low->SetParameters(dNdy_low,tempLow,m_partInfo->GetParticleMass(0));
        BE_low->SetLineColor(kMagenta);

        TF1 *BE_high = new TF1("BE_high","([0]/(exp( (x+[2])/[1]) - 1.0)) / (6.283185307179586 * [1]*[1]*( PhysMath::Li2(exp(-[2]/[1])) - [2]*log(1.0 - exp(-[2]/[1]))/[1] ) )",0.0,10.0);
