      dNdyHigh_init_sys->SetTitle("dN/dy_{high} Sys Initial Values");
      dNdyHigh_init_sys->GetXaxis()->SetTitle("y_{lab}");
      dNdyHigh_init_sys->GetYaxis()->SetTitle("dN/dy_{high}");
      dNdyHigh_init_sys->SetMarkerStyle(20);

      TGraph *tempLow_init = new TGraph(m_liveRapidityValuePionSpectra_charge[pmIndex].size(),&m_liveRapidityValuePionSpectra_charge[pmIndex][0],&tempLowStorage[pmIndex][0]);
      tempLow_init->SetTitle("Temp_{low} Initial Values");
      tempLow_init->GetXaxis()->SetTitle("y_{lab}");
