      tempLow_init->SetMarkerStyle(20);

      TGraph *tempLow_init_sys = new TGraph(m_liveRapidityValuePionSpectra_charge[pmIndex].size(),&m_liveRapidityValuePionSpectra_charge[pmIndex][0],&tempLowStorage_sys[pmIndex][0]);
      tempLow_init_sys->SetTitle("Temp_{low} Sys Initial Values");
      tempLow_init_sys->GetXaxis()->SetTitle("y_{lab}");
      tempLow_init_sys->GetYaxis()->SetTitle("Temp_{low} (GeV)");
