      TGraph *tempHigh_init = new TGraph(m_liveRapidityValuePionSpectra_charge[pmIndex].size(),&m_liveRapidityValuePionSpectra_charge[pmIndex][0],&tempStorage[pmIndex][0]);
      tempHigh_init->SetTitle("Temp_{high} Initial Values");
      tempHigh_init->GetXaxis()->SetTitle("y_{lab}");
