void SpectraFitter::fitPionSpectraWithDoubleBoseEinstein(double a_momOfHighTempConstraint){
  cout << "Fitting Pion Spectra" << endl;
  m_currentPartIndex = 0;
  m_isCurrentFitNominal = true;
  TCanvas* fittingCanvas = new TCanvas("fittingCanvas","Fitting Canvas");
  fittingCanvas->SetWindowSize(1300,700);
  fittingCanvas->SetCanvasSize(1200,600);

  double pionMass = m_partInfo->GetParticleMass(0);
  for(unsigned int centIndex = 0; centIndex < 16; centIndex++){
    m_currentCentIndex = centIndex;
    for(int pmIndex = 0; pmIndex < 2; pmIndex++){
      m_currentCharge = 1;
      if(pmIndex == 1) m_currentCharge = -1;

      m_isTemperatureConstrained = false;
      for(unsigned int yIndex = 0; yIndex < m_cuts->getRapMtM0BinStructure(0, 1)->GetNbinsX(); yIndex++){
        m_currentRapValue = m_cuts->getRapMtM0BinStructure(0, 1)->GetBinCenter(yIndex+1);
        m_currentRapIndex = yIndex;
        double mTm0_highTempLowBound = PhysMath::mTm0_from_y_p(m_currentRapValue, a_momOfHighTempConstraint, pionMass);
        TGraphErrors* specPM[2];
        specPM[0] = m_totalSpectra_Plus[0][m_currentCentIndex][yIndex];
        specPM[1] = m_totalSpectra_Minus[0][m_currentCentIndex][yIndex];
        if( !specPM[pmIndex] || specPM[pmIndex]->GetN() <= 0 ) continue;

        cout << "Pion Fitting: Cent " << m_currentCentIndex << " yIndex " << yIndex << " charge: " << m_currentCharge << " ptr: " << specPM[pmIndex] << " N: " << specPM[pmIndex]->GetN() <<  endl;
        cout << "TGraph Title : " << specPM[pmIndex]->GetTitle() << endl;

        //##########  FIT WITH SINGLE BOSE EINSTEIN FIT FUNCTION IN HIGH PT REGION ##########
        m_currentSpectra = specPM[pmIndex];
        //m_currentSpectra = (TGraphErrors*) specPM[pmIndex]->Clone();
        cout << "Working with graph named " << m_currentSpectra->GetTitle() << endl;;
        //scaleTGraphByInvFactor(m_currentSpectra, pionMass);
        //HistogramUtilities::shiftTGraph(m_currentSpectra, pionMass);
        init_boseEinstein();

        TF1* initial_BE_fit = (TF1*) m_boseEinstein->Clone();
        initial_BE_fit->SetLineColor(kYellow);
        initial_BE_fit->SetName("initial_BE_fit");


        //##### check to make sure there are points beyond cutoff #####
        int numPointsAboveCutOff = 0;
        for(int pointIndex = 0; pointIndex < m_currentSpectra->GetN(); pointIndex++){
          double X_ofPoint = 0.0;
          double Y_ofPoint = 0.0;
          m_currentSpectra->GetPoint(pointIndex,X_ofPoint,Y_ofPoint);
          if(X_ofPoint > mTm0_highTempLowBound) numPointsAboveCutOff++;
        }
        if(numPointsAboveCutOff < 3) continue;


        int status= m_currentSpectra->Fit("m_boseEinstein","E EX0","",mTm0_highTempLowBound,10);
        TF1* fitResult = m_currentSpectra->GetFunction("m_boseEinstein");

        //#####  make the fit image #####
        fittingCanvas->cd();
        double smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
        double largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
        if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
        frame->SetTitle(Form("#pi^{%s} Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
          m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
          m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
        frame->GetXaxis()->SetTitle("m_{T}-m_{#pi} (GeV/c^{2})");
        frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);
        initial_BE_fit->Draw("same");
        m_currentSpectra->Draw("P");
        fittingCanvas->Update();
        fittingCanvas->SaveAs(Form("%s/%s/Fit_Nom_HighPT_SingleFit_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));


        //###### STORE THE FIT DATA #######
        if(status == 0){
          //push the fit results back
          double Amp = fitResult->GetParameter(0);
          double AmpErr = fitResult->GetParError(0);
          cout << "Amp: " << Amp << " +/- " << AmpErr/Amp*100.0 << "%" << endl;
          if(m_currentCharge == 1){
            if(!std::isnan(Amp) && !std::isnan(AmpErr)){
              m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,Amp);
              m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,AmpErr);
            }
          }else{
            if(!std::isnan(Amp) && !std::isnan(AmpErr)){
              m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,Amp);
              m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,AmpErr);
            }
          }

          double Temp = fitResult->GetParameter(1);
          double Temp_err = fitResult->GetParError(1);
          cout << "Temp: " << Temp << " +/- " << Temp_err/Temp*100.0 << "%" << endl;
          if(m_currentCharge == 1){
            if(!std::isnan(Temp) && !std::isnan(Temp_err)){
              m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,Temp);
              m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,Temp_err);
              cout << "temp rap index: " << yIndex << " bin center: " << m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->GetBinCenter(yIndex+1) << endl;
            }
          }else{
            if(!std::isnan(Temp) && !std::isnan(Temp_err)){
              m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,Temp);
              m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,Temp_err);
            }
          }
        }
      }


      //####################################################
      //##########  CONSTRAIN HIGH PT TEMPERATURE ##########
      //####################################################
      cout << "####################################################" << endl;
      cout << "##########  CONSTRAIN HIGH PT TEMPERATURE ##########" << endl;
      cout << "####################################################" << endl;
      TH1D* temperature_histo_nom = NULL;
      if(m_currentCharge == 1){
        temperature_histo_nom = m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex];
      }else{
        temperature_histo_nom = m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex];
      }

      m_currentTemperatureHisto = temperature_histo_nom;
      init_gausFunctForTemp();
      int status_temp = temperature_histo_nom->Fit("m_gausFunct","E");
      TF1* fitResult_Nom = temperature_histo_nom->GetFunction("m_gausFunct");
      cout << "TempConstraint :  N:" << fitResult_Nom->GetParameter(0) << " mean:" << fitResult_Nom->GetParameter(1) << " stdDev:" << fitResult_Nom->GetParameter(2) << endl;
      fittingCanvas->cd();
      gPad->SetLogy(false);
      temperature_histo_nom->Draw("E");
      fittingCanvas->SaveAs(Form("%s/%s/TemperatureFit_Nom_HighPt_SingleFit_Cent%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));

      double highPtTempStorage[100];
      for(unsigned int yIndex = 0; yIndex < m_cuts->getRapMtM0BinStructure(0, 1)->GetNbinsX(); yIndex++){
        //m_currentRapValue = m_cuts->getRapMtM0BinStructure(0, 1)->GetBinCenter(yIndex+1);
        m_currentRapValue = m_cuts->getRapidityRangeCenter(yIndex,0,1);
        highPtTempStorage[yIndex] = fitResult_Nom->Eval(m_currentRapValue);
      }

      //#########################################################################
      //##########    REFIT WITH HIGH PT TEMPERATURE CONSTRAINED ################
      //#########################################################################
      cout << "#########################################################################" << endl;
      cout << "##########    REFIT WITH HIGH PT TEMPERATURE CONSTRAINED ################" << endl;
      cout << "#########################################################################" << endl;
      m_isTemperatureConstrained = true;
      for(unsigned int yIndex = 0; yIndex < m_cuts->getRapMtM0BinStructure(0, 1)->GetNbinsX(); yIndex++){
        //m_currentRapValue = m_cuts->getRapMtM0BinStructure(0, 1)->GetBinCenter(yIndex+1);
        m_currentRapValue = m_cuts->getRapidityRangeCenter(yIndex,0,1);
        m_currentRapIndex = yIndex;

        TGraphErrors* specPM[2];
        specPM[0] = m_totalSpectra_Plus[0][m_currentCentIndex][yIndex];
        specPM[1] = m_totalSpectra_Minus[0][m_currentCentIndex][yIndex];
        if( !specPM[pmIndex] || specPM[pmIndex]->GetN() <= 0 ) continue;

        cout << "Pion Fitting: Cent " << m_currentCentIndex << " yIndex " << yIndex << " ptr: " << specPM[pmIndex] << " N: " << specPM[pmIndex]->GetN() <<  endl;
        cout << "    spec title: " << specPM[pmIndex]->GetTitle() << endl;
        cout << "    rapidity: " << m_currentRapValue << endl;

        m_isCurrentFitNominal = true;
        m_currentSpectra = specPM[pmIndex];


        //##########     INITIALIZE DOUBLE BOSE EINSTEIN    ###########
        double initialHighPtAmp = 0;
        if(m_currentCharge == 1){
          initialHighPtAmp = m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->GetBinContent(yIndex+1);
        }else{
          initialHighPtAmp = m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->GetBinContent(yIndex+1);
        }

        double constantHighTemp = highPtTempStorage[yIndex];
        m_doubleBoseEinstein->SetParameter(0,0.5*initialHighPtAmp);
        m_doubleBoseEinstein->SetParLimits(0,0.0, initialHighPtAmp*0.9);
        m_doubleBoseEinstein->SetParameter(1,constantHighTemp*0.75);
        m_doubleBoseEinstein->SetParLimits(1, 0.0 , constantHighTemp*0.9);
        m_doubleBoseEinstein->FixParameter(2,pionMass);
        m_doubleBoseEinstein->SetParameter(3,initialHighPtAmp);
        m_doubleBoseEinstein->SetParLimits(3,0.1 * initialHighPtAmp,10.0 * initialHighPtAmp);
        m_doubleBoseEinstein->FixParameter(4,constantHighTemp);


        TF1* initial_BE_fit = (TF1*) m_doubleBoseEinstein->Clone();
        initial_BE_fit->SetLineColor(kYellow);
        initial_BE_fit->SetName("initial_BE_fit");
        TFitResultPtr resultPtr = m_currentSpectra->Fit("m_doubleBoseEinstein","ES EX0","",0,10);
        TF1* fitResult = m_currentSpectra->GetFunction("m_doubleBoseEinstein");

        //########  make the fit image ############
        fittingCanvas->cd();
        double smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
        double largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
        if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
        frame->SetTitle(Form("#pi^{%s} Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
          m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
          m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
        //frame->GetXaxis()->SetTitle("m_{T} (GeV/c^{2})");
        //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame->GetXaxis()->SetTitle("m_{T}-m_{#pi} (GeV/c^{2})");
        frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);
        initial_BE_fit->Draw("same");
        m_currentSpectra->Draw("P");
        fittingCanvas->Update();
        fittingCanvas->SaveAs(Form("%s/%s/Fit_Nom_HighPtTempConstrained_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));
        //delete initial_BE_fit;

        //push the fit results back
        double AmpLow = fitResult->GetParameter(0);
        double AmpLowErr = fitResult->GetParError(0);
        cout << "AmpLow: " << AmpLow << " +/- " << AmpLowErr/AmpLow*100.0 << "%" << endl;
        double Amp = fitResult->GetParameter(3);
        double AmpErr = fitResult->GetParError(3);
        cout << "Amp: " << Amp << " +/- " << AmpErr/Amp*100.0 << "%" << endl;

        if(m_currentCharge == 1){
          if(!std::isnan(AmpLow) && !std::isnan(AmpLowErr)){
            m_dNdyLow_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,AmpLow);
            m_dNdyLow_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,AmpLowErr);
          }
          if(!std::isnan(Amp) && !std::isnan(AmpErr)){
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,Amp);
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,AmpErr);
          }
        }else{
          if(!std::isnan(Amp) && !std::isnan(AmpErr)){
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,Amp);
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,AmpErr);
          }
          if(!std::isnan(AmpLow) && !std::isnan(AmpLowErr)){
            m_dNdyLow_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,AmpLow);
            m_dNdyLow_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,AmpLowErr);
          }
        }

        double Temp = fitResult->GetParameter(1);
        double Temp_err = fitResult->GetParError(1);
        cout << "    Temp: " << Temp << " +/- " << Temp_err/Temp*100.0 << "%" << endl;
        if(m_currentCharge == 1){
          if(!std::isnan(Temp) && !std::isnan(Temp_err)){
            m_TempLow_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,Temp);
            m_TempLow_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,Temp_err);
          }
        }else{
          if(!std::isnan(Temp) && !std::isnan(Temp_err)){
            m_TempLow_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,Temp);
            m_TempLow_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,Temp_err);
          }
        }

      } // end rapidity loop



      //###################################################
      //##########  CONSTRAIN LOW PT TEMPERATURE ##########
      //###################################################
      cout << "###################################################" << endl;
      cout << "##########  CONSTRAIN LOW PT TEMPERATURE ##########" << endl;
      cout << "###################################################" << endl;
      temperature_histo_nom = NULL;
      if(m_currentCharge == 1){
        temperature_histo_nom = m_TempLow_Plus_Nominal[m_currentPartIndex][m_currentCentIndex];
      }else{
        temperature_histo_nom = m_TempLow_Minus_Nominal[m_currentPartIndex][m_currentCentIndex];
      }

      m_currentTemperatureHisto = temperature_histo_nom;
      //init_gausFunctForTemp();
      init_constFunctForTemp();
      m_constFunct->SetParameter(0,0.05);
      m_constFunct->SetParLimits(0,0.05*0.1,0.05*2);
      int status_temp_lowPt = temperature_histo_nom->Fit("m_constFunct","E");
      TF1* fitResult_Nom_lowPt = temperature_histo_nom->GetFunction("m_constFunct");
      //cout << "TempConstraint :  N:" << fitResult_Nom_lowPt->GetParameter(0) << " mean:" << fitResult_Nom_lowPt->GetParameter(1) << " stdDev:" << fitResult_Nom_lowPt->GetParameter(2) << endl;
      fittingCanvas->cd();
      gPad->SetLogy(false);
      temperature_histo_nom->Draw("E");
      fittingCanvas->SaveAs(Form("%s/%s/TemperatureFit_LowPt_Nominal_Cent%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));


      double lowPtTempStorage[100];
      for(unsigned int yIndex = 0; yIndex < m_cuts->getRapMtM0BinStructure(0, 1)->GetNbinsX(); yIndex++){
        //m_currentRapValue = m_cuts->getRapMtM0BinStructure(0, 1)->GetBinCenter(yIndex+1);
        m_currentRapValue = m_cuts->getRapidityRangeCenter(yIndex,0,1);
        lowPtTempStorage[yIndex] = fitResult_Nom_lowPt->Eval(m_currentRapValue);
      }

      //######################################################################
      //##########    REFIT WITH BOTH TEMPERATURE CONSTRAINED ################
      //######################################################################
      cout << "######################################################################" << endl;
      cout << "##########    REFIT WITH BOTH TEMPERATURE CONSTRAINED ################" << endl;
      cout << "######################################################################" << endl;
      m_isTemperatureConstrained = true;
      for(unsigned int yIndex = 0; yIndex < m_cuts->getRapMtM0BinStructure(0, 1)->GetNbinsX(); yIndex++){
        //m_currentRapValue = m_cuts->getRapMtM0BinStructure(0, 1)->GetBinCenter(yIndex+1);
        m_currentRapValue = m_cuts->getRapidityRangeCenter(yIndex,0,1);
        m_currentRapIndex = yIndex;

        TGraphErrors* specPM[2];
        specPM[0] = m_totalSpectra_Plus[0][m_currentCentIndex][yIndex];
        specPM[1] = m_totalSpectra_Minus[0][m_currentCentIndex][yIndex];
        if( !specPM[pmIndex] || specPM[pmIndex]->GetN() <= 0 ) continue;

        cout << "Pion Fitting: Cent " << m_currentCentIndex << " yIndex " << yIndex << " ptr: " << specPM[pmIndex] << " N: " << specPM[pmIndex]->GetN() <<  endl;
        cout << "spec title: " << specPM[pmIndex]->GetTitle() << endl;
        cout << "rapidity: " << m_currentRapValue << endl;

        //##########  FIT WITH NOMINAL FIT FUNCTION ##########
        cout << "Nominal Fit" << endl;
        m_isCurrentFitNominal = true;
        m_currentSpectra = specPM[pmIndex];




        //##########     INITIALIZE DOUBLE BOSE EINSTEIN    ###########
        double initial_lowPt_amp = 0;
        double initial_highPt_amp = 0;
        if(m_currentCharge == 1){
          initial_lowPt_amp = m_dNdyLow_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->GetBinContent(yIndex+1);
          initial_highPt_amp = m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->GetBinContent(yIndex+1);
        }else{
          initial_lowPt_amp = m_dNdyLow_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->GetBinContent(yIndex+1);
          initial_highPt_amp = m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->GetBinContent(yIndex+1);
        }

        double constantHighTemp = highPtTempStorage[yIndex];
        double constantLowTemp = lowPtTempStorage[yIndex];
        m_doubleBoseEinstein->SetParameter(0,initial_lowPt_amp);
        m_doubleBoseEinstein->SetParLimits(0,0.0, initial_highPt_amp * 2.0);
        m_doubleBoseEinstein->FixParameter(1,constantLowTemp);
        m_doubleBoseEinstein->FixParameter(2,pionMass);
        m_doubleBoseEinstein->SetParameter(3,initial_highPt_amp*0.2);
        m_doubleBoseEinstein->SetParLimits(3,0.01*initial_lowPt_amp , 3.0 * initial_highPt_amp);
        m_doubleBoseEinstein->FixParameter(4,constantHighTemp);



        TF1* initial_BE_fit_tot = (TF1*) m_doubleBoseEinstein->Clone();
        initial_BE_fit_tot->SetLineColor(kYellow);
        initial_BE_fit_tot->SetName("initial_BE_fit_tot");
        TFitResultPtr resultPtr = m_currentSpectra->Fit("m_doubleBoseEinstein","ES EX0","",0,10);
        TF1* fitResult = m_currentSpectra->GetFunction("m_doubleBoseEinstein");



        //####  make the fit image  ######
        fittingCanvas->cd();
        double smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
        double largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
        if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
        frame->SetTitle(Form("#pi^{%s} Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
          m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
          m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
        //frame->GetXaxis()->SetTitle("m_{T} (GeV/c^{2})");
        //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame->GetXaxis()->SetTitle("m_{T}-m_{#pi} (GeV/c^{2})");
        frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);
        initial_BE_fit_tot->Draw("same");
        m_currentSpectra->Draw("P");
        fittingCanvas->Update();
        fittingCanvas->SaveAs(Form("%s/%s/Fit_Nom_TempConstrained_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));
        //delete initial_BE_fit;

        double dNdy = 0;
        double dNdyAvg = 0;
        double dNdyErr = 0;

        cout << "Starting Bootstraping: " << endl;
        FitUtilities::bootstrapIntegralMultiParameter(dNdy,dNdyAvg, dNdyErr, fitResult, resultPtr.Get(),pionMass);
        cout << "dNdy: " << dNdy << " +/- " << dNdyErr/dNdy*100.0 << "%" << endl;


        if(m_currentCharge == 1){
          if(!std::isnan(dNdy) && !std::isnan(dNdyErr)){
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdy);
            m_dNdy_Plus_Nominal_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdyAvg);
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
            m_dNdy_Plus_Nominal_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
            TF1* fitResultClone = (TF1*) fitResult->Clone();
            fitResultClone->SetName(Form("NominalFit_Cent%02d_yIndex%02d",m_currentCentIndex,yIndex));
            m_nominalFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitResultClone;
          }
        }else{
          if(!std::isnan(dNdy) && !std::isnan(dNdyErr)){
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdy);
            m_dNdy_Minus_Nominal_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdyAvg);
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
            m_dNdy_Minus_Nominal_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
            TF1* fitResultClone = (TF1*) fitResult->Clone();
            fitResultClone->SetName(Form("NominalFit_Cent%02d_yIndex%02d",m_currentCentIndex,yIndex));
            m_nominalFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitResultClone;
          }
        }

      } // end rapidity loop




    }// pm index
  }// cent index

}


