          m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityKaonSpectra[iii]+1,dNdy_err);

          m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityKaonSpectra[iii]+1,temp);
          m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityKaonSpectra[iii]+1,tempErr);

          m_nominalFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;

          m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityKaonSpectra[iii]+1, dNdy_sys);
          m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityKaonSpectra[iii]+1,dNdy_err_sys);

