void SpectraFitter::fitProtonSpectraIndivBlastWave(bool a_constrainTemperature){
  cout << "Fitting Proton Spectra" << endl;
  m_currentPartIndex = 2;

  TCanvas* fittingCanvas = new TCanvas("fittingCanvas","Fitting Canvas");
  fittingCanvas->SetWindowSize(1300,700);
  fittingCanvas->SetCanvasSize(1200,600);

  double pionMass = m_partInfo->GetParticleMass(2);
  for(unsigned int centIndex = 0; centIndex < 16; centIndex++){
    m_currentCentIndex = centIndex;
    for(int pmIndex = 0; pmIndex < 2; pmIndex++){
      m_currentCharge = 1;
      if(pmIndex == 1) m_currentCharge = -1;

      m_isTemperatureConstrained = false;
      for(unsigned int yIndex = 0; yIndex < m_cuts->getRapMtM0BinStructure(2, 1)->GetNbinsX(); yIndex++){
        m_currentRapValue = m_cuts->getRapMtM0BinStructure(2, 1)->GetBinCenter(yIndex+1);
        m_currentRapIndex = yIndex;
        TGraphErrors* specPM[2];
        specPM[0] = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][yIndex];
        specPM[1] = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][yIndex];
        if( !specPM[pmIndex] || specPM[pmIndex]->GetN() <= 0 ) continue;

        cout << "Proton Fitting: Cent " << m_currentCentIndex << " yIndex " << yIndex << " charge: " << m_currentCharge << " ptr: " << specPM[pmIndex] << " N: " << specPM[pmIndex]->GetN() <<  endl;
        cout << "TGraph Title : " << specPM[pmIndex]->GetTitle() << endl;

        //##########  FIT WITH NOMINAL FIT FUNCTION ##########
        cout << "Nominal Fit" << endl;
        m_isCurrentFitNominal = true;
        m_currentSpectra = specPM[pmIndex];
        //m_currentSpectra = (TGraphErrors*) specPM[pmIndex]->Clone();
        cout << "Working with graph named " << m_currentSpectra->GetTitle() << endl;;
        //scaleTGraphByInvFactor(m_currentSpectra, pionMass);
        //HistogramUtilities::shiftTGraph(m_currentSpectra, pionMass);
        init_blastWave();

        TF1* initial_BW_fit = (TF1*) m_blastWave->Clone();
        initial_BW_fit->SetLineColor(kYellow);
        initial_BW_fit->SetName("initial_BW_fit");
        int status= m_currentSpectra->Fit("m_blastWave","E","",0,10);
        TF1* fitResult = m_currentSpectra->GetFunction("m_blastWave");

        //make the fit image
        fittingCanvas->cd();
        double smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
        double largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
        if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
        frame->SetTitle(Form("%s Spectra y=[%1.2f,%1.2f] %.0f-%.0f%% Centrality",pmIndex ? "#bar{p}":"p",
          m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
          m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
        //frame->GetXaxis()->SetTitle("m_{T} (GeV/c^{2})");
        //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        frame->GetXaxis()->SetTitle("m_{T}-m_{p} (GeV/c^{2})");
        frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);
        initial_BW_fit->Draw("same");
        m_currentSpectra->Draw("P");

        fittingCanvas->Update();
        fittingCanvas->SaveAs(Form("%s/%s/Fit_Nom_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));
        //delete initial_BE_fit;

        if(status == 0){
          //push the fit results back
          double dNdy = fitResult->GetParameter(0);
          double dNdyErr = fitResult->GetParError(0);
          #ifdef _SPECTRA_FITTER_DEBUG_
            cout << "dNdy: " << dNdy << " +/- " << dNdyErr/dNdy*100.0 << "%" << endl;
          #endif
          if(m_currentCharge == 1){
            if(!std::isnan(dNdy) && !std::isnan(dNdyErr)){
              m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdy);
              m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
            }
          }else{
            if(!std::isnan(dNdy) && !std::isnan(dNdyErr)){
              m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdy);
              m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
            }
          }

          double Temp = fitResult->GetParameter(1);
          double Temp_err = fitResult->GetParError(1);
          #ifdef _SPECTRA_FITTER_DEBUG_
            cout << "Temp: " << Temp << " +/- " << Temp_err/Temp*100.0 << "%" << endl;
          #endif
          if(m_currentCharge == 1){
            if(!std::isnan(Temp) && !std::isnan(Temp_err)){
              m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,Temp);
              m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,Temp_err);
              cout << "temp rap index: " << yIndex << " bin center: " << m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->GetBinCenter(yIndex+1) << endl;
            }
          }else{
            if(!std::isnan(Temp) && !std::isnan(Temp_err)){
              m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,Temp);
              m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,Temp_err);
            }
          }

          double betaS = fitResult->GetParameter(2);
          double betaSErr = fitResult->GetParError(2);
          #ifdef _SPECTRA_FITTER_DEBUG_
            cout << "BetaS: " << betaS << " +/- " << betaSErr/betaS*100 << "%" << endl;
          #endif
          if(m_currentCharge == 1){
            if(!std::isnan(betaS) && !std::isnan(betaSErr)){
              m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinContent(yIndex+1,betaS);
              m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinError(yIndex+1,betaSErr);
              cout << "betaS rap index: " << yIndex << " bin center: " << m_BetaS_Plus_Nominal[m_currentCentIndex]->GetBinCenter(yIndex+1) << endl;
            }
          }
        }








        //##########  FIT WITH SYSTEMATIC FIT FUNCTION ##########
        #ifdef _SPECTRA_FITTER_DEBUG_
          cout << "Systematic Fit" << endl;
        #endif
        m_isCurrentFitNominal = false;
        //m_currentSpectra = (TGraphErrors*) specPM[pmIndex]->Clone();
        //scaleTGraphByInvFactor(m_currentSpectra, pionMass);
        //HistogramUtilities::shiftTGraph(m_currentSpectra,pionMass);
        //m_currentSpectraAsymm = HistogramUtilities::convertPlot_mT_to_pT(m_currentSpectra, pionMass);
        //m_currentSpectraAsymm->SetMarkerSize(0.5);
        //m_currentSpectraAsymm->SetMarkerStyle(20);
        //m_currentSpectra = HistogramUtilities::convertAsymToNoAsym(ptSpecWithError);
        init_pTExponential();
        TF1* initial_PE_fit = (TF1*) m_pTExponential->Clone();
        initial_PE_fit->SetLineColor(kYellow);
        initial_PE_fit->SetName("initial_PE_fit");
        //int status_sys = m_currentSpectraAsymm->Fit("m_pTExponential","E","",0,10);
        //TF1* fitResultSys = m_currentSpectraAsymm->GetFunction("m_pTExponential");
        int status_sys = m_currentSpectra->Fit("m_pTExponential","E","",0,10);
        TF1* fitResultSys = m_currentSpectra->GetFunction("m_pTExponential");
        //make the fit image
        fittingCanvas->cd();
        smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
        largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
        if(smallYVal < 0.0) smallYVal = 1e-6;
        frame = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
        frame->SetTitle(Form("%s Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ?"#bar{p}":"p",
          m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
          m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
        //frame->GetXaxis()->SetTitle("p_{T} (GeV/c)");
        //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dp_{T}dy}");
        frame->GetXaxis()->SetTitle("m_{T}-m_{#pi} (GeV/c^{2})");
        frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");

        gPad->SetLogy();
        gPad->SetRightMargin(0.4);
        initial_PE_fit->Draw("same");
        m_currentSpectra->Draw("P");
        fittingCanvas->Update();
        fittingCanvas->SaveAs(Form("%s/%s/Fit_Sys_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));
        //delete initial_PE_fit;

        //push the fit results back
        if(status_sys == 0){
          double dNdy    = fitResultSys->GetParameter(0);
          double dNdyErr = fitResultSys->GetParError(0);
          #ifdef _SPECTRA_FITTER_DEBUG_
            cout << "dNdy: " << dNdy << " +/- " << dNdyErr/dNdy*100.0 << "%" << endl;
          #endif
          if(m_currentCharge == 1){
            if(std::isfinite(dNdy) && std::isfinite(dNdyErr)){
              m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdy);
              m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
            }
          }else{
            if(std::isfinite(dNdy) && std::isfinite(dNdyErr)){
              m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdy);
              m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
            }
          }

          double Temp     = fitResultSys->GetParameter(1);
          double Temp_err = fitResultSys->GetParError(1);
          #ifdef _SPECTRA_FITTER_DEBUG_
            cout << "Temp: " << Temp << " +/- " << Temp_err/Temp*100.0 << "%" << endl;
          #endif
          if(m_currentCharge == 1){
            if(std::isfinite(Temp) && std::isfinite(Temp_err)){
              m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,Temp);
              m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,Temp_err);
            }
          }else{
            if(std::isfinite(Temp) && std::isfinite(Temp_err)){
              m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,Temp);
              m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,Temp_err);
            }
          }
        }

      } // end rapidity loop

      if(!a_constrainTemperature) continue;






      //##########  CONSTRAIN NOMINAL TEMPERATURE ##########
      TH1D* temperature_histo_nom = NULL;
      TH1D* temperature_histo_sys = NULL;
      if(m_currentCharge == 1){
        temperature_histo_nom = m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex];
        temperature_histo_sys = m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex];
      }else{
        temperature_histo_nom = m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex];
        temperature_histo_sys = m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex];
      }

      m_currentTemperatureHisto = temperature_histo_nom;
      init_gausFunctForTemp();
      //init_constFunctForTemp();
      int status_temp = temperature_histo_nom->Fit("m_gausFunct","E");
      TF1* fitResult_Nom = temperature_histo_nom->GetFunction("m_gausFunct");
      //cout << "TempConstraint :  N:" << fitResult_Nom->GetParameter(0) << " mean:" << fitResult_Nom->GetParameter(1) << " stdDev:" << fitResult_Nom->GetParameter(2) << endl;
      //cout << "TempConstraint :  C:" << fitResult_Nom->GetParameter(0) << endl;
      fittingCanvas->cd();
      gPad->SetLogy(false);
      temperature_histo_nom->Draw("E");
      fittingCanvas->SaveAs(Form("%s/%s/TemperatureFit_Nominal_Cent%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));

      m_currentTemperatureHisto = temperature_histo_sys;
      init_gausFunctForTemp();
      int status_temp_sys = temperature_histo_sys->Fit("m_gausFunct","E");
      TF1* fitResult_Sys = temperature_histo_sys->GetFunction("m_gausFunct");
      //cout << "TempConstraint :  N:" << fitResult_Sys->GetParameter(0) << " mean:" << fitResult_Sys->GetParameter(1) << " stdDev:" << fitResult_Sys->GetParameter(2) << endl;

      fittingCanvas->cd();
      gPad->SetLogy(false);
      temperature_histo_sys->Draw("E");
      fittingCanvas->SaveAs(Form("%s/%s/TemperatureFit_Systematic_Cent%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));

      //Draw BetaS histogram
      m_currentTemperatureHisto = m_BetaS_Plus_Nominal[m_currentCentIndex];
      init_gausFunctForTemp();
      int status_betaS_nom = m_BetaS_Plus_Nominal[m_currentCentIndex]->Fit("m_gausFunct","E");
      TF1* betaS_Fit_Nom = m_BetaS_Plus_Nominal[m_currentCentIndex]->GetFunction("m_gausFunct");

      fittingCanvas->cd();
      m_BetaS_Plus_Nominal[m_currentCentIndex]->Draw("E");
      fittingCanvas->SaveAs(Form("%s/%s/betaS_Nom_Cent%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));

      //##########    REFIT WITH TEMPERATURE CONSTRAINED ################
      m_isTemperatureConstrained = true;
      for(unsigned int yIndex = 0; yIndex < m_cuts->getRapMtM0BinStructure(2, 1)->GetNbinsX(); yIndex++){
        //m_currentRapValue = m_cuts->getRapMtM0BinStructure(0, 1)->GetBinCenter(yIndex+1);
        m_currentRapValue = m_cuts->getRapidityRangeCenter(yIndex,2,1);
        m_currentRapIndex = yIndex;

        TGraphErrors* specPM[2];
        specPM[0] = m_totalSpectra_Plus[0][m_currentCentIndex][yIndex];
        specPM[1] = m_totalSpectra_Minus[0][m_currentCentIndex][yIndex];
        if( !specPM[pmIndex] || specPM[pmIndex]->GetN() <= 0 ) continue;

        #ifdef _SPECTRA_FITTER_DEBUG_
          cout << "Pion Fitting: Cent " << m_currentCentIndex << " yIndex " << yIndex << " ptr: " << specPM[pmIndex] << " N: " << specPM[pmIndex]->GetN() <<  endl;
          cout << "spec title: " << specPM[pmIndex]->GetTitle() << endl;
          cout << "rapidity: " << m_currentRapValue << endl;
        #endif
        //##########  FIT WITH NOMINAL FIT FUNCTION ##########
        #ifdef _SPECTRA_FITTER_DEBUG_
          cout << "Nominal Fit" << endl;
        #endif
        m_isCurrentFitNominal = true;
        m_currentSpectra = specPM[pmIndex];
        //m_currentSpectra = (TGraphErrors*) specPM[pmIndex]->Clone();
        //scaleTGraphByInvFactor(m_currentSpectra, pionMass);
        //HistogramUtilities::shiftTGraph(m_currentSpectra, pionMass);
        init_blastWave();
        TF1* initial_BW_fit = (TF1*) m_blastWave->Clone();
        initial_BW_fit->SetLineColor(kYellow);
        initial_BW_fit->SetName("initial_BW_fit");
        TFitResultPtr resultPtr = m_currentSpectra->Fit("m_blastWave","ES","",0,10);
        TF1* fitResult = m_currentSpectra->GetFunction("m_blastWave");

        //make the fit image
        fittingCanvas->cd();
        double smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
        double largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
        if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
        frame->SetTitle(Form("%s Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "#bar{p}":"p",
          m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
          m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
        //frame->GetXaxis()->SetTitle("m_{T} (GeV/c^{2})");
        //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame->GetXaxis()->SetTitle("m_{T}-m_{p} (GeV/c^{2})");
        frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);
        initial_BW_fit->Draw("same");
        m_currentSpectra->Draw("P");
        fittingCanvas->Update();
        fittingCanvas->SaveAs(Form("%s/%s/Fit_Nom_TempConstrained_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));
        //delete initial_BE_fit;

        //push the fit results back
        double Amp = fitResult->GetParameter(0);
        double AmpErr = fitResult->GetParError(0);
        #ifdef _SPECTRA_FITTER_DEBUG_
          cout << "Amp: " << Amp << " +/- " << AmpErr/Amp*100.0 << "%" << endl;
        #endif
        double dNdy    = 0;
        double dNdyAvg = 0;
        double dNdyErr = 0;

        FitUtilities::bootstrapIntegralSingleParameter(dNdy,dNdyAvg, dNdyErr, fitResult, resultPtr.Get(),pionMass,0);

        #ifdef _SPECTRA_FITTER_DEBUG_
          cout << "dNdy: " << dNdy << " +/- " << dNdyErr/dNdy*100.0 << "%" << endl;
        #endif


        if(m_currentCharge == 1){
          if(!std::isnan(dNdy) && !std::isnan(dNdyErr)){
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdy);
            m_dNdy_Plus_Nominal_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdyAvg);
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
            m_dNdy_Plus_Nominal_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
            TF1* fitResultClone = (TF1*) fitResult->Clone();
            fitResultClone->SetName(Form("NominalFit_Cent%02d_yIndex%02d",m_currentCentIndex,yIndex));
            fitResultClone->SetTitle(Form("%s Blast Wave Fit y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "#bar{p}":"p",
              m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
            m_nominalFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitResultClone;
          }
        }else{
          if(!std::isnan(dNdy) && !std::isnan(dNdyErr)){
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdy);
            m_dNdy_Minus_Nominal_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdyAvg);
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
            m_dNdy_Minus_Nominal_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
            TF1* fitResultClone = (TF1*) fitResult->Clone();
            fitResultClone->SetName(Form("NominalFit_Cent%02d_yIndex%02d",m_currentCentIndex,yIndex));
            fitResultClone->SetTitle(Form("%s Blast Wave Fit y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "#bar{p}":"p",
              m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
            m_nominalFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitResultClone;
          }
        }


        /*
        //##########  FIT WITH SYSTEMATIC FIT FUNCTION ##########
        m_isCurrentFitNominal = false;
        //m_currentSpectra = (TGraphErrors*) specPM[pmIndex]->Clone();
        //scaleTGraphByInvFactor(m_currentSpectra, pionMass);
        //HistogramUtilities::shiftTGraph(m_currentSpectra,pionMass);
        //m_currentSpectraAsymm = HistogramUtilities::convertPlot_mT_to_pT(m_currentSpectra, pionMass);
        //m_currentSpectraAsymm->SetMarkerSize(0.5);
        //m_currentSpectraAsymm->SetMarkerStyle(20);
        //m_currentSpectra = HistogramUtilities::convertAsymToNoAsym(ptSpecWithError);
        init_pTExponential();
        TF1* initial_PE_fit = (TF1*) m_pTExponential->Clone();
        initial_PE_fit->SetLineColor(kYellow);
        initial_PE_fit->SetName("initial_PE_fit");
        TFitResultPtr resultPtrSys = m_currentSpectra->Fit("m_pTExponential","ES","",0,10);
        TF1* fitResultSys = m_currentSpectra->GetFunction("m_pTExponential");



        //make the fit image
        fittingCanvas->cd();
        smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
        largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
        if(smallYVal < 0.0) smallYVal = 1e-6;
        frame = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
        frame->SetTitle(Form("#pi^{%s} Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
          m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
          m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
        //frame->GetXaxis()->SetTitle("p_{T} (GeV/c)");
        //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dp_{T}dy}");
        frame->GetXaxis()->SetTitle("m_{T}-m_{#pi} (GeV/c^{2})");
        frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);
        initial_PE_fit->Draw("same");
        m_currentSpectra->Draw("P");
        fittingCanvas->Update();
        fittingCanvas->SaveAs(Form("%s/%s/Fit_Sys_TempConstrained_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));
        //delete initial_PE_fit;

        //push the fit results back
        Amp = fitResultSys->GetParameter(0);
        //AmpAvg = 0;
        AmpErr = fitResultSys->GetParError(0);
        cout << "Amp: " << Amp << " +/- " << AmpErr/Amp*100.0 << "%" << endl;

        FitUtilities::bootstrapIntegralSingleParameter(dNdy,dNdyAvg, dNdyErr, fitResultSys, resultPtrSys.Get(), pionMass,0);
        cout << "dNdy: " << dNdy << " +/- " << dNdyErr/dNdy*100.0 << "%" << endl;

        if(m_currentCharge == 1){
          if(!std::isnan(dNdy) && !std::isnan(dNdyErr)){
            m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdy);
            m_dNdy_Plus_Systematic_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdyAvg);
            m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
            m_dNdy_Plus_Systematic_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
            TF1* fitResultClone = (TF1*) fitResultSys->Clone();
            fitResultClone->SetName(Form("SystematicFit_Cent%02d_yIndex%02d",m_currentCentIndex,yIndex));
            fitResultClone->SetTitle(Form("#pi^{%s} p_{T} Exponential Fit y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
              m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
            m_systematicFits_Plus[m_currentPartIndex][m_currentCentIndex].push_back(fitResultClone);
          }
        }else{
          if(!std::isnan(dNdy) && !std::isnan(dNdyErr)){
            m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdy);
            m_dNdy_Minus_Systematic_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinContent(yIndex+1,dNdyAvg);
            m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
            m_dNdy_Minus_Systematic_Avg[m_currentPartIndex][m_currentCentIndex]->SetBinError(yIndex+1,dNdyErr);
            TF1* fitResultClone = (TF1*) fitResultSys->Clone();
            fitResultClone->SetName(Form("SystematicFit_Cent%02d_yIndex%02d",m_currentCentIndex,yIndex));
            fitResultClone->SetTitle(Form("#pi^{%s} p_{T} Exponential Fit y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
              m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
            m_systematicFits_Minus[m_currentPartIndex][m_currentCentIndex].push_back(fitResultClone);
          }
        }
*/
      } // end rapidity loop


    }// pm index
  }// cent index

}

//############################################################################################################################################################
//###########################################################################################################################################################




void SpectraFitter::fitSpectra_Simultaneous_SingleCharge_Legendre_Constraints(int a_partIndex, int a_centIndex, int a_charge, bool a_isNominal, int a_lowRapIndex, int a_highRapIndex, double a_lowMtM0FitRange, double a_highMtM0FitRange){
  cout << "#####################  Starting SpectraFitter::fitProtonSpectra_Simultaneous_SingleCharge_Legendre_Constraints(" << a_centIndex << "," << a_charge << "," << a_isNominal << ") ########################" << endl;
  TVirtualFitter::SetMaxIterations(1000000);
  bool doAverageAmplitude = false; // automatic scaling is better?



  m_currentPartIndex = a_partIndex;
  m_currentLowFitRange = a_lowMtM0FitRange;
  m_currentHighFitRange = a_highMtM0FitRange;

  TCanvas* fittingCanvas = new TCanvas("fittingCanvas_Proton","Fitting Canvas");
  fittingCanvas->SetWindowSize(1300,700);
  fittingCanvas->SetCanvasSize(1200,600);
  double particleMass = m_partInfo->GetParticleMass(m_currentPartIndex);
  m_currentCentIndex = a_centIndex;
  m_currentCharge = a_charge;
  int pmIndex = 1;
  if(a_charge > 0) pmIndex = 0;
  m_liveRapiditySpectra.clear();
  m_liveRapidityValueSpectra.clear();

  if(m_currentPartIndex == 0){
    m_tsallis->SetParameter(0,1.0); // must be set because chi squared doesn't set these parameters every single time
    m_tsallis->SetParameter(1,1.0);
    m_tsallis->SetParameter(2,1.0);
    m_tsallis->SetParameter(3,particleMass);

    m_boseEinstein->SetParameter(0,1.0); // must be set because chi squared doesn't set these parameters every single time
    m_boseEinstein->SetParameter(1,1.0);
    m_boseEinstein->SetParameter(2,particleMass);

  }else if(m_currentPartIndex == 1){
    m_tsallis->SetParameter(0,1.0); // must be set because chi squared doesn't set these parameters every single time
    m_tsallis->SetParameter(1,1.0);
    m_tsallis->SetParameter(2,1.0);
    m_tsallis->SetParameter(3,particleMass);

    m_mTm0Exponential->SetParameter(0,1.0); // must be set because chi squared doesn't set these parameters every single time
    m_mTm0Exponential->SetParameter(1,1.0);
  }else if(m_currentPartIndex == 2){
    m_blastWave->SetParameter(3,1.0); // must be set because chi squared doesn't set these parameters every single time
    m_blastWave->SetParameter(4,1.0);
    m_blastWave->SetParameter(5,particleMass);
  }




  //### IF RAPIDITY INDEX RANGE NOT SPECIFIED, FIND MAX VALID RANGE #####
  int firstRapidityIndex = a_lowRapIndex;
  if(firstRapidityIndex < 0){
    for(int rapIndex = 0; rapIndex < g_SpecFit_MaxNumRapBins; rapIndex++){
      if(a_charge > 0){
        if(m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][rapIndex] && m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][rapIndex]->GetN() > 4){
          firstRapidityIndex = rapIndex;
        }
      }else{
        if(m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][rapIndex] && m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][rapIndex]->GetN() > 4){
          firstRapidityIndex = rapIndex;
        }
      }
    }
  }
  int lastRapidityIndex = a_highRapIndex;
  if(lastRapidityIndex < 0){
    for(int rapIndex = g_SpecFit_MaxNumRapBins - 1; rapIndex >= 0; rapIndex--){
      if(a_charge > 0){
        if(m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][rapIndex] && m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][rapIndex]->GetN() > 4){
          lastRapidityIndex = rapIndex;
        }
      }else{
        if(m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][rapIndex] && m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][rapIndex]->GetN() > 4){
          lastRapidityIndex = rapIndex;
        }
      }
    }
  }
  #ifdef _SPECTRA_FITTER_DEBUG_
    cout << "  Rapidity Index Range = [" << firstRapidityIndex << "," << lastRapidityIndex << "]" << endl;
  #endif


  //#### SET THE LIVE SPECTRA (THE ONES USED IN THE CHI SQUARED CALCULATION) ####
  //#### CALCULATE THE AVERAGE FIT PARAMETERS FROM INDIVIDUAL RAPIDITY FITS ####
  int    degreesOfFreedom          = 0;
  double averageDnDy               = 0.0;
  double averageDnDyWeights        = 0.0;
  double averageTemperature        = 0.0;
  double averageTemperatureWeights = 0.0;
  double averageBetaS              = 0.0;
  double averageBetaSWeights       = 0.0;
  for(int rapIndex = firstRapidityIndex; rapIndex <= lastRapidityIndex; rapIndex++){
    m_liveRapiditySpectra.push_back(rapIndex);
    m_liveRapidityValueSpectra.push_back(m_cuts->getRapMtM0BinStructure(m_currentPartIndex,1)->GetBinCenter(rapIndex+1));
    #ifdef _SPECTRA_FITTER_DEBUG_
      cout << "  Rapidity Index " << rapIndex << " is live with y=" << m_liveRapidityValueSpectra[m_liveRapidityValueSpectra.size()-1] << endl;
    #endif
    double dNdy     = 0.0;
    double dNdyErr  = 0.0;
    double Temp     = 0.0;
    double TempErr  = 0.0;
    double BetaS    = 0.0;
    double BetaSErr = 0.0;
    if(m_currentCharge > 0){
      degreesOfFreedom += HistogramUtilities::getNPointsInRange(m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][rapIndex], a_lowMtM0FitRange, a_highMtM0FitRange);
      if(a_isNominal){
        dNdy    = m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->GetBinContent(rapIndex + 1);
        dNdyErr = m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->GetBinError(rapIndex + 1);
        Temp    = m_Isolated_Nominal_Fit_Params_Plus[m_currentPartIndex][m_currentCentIndex][1]->GetBinContent(rapIndex + 1);
        TempErr = m_Isolated_Nominal_Fit_Params_Plus[m_currentPartIndex][m_currentCentIndex][1]->GetBinError(rapIndex + 1);
        BetaS   = m_Isolated_Nominal_Fit_Params_Plus[m_currentPartIndex][m_currentCentIndex][2]->GetBinContent(rapIndex + 1);
        BetaSErr= m_Isolated_Nominal_Fit_Params_Plus[m_currentPartIndex][m_currentCentIndex][2]->GetBinError(rapIndex + 1);
      }else{
        dNdy    = m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->GetBinContent(rapIndex + 1);
        dNdyErr = m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->GetBinError(rapIndex + 1);
        Temp    = m_Isolated_Systematic_Fit_Params_Plus[m_currentPartIndex][m_currentCentIndex][1]->GetBinContent(rapIndex + 1);
        TempErr = m_Isolated_Systematic_Fit_Params_Plus[m_currentPartIndex][m_currentCentIndex][1]->GetBinError(rapIndex + 1);
      }
    }else{
      degreesOfFreedom += HistogramUtilities::getNPointsInRange(m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][rapIndex], a_lowMtM0FitRange, a_highMtM0FitRange);
      if(a_isNominal){
        dNdy    = m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->GetBinContent(rapIndex + 1);
        dNdyErr = m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->GetBinError(rapIndex + 1);
        Temp    = m_Isolated_Nominal_Fit_Params_Minus[m_currentPartIndex][m_currentCentIndex][1]->GetBinContent(rapIndex + 1);
        TempErr = m_Isolated_Nominal_Fit_Params_Minus[m_currentPartIndex][m_currentCentIndex][1]->GetBinError(rapIndex + 1);
        BetaS   = m_Isolated_Nominal_Fit_Params_Minus[m_currentPartIndex][m_currentCentIndex][2]->GetBinContent(rapIndex + 1);
        BetaSErr= m_Isolated_Nominal_Fit_Params_Minus[m_currentPartIndex][m_currentCentIndex][2]->GetBinError(rapIndex + 1);
      }else{
        dNdy    = m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->GetBinContent(rapIndex + 1);
        dNdyErr = m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->GetBinError(rapIndex + 1);
        Temp    = m_Isolated_Systematic_Fit_Params_Minus[m_currentPartIndex][m_currentCentIndex][1]->GetBinContent(rapIndex + 1);
        TempErr = m_Isolated_Systematic_Fit_Params_Minus[m_currentPartIndex][m_currentCentIndex][1]->GetBinError(rapIndex + 1);
      }
    }

    if(!(std::isfinite(dNdyErr)&&std::isfinite(TempErr)&&std::isfinite(BetaSErr)) ){
      cout << "ERROR: Something went wrong! Did you not call the individual single rapidity fit function first??? Got NAN/INF for the errors on parameters: " << dNdyErr << " " << TempErr << " " << BetaSErr << endl;
    }

    if(dNdyErr > 0.0){
      averageDnDy        += dNdy/(dNdyErr*dNdyErr);
      averageDnDyWeights += 1.0/(dNdyErr*dNdyErr);
    }
    if(TempErr > 0.0){
      averageTemperature         += Temp/(TempErr*TempErr);
      averageTemperatureWeights  += 1.0/(TempErr*TempErr);
    }
    if(BetaSErr > 0.0){
      averageBetaS         += BetaS/(BetaSErr*BetaSErr);
      averageBetaSWeights  += 1.0/(BetaSErr*BetaSErr);
    }

    #ifdef _SPECTRA_FITTER_DEBUG_
      cout << "      AvgDnDy Now =  " << averageDnDy/averageDnDyWeights << "   T_Avg Now = " << averageTemperature/averageTemperatureWeights << "    BetaS_Avg Now = " << averageBetaS/averageBetaSWeights << endl;
    #endif


  } // End Rapidity Index Loop

  averageDnDy        = averageDnDy/averageDnDyWeights;
  averageTemperature = averageTemperature/averageTemperatureWeights;
  averageBetaS       = averageBetaS/averageBetaSWeights;

  #ifdef _SPECTRA_FITTER_DEBUG_
    cout << "      AvgDnDy =  " << averageDnDy << "   T_Avg = " << averageTemperature<< "    BetaS_Avg = " << averageBetaS << endl;
  #endif

  //#### DETERMINE THE AVERAGE AMPLITUDE #####
  double averageAmplitude = 0.0;

  if(m_currentPartIndex == 2 && a_isNominal){
    m_blastWave->SetParameters(1.0,averageTemperature,averageBetaS,1.0,1.0,particleMass);
    averageAmplitude = averageDnDy/m_blastWave->Integral(0.0,5.0);
  }else{
    m_tsallis->SetParameters(1.0,averageTemperature,averageBetaS,particleMass);
    m_boseEinstein->SetParameters(1.0,averageTemperature,particleMass);
    m_mTm0Exponential->SetParameters(1.0,averageTemperature);
    m_thermal->SetParameters(1.0,averageTemperature,particleMass); // mass must be set here, it isn't changed in chi^2 function
    averageAmplitude = averageDnDy; // dNdy is parameter of thermal function
  }


  #ifdef _SPECTRA_FITTER_DEBUG_
    cout << "  Calculated Average Parameters for Simulaneous Minimizer Seeds:" << endl;
    cout << "      Average dN/dy = " << averageDnDy << endl;
    cout << "      Average Temp  = " << averageTemperature << endl;
    cout << "      Average BetaS = " << averageBetaS << endl;
    cout << "      Average Amp   = " << averageAmplitude << endl;
  #endif


  //#### SETUP THE MINIMIZER AND PARAMTER LIMITS ####
  int numSpectraToFit = (int) m_liveRapiditySpectra.size();
  m_minimizer = ROOT::Math::Factory::CreateMinimizer();
  int numAdditionalParameters = 4;
  if(m_currentPartIndex == 0){
    if(a_isNominal){
      numAdditionalParameters = 8;
      if(m_currentCharge > 0){
        m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_tsallis_Legendre_qm1_And_Temp_Plus_ChiSqr,numSpectraToFit + numAdditionalParameters);
      }else{
        m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_tsallis_Legendre_qm1_And_Temp_Minus_ChiSqr,numSpectraToFit + numAdditionalParameters);
      }
    }else{
      if(m_currentCharge > 0){
        m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_boseEinstein_Legendre_Temp_Plus_ChiSqr,numSpectraToFit + numAdditionalParameters);
      }else{
        m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_boseEinstein_Legendre_Temp_Minus_ChiSqr,numSpectraToFit + numAdditionalParameters);
      }
    }
  }else if(m_currentPartIndex == 1){
    if(a_isNominal){
      numAdditionalParameters = 8;
      if(m_currentCharge > 0){
        m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_tsallis_Legendre_qm1_And_Temp_Plus_ChiSqr,numSpectraToFit + numAdditionalParameters);
      }else{
        m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_tsallis_Legendre_qm1_And_Temp_Minus_ChiSqr,numSpectraToFit + numAdditionalParameters);
      }
    }else{
      if(m_currentCharge > 0){
        m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_mTm0Exponential_Legendre_Temp_Plus_ChiSqr,numSpectraToFit + numAdditionalParameters);
      }else{
        m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_mTm0Exponential_Legendre_Temp_Minus_ChiSqr,numSpectraToFit + numAdditionalParameters);
      }
    }
  }else if(m_currentPartIndex == 2){
    if(a_isNominal){
      numAdditionalParameters = 8;
      if(m_currentCharge > 0){
        m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_blastWave_Legendre_BetaS_And_Temp_Plus_ChiSqr,numSpectraToFit + numAdditionalParameters);
      }else{
        m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_blastWave_Legendre_BetaS_And_Temp_Minus_ChiSqr,numSpectraToFit + numAdditionalParameters);
      }
    }else{
      if(m_currentCharge > 0){
        m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_thermal_Legendre_Temp_Plus_ChiSqr,numSpectraToFit + numAdditionalParameters);
      }else{
        m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_thermal_Legendre_Temp_Minus_ChiSqr,numSpectraToFit + numAdditionalParameters);
      }
    }
  }

  m_minimizer->SetFunction(*m_chiSqrdFunctor);
  for(int yIndexIndex = 0; yIndexIndex < numSpectraToFit; yIndexIndex++){
    double amp_to_use = averageAmplitude;
    if(!doAverageAmplitude){
      if(m_currentCharge > 0)  m_currentSpectra = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapiditySpectra[yIndexIndex]];
      else                     m_currentSpectra = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapiditySpectra[yIndexIndex]];
      int midPointIndex = m_currentSpectra->GetN()/2;
      if(m_currentPartIndex == 0){
        if(a_isNominal){
          m_tsallis->SetParameters(1.0,averageTemperature,averageBetaS,particleMass);
          amp_to_use = m_currentSpectra->GetY()[midPointIndex]/m_tsallis->Eval(m_currentSpectra->GetX()[midPointIndex]);
        }else{
          m_boseEinstein->SetParameters(1.0,averageTemperature,particleMass);
          amp_to_use = m_currentSpectra->GetY()[midPointIndex]/m_boseEinstein->Eval(m_currentSpectra->GetX()[midPointIndex]);
        }
      }else if(m_currentPartIndex == 1){
        if(a_isNominal){
          m_tsallis->SetParameters(1.0,averageTemperature,averageBetaS,particleMass);
          amp_to_use = m_currentSpectra->GetY()[midPointIndex]/m_tsallis->Eval(m_currentSpectra->GetX()[midPointIndex]);
        }else{
          m_mTm0Exponential->SetParameters(1.0,averageTemperature);
          amp_to_use = m_currentSpectra->GetY()[midPointIndex]/m_mTm0Exponential->Eval(m_currentSpectra->GetX()[midPointIndex]);
        }
      }else if(m_currentPartIndex == 2){
        if(a_isNominal){
          m_blastWave->SetParameters(1.0,averageTemperature,averageBetaS,1.0,1.0,particleMass);
          amp_to_use = m_currentSpectra->GetY()[midPointIndex]/m_blastWave->Eval(m_currentSpectra->GetX()[midPointIndex]);
        }else{
          m_thermal->SetParameters(1.0,averageTemperature,particleMass);
          amp_to_use = m_currentSpectra->GetY()[midPointIndex]/m_thermal->Eval(m_currentSpectra->GetX()[midPointIndex]);
        }
      }
    }

    if(m_currentPartIndex == 2 && a_isNominal){
      m_minimizer->SetVariable(yIndexIndex, Form("Amp_%02d",m_liveRapiditySpectra[yIndexIndex]), amp_to_use , 0.05*amp_to_use);
    }else{
      m_minimizer->SetVariable(yIndexIndex, Form("dNdy_%02d",m_liveRapiditySpectra[yIndexIndex]), amp_to_use , 0.05*amp_to_use);
    }
    m_minimizer->SetVariableLimits(yIndexIndex, 0.0001*amp_to_use, 10000.0*amp_to_use);
  }// end rapidity loop
  m_minimizer->SetVariable(numSpectraToFit    , "T_0" ,averageTemperature, 0.01);
  m_minimizer->SetVariable(numSpectraToFit + 1, "T_2" ,0.0, 0.01);
  m_minimizer->SetVariable(numSpectraToFit + 2, "T_4" ,0.0, 0.01);
  m_minimizer->SetVariable(numSpectraToFit + 3, "T_W" ,1.0, 0.1);
  m_minimizer->SetVariableLimits(numSpectraToFit    ,0.01*averageTemperature, 100.0*averageTemperature);
  m_minimizer->SetVariableLimits(numSpectraToFit + 1,-100.0, 100.0);
  m_minimizer->SetVariableLimits(numSpectraToFit + 2,-100.0, 100.0);
  //m_minimizer->FixVariable(numSpectraToFit + 2);
  m_minimizer->FixVariable(numSpectraToFit + 3);
  //m_minimizer->SetVariableLimits(numSpectraToFit + 3,   0.0, 50.0);

  if(a_isNominal){
    m_minimizer->SetVariable(numSpectraToFit + 4, m_currentPartIndex == 2 ? "#beta_{S}_0" : "q_minus_one_0" ,averageBetaS, 0.01);
    m_minimizer->SetVariable(numSpectraToFit + 5, m_currentPartIndex == 2 ? "#beta_{S}_2" : "q_minus_one_2" ,0.0, 0.01);
    m_minimizer->SetVariable(numSpectraToFit + 6, m_currentPartIndex == 2 ? "#beta_{S}_4" : "q_minus_one_4" ,0.0, 0.01);
    m_minimizer->SetVariable(numSpectraToFit + 7, m_currentPartIndex == 2 ? "#beta_{S}_W" : "q_minus_one_W" ,1.0, 0.1);
    if(m_currentPartIndex != 2){ //Tsallis
      m_minimizer->SetVariableLimits(numSpectraToFit + 4,0.0, 1.0);
      m_minimizer->SetVariableLimits(numSpectraToFit + 5,-1.0, 1.0);
      m_minimizer->SetVariableLimits(numSpectraToFit + 6,-1.0, 11.0);
    }else{
      m_minimizer->SetVariableLimits(numSpectraToFit + 4,0.01*averageBetaS, 100.0*averageBetaS);
      m_minimizer->SetVariableLimits(numSpectraToFit + 5,-10.0, 10.0);
      m_minimizer->SetVariableLimits(numSpectraToFit + 6,-10.0, 10.0);
    }

    //m_minimizer->FixVariable(numSpectraToFit + 5);
    //m_minimizer->FixVariable(numSpectraToFit + 6);

    m_minimizer->FixVariable(numSpectraToFit + 7);
    //m_minimizer->SetVariableLimits(numSpectraToFit + 7,   0.0, 50.0);
    degreesOfFreedom = degreesOfFreedom  - numSpectraToFit - 6;
  }else{
    degreesOfFreedom = degreesOfFreedom  - numSpectraToFit - 3;
  }

  #ifdef _SPECTRA_FITTER_DEBUG_
    m_minimizer->SetPrintLevel(6);
  #else
    m_minimizer->SetPrintLevel(1);
  #endif
  m_minimizer->SetMaxIterations(3000);
  m_minimizer->SetMaxFunctionCalls(200000);
  m_minimizer->SetValidError(true);


  //####      ACTUALLY FIT THE SPECTRA   ####
  m_minimizer->Minimize();
  int status = m_minimizer->Status();
  const double* finalParams = m_minimizer->X();
  if(status == 0){
    cout << "Fit Status: " << status << endl;
    m_minimizer->Hesse();
  }else{
    cout << "ERROR: " << (a_isNominal ? " Nominal " : " Systematic ") << "  FIT FAILED AT CENTRALITY " << m_currentCentIndex << " WITH STATUS " << status << endl;
    cout << "     Current Parameters: " << endl;
    for(int paramIndex = 0; paramIndex < (int) m_liveRapiditySpectra.size() + numAdditionalParameters; paramIndex++){
      cout << "  " << finalParams[paramIndex];
    } cout << endl;
    //continue;
  }


  double chiSquared = 0.0;
  if(m_currentPartIndex == 0){
    if(a_isNominal){
      if(m_currentCharge > 0) chiSquared = simultaneous_tsallis_Legendre_qm1_And_Temp_Plus_ChiSqr(finalParams);
      else                    chiSquared = simultaneous_tsallis_Legendre_qm1_And_Temp_Minus_ChiSqr(finalParams);
    }else{
      if(m_currentCharge > 0) chiSquared = simultaneous_boseEinstein_Legendre_Temp_Plus_ChiSqr(finalParams);
      else                    chiSquared = simultaneous_boseEinstein_Legendre_Temp_Minus_ChiSqr(finalParams);
    }
  }else if(m_currentPartIndex == 1){
    if(a_isNominal){
      if(m_currentCharge > 0) chiSquared = simultaneous_tsallis_Legendre_qm1_And_Temp_Plus_ChiSqr(finalParams);
      else                    chiSquared = simultaneous_tsallis_Legendre_qm1_And_Temp_Minus_ChiSqr(finalParams);
    }else{
      if(m_currentCharge > 0) chiSquared = simultaneous_mTm0Exponential_Legendre_Temp_Plus_ChiSqr(finalParams);
      else                    chiSquared = simultaneous_mTm0Exponential_Legendre_Temp_Minus_ChiSqr(finalParams);
    }
  }else if(m_currentPartIndex == 2){
    if(a_isNominal){
      if(m_currentCharge > 0) chiSquared = simultaneous_blastWave_Legendre_BetaS_And_Temp_Plus_ChiSqr(finalParams);
      else                    chiSquared = simultaneous_blastWave_Legendre_BetaS_And_Temp_Minus_ChiSqr(finalParams);
    }else{
      if(m_currentCharge > 0) chiSquared = simultaneous_thermal_Legendre_Temp_Plus_ChiSqr(finalParams);
      else                    chiSquared = simultaneous_thermal_Legendre_Temp_Minus_ChiSqr(finalParams);
    }
  }


  double chiSquaredPerDOF = chiSquared / ((double) degreesOfFreedom);

  #ifdef _SPECTRA_FITTER_DEBUG_
     cout << " Final Simultaneous Proton Fit:         Chi^2:     " << chiSquared << "        Chi^2/dof: " << chiSquaredPerDOF << endl;
  #endif


  //####  FORM VARIOUS COVARIANCE MATRICIES FOR ERROR PROPAGATION ######
  double covMatrixArray[110000];
  m_minimizer->GetCovMatrix(&covMatrixArray[0]);
  TMatrixDSym covMatrix(numSpectraToFit + numAdditionalParameters, &covMatrixArray[0]);
  vector<int> parsToKeep_TempMatrix = {numSpectraToFit,numSpectraToFit+1,numSpectraToFit+2,numSpectraToFit+3};
  vector<int> parsToKeep_BetaSMatrix = {numSpectraToFit+4,numSpectraToFit+5,numSpectraToFit+6,numSpectraToFit+7};
  TMatrixDSym TemperatureCovMatrix = PhysMath::reduceCovMatrix_keepPassedVector(covMatrix,parsToKeep_TempMatrix);
  TMatrixDSym BetaSCovMatrix = PhysMath::reduceCovMatrix_keepPassedVector(covMatrix,parsToKeep_BetaSMatrix);
  double temperatureParameters[4] = {finalParams[numSpectraToFit],finalParams[numSpectraToFit+1],finalParams[numSpectraToFit+2],finalParams[numSpectraToFit+3]};


  TF1* invariant_fitResult = NULL;
  TF1* nonInvariant_fitResult = NULL;
  TF1* betaSFunction = new TF1(Form("BetaSLegendre_%s_Cent%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex),
        "[0]+[1]*PhysMath::legendre(2,2.0*x/[3])+[2]*PhysMath::legendre(4,2.0*x/[3]);",-2.0,2.0);
  TF1* temperatureFunction = new TF1(Form("TemperatureLegendre_%s_Cent%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex),
        "[0]+[1]*PhysMath::legendre(2,2.0*x/[3])+[2]*PhysMath::legendre(4,2.0*x/[3]);",-2.0,2.0);
  temperatureFunction->SetParameters(temperatureParameters[0],temperatureParameters[1],temperatureParameters[2],temperatureParameters[3]);
  #ifdef _SPECTRA_FITTER_DEBUG_
     cout << " Temperature Parameters: " << temperatureParameters[0] << " " << temperatureParameters[1] << " " << temperatureParameters[2] << " " << temperatureParameters[3] << endl;
  #endif


  for(int yIndexIndex = 0; yIndexIndex < m_liveRapiditySpectra.size(); yIndexIndex++){ //this is a rapidity index index loop
    m_currentRapIndex   = m_liveRapiditySpectra[yIndexIndex];
    double rapidity     = m_liveRapidityValueSpectra[yIndexIndex];
    if(m_currentCharge > 0)  m_currentSpectra = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapiditySpectra[yIndexIndex]];
    else                     m_currentSpectra = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapiditySpectra[yIndexIndex]];


    double TempValue    = temperatureFunction->Integral(rapidity - 0.01,rapidity + 0.01)/0.02; // this shouldn't be full range because it isn't an integral in the chi^2
    double TempValueErr = temperatureFunction->IntegralError(rapidity - 0.01,rapidity + 0.01, temperatureParameters, TemperatureCovMatrix.GetMatrixArray(),0.1)/0.02;
    #ifdef _SPECTRA_FITTER_DEBUG_
      cout << "  Compare Temp Value: " << temperatureFunction->Eval(rapidity) << "  vs integral: " << TempValue << " +/- " << TempValueErr << endl;
    #endif
    TempValue = temperatureFunction->Eval(rapidity);

    TCanvas* fittingCanvas = new TCanvas("fittingCanvas","Fitting Canvas Spectra",1300,1000);
    fittingCanvas->Draw();
    TPad* topPad    = new TPad("topPad_btofEff","topPad_btofEff",0.0,0.3,1.0,1.0);
    TPad* bottomPad = new TPad("bottomPad_btofEff","bottomPad_btofEff",0.0,0.0,1.0,0.3);
    topPad->Draw();
    bottomPad->Draw();
    topPad->cd();
    TPaveText *fitParsTxt = new TPaveText(0.65,0.15,0.95,0.85,"NDC");

    vector<double> simpleParams;
    vector<double> simpleParamErrs;
    vector<string> simpleParamNames;
    string functionName = "";
    double dNdy    = finalParams[yIndexIndex];
    double dNdyErr = m_minimizer->CovMatrix(yIndexIndex,yIndexIndex);
    double dNdy_lowExtrap_fit = 0.0;
    double dNdy_lowExtrap_fit_error = 0.0;
    double lowestMtM0 = m_currentSpectra->GetX()[0] - m_currentSpectra->GetEX()[0];

    if(a_isNominal){
      double BetaSParameters[4] = {finalParams[numSpectraToFit+4],finalParams[numSpectraToFit+5],finalParams[numSpectraToFit+6],finalParams[numSpectraToFit+7]};
      betaSFunction->SetParameters(BetaSParameters[0],BetaSParameters[1],BetaSParameters[2],BetaSParameters[3]);
      #ifdef _SPECTRA_FITTER_DEBUG_
        cout << " BetaS Parameters: " << BetaSParameters[0] << " " << BetaSParameters[1] << " " << BetaSParameters[2] << " " << BetaSParameters[3] << endl;
      #endif
      double BetaSValue    = betaSFunction->Eval(rapidity - 0.01,rapidity + 0.01)/0.02; // this shouldn't be full range because it isn't an integral in the chi^2
      double BetaSValueErr = betaSFunction->IntegralError(rapidity - 0.01,rapidity + 0.01, BetaSParameters, BetaSCovMatrix.GetMatrixArray(),0.1)/0.02;
      #ifdef _SPECTRA_FITTER_DEBUG_
        cout << "  Compare BetaS Value: " << betaSFunction->Eval(rapidity) << "  vs integral: " << BetaSValue << " +/- " << BetaSValueErr << endl;
      #endif
      BetaSValue = betaSFunction->Eval(rapidity);


      vector<int> parsToKeep = {yIndexIndex,numSpectraToFit,numSpectraToFit+1,numSpectraToFit+2,numSpectraToFit+3,numSpectraToFit+4,numSpectraToFit+5,numSpectraToFit+6,numSpectraToFit+7};
      TMatrixDSym singleRapCovMatrix = PhysMath::reduceCovMatrix_keepPassedVector(covMatrix,parsToKeep);

      if(m_currentPartIndex == 0){
        TMatrixDSym singleRapCovMatrix_full = PhysMath::addZerosToCovMatrix(singleRapCovMatrix, 2); // need extra mass and rapidity variables
        double singleRapParameters[11] = {
          finalParams[parsToKeep[0]],finalParams[parsToKeep[1]],finalParams[parsToKeep[2]],finalParams[parsToKeep[3]],finalParams[parsToKeep[4]],
          finalParams[parsToKeep[5]],finalParams[parsToKeep[6]],finalParams[parsToKeep[7]],finalParams[parsToKeep[8]],particleMass,rapidity};
        for(int paramIndex = 0; paramIndex < 11; paramIndex++){
          m_tsallis_NotInvariant_WithLegendreTempAndQm1->SetParameter(paramIndex, singleRapParameters[paramIndex]);
        }
        dNdy_lowExtrap_fit    = m_tsallis_NotInvariant_WithLegendreTempAndQm1->Integral(0,lowestMtM0);
        dNdy_lowExtrap_fit_error = m_tsallis_NotInvariant_WithLegendreTempAndQm1->IntegralError(0,lowestMtM0, singleRapParameters, singleRapCovMatrix_full.GetMatrixArray(),0.1);
      }else if(m_currentPartIndex == 1){
        TMatrixDSym singleRapCovMatrix_full = PhysMath::addZerosToCovMatrix(singleRapCovMatrix, 2); // need extra mass and rapidity variables
        double singleRapParameters[11] = {
          finalParams[parsToKeep[0]],finalParams[parsToKeep[1]],finalParams[parsToKeep[2]],finalParams[parsToKeep[3]],finalParams[parsToKeep[4]],
          finalParams[parsToKeep[5]],finalParams[parsToKeep[6]],finalParams[parsToKeep[7]],finalParams[parsToKeep[8]],particleMass,rapidity};
        for(int paramIndex = 0; paramIndex < 11; paramIndex++){
          m_tsallis_NotInvariant_WithLegendreTempAndQm1->SetParameter(paramIndex, singleRapParameters[paramIndex]);
        }
        dNdy_lowExtrap_fit    = m_tsallis_NotInvariant_WithLegendreTempAndQm1->Integral(0,lowestMtM0);
        dNdy_lowExtrap_fit_error = m_tsallis_NotInvariant_WithLegendreTempAndQm1->IntegralError(0,lowestMtM0, singleRapParameters, singleRapCovMatrix_full.GetMatrixArray(),0.1);
      }else if(m_currentPartIndex == 2){
        TMatrixDSym singleRapCovMatrix_full = PhysMath::addZerosToCovMatrix(singleRapCovMatrix, 3); // need extra n m_p y variables
        double singleRapParameters[12] = {
          finalParams[parsToKeep[0]],finalParams[parsToKeep[1]],finalParams[parsToKeep[2]],finalParams[parsToKeep[3]],finalParams[parsToKeep[4]],
          finalParams[parsToKeep[5]],finalParams[parsToKeep[6]],finalParams[parsToKeep[7]],finalParams[parsToKeep[8]],1.0,particleMass,rapidity};
        for(int paramIndex = 0; paramIndex < 12; paramIndex++){
          m_blastWave_NotInvariant_WithLegendreTempAndBetaS->SetParameter(paramIndex, singleRapParameters[paramIndex]);
        }
        dNdy    = m_blastWave_NotInvariant_WithLegendreTempAndBetaS->Integral(0,6);
        dNdyErr = m_blastWave_NotInvariant_WithLegendreTempAndBetaS->IntegralError(0,6, singleRapParameters, singleRapCovMatrix_full.GetMatrixArray(),0.1);
        if(!std::isfinite(dNdyErr)){
          dNdyErr = m_blastWave_NotInvariant_WithLegendreTempAndBetaS->IntegralError(0,3.5, singleRapParameters, singleRapCovMatrix_full.GetMatrixArray(),0.1);
          if(!std::isfinite(dNdyErr)){
            dNdyErr = 99.999; // broken
          }
        }
        dNdy_lowExtrap_fit    = m_blastWave_NotInvariant_WithLegendreTempAndBetaS->Integral(0,lowestMtM0);
        dNdy_lowExtrap_fit_error = m_blastWave_NotInvariant_WithLegendreTempAndBetaS->IntegralError(0,lowestMtM0, singleRapParameters, singleRapCovMatrix_full.GetMatrixArray(),0.1);
      }

      fitParsTxt->AddText(Form("dN/dy \t %f#pm%f",dNdy,dNdyErr));
      fitParsTxt->AddText(Form("T \t %f#pm%f",TempValue,TempValueErr));
      simpleParamNames.push_back("A");
      simpleParams.push_back(finalParams[yIndexIndex]);
      simpleParamErrs.push_back(sqrt(covMatrix[yIndexIndex][yIndexIndex]));
      simpleParamNames.push_back("T");
      simpleParams.push_back(TempValue);
      simpleParamErrs.push_back(TempValueErr);
      if(m_currentPartIndex == 2) simpleParamNames.push_back("BetaS");
      else                        simpleParamNames.push_back("q_mins_one");
      simpleParams.push_back(BetaSValue);
      simpleParamErrs.push_back(BetaSValueErr);
      if(m_currentPartIndex == 2){
        fitParsTxt->AddText(Form("A \t %f#pm%f",simpleParams[0],simpleParamErrs[0]));
        fitParsTxt->AddText(Form("#beta_{S} \t %f#pm%f",BetaSValue,BetaSValueErr));
        fitParsTxt->AddText(Form("n \t %f (fixed)",1.0));
        simpleParamNames.push_back("n");
        simpleParams.push_back(1.0);
        simpleParamErrs.push_back(0.0);
        simpleParamNames.push_back("R");
        simpleParams.push_back(1.0);
        simpleParamErrs.push_back(0.0);
      }else{
        fitParsTxt->AddText(Form("q-1 \t %f#pm%f",BetaSValue,BetaSValueErr));
      }
      simpleParamNames.push_back("m_p");
      simpleParams.push_back(particleMass);
      simpleParamErrs.push_back(0.0);

      fitParsTxt->AddText(Form("m_{0} \t %f (fixed)",particleMass));
      int numSimpleParams = 4;
      if(m_currentPartIndex == 0 || m_currentPartIndex == 1){
        functionName = "Tsallis";
        invariant_fitResult = (TF1*) m_tsallis->Clone();
        invariant_fitResult->SetName(Form("NominalFit_Cent%02d_yIndex%02d",m_currentCentIndex,m_liveRapiditySpectra[yIndexIndex]));
        nonInvariant_fitResult = (TF1*) m_tsallis_NotInvariant->Clone();
        nonInvariant_fitResult->SetName(Form("NominalFit_Cent%02d_yIndex%02d_NotInvariant",m_currentCentIndex,m_liveRapiditySpectra[yIndexIndex]));
      }else if(m_currentPartIndex == 2){
        numSimpleParams = 6;
        functionName = "Blast-Wave";
        invariant_fitResult = new TF1(Form("NominalFit_Cent%02d_yIndex%02d",m_currentCentIndex,m_liveRapiditySpectra[yIndexIndex]),this,&SpectraFitter::blastWaveModelFit,0,6.0,6,"SpectraFitter","blastWaveModelFit");
        invariant_fitResult->SetParNames("A","T_kin","#beta_S","n","R","m_p");
        nonInvariant_fitResult = new TF1(Form("NominalFit_Cent%02d_yIndex%02d_NotInvariant",m_currentCentIndex,m_liveRapiditySpectra[yIndexIndex]),this,&SpectraFitter::blastWaveModelFit_NotInvariant,0,6.0,6,"SpectraFitter","blastWaveModelFit_NotInvariant");
        nonInvariant_fitResult->SetParNames("A","T_kin","#beta_S","n","R","m_p");
      }
      invariant_fitResult->SetLineColor(kViolet);
      nonInvariant_fitResult->SetLineColor(kViolet);
      for(int paramIndex = 0; paramIndex < numSimpleParams; paramIndex++){
        invariant_fitResult->SetParameter(paramIndex, simpleParams[paramIndex]);
        invariant_fitResult->SetParError(paramIndex,simpleParamErrs[paramIndex]);
        nonInvariant_fitResult->SetParameter(paramIndex, simpleParams[paramIndex]);
        nonInvariant_fitResult->SetParError(paramIndex,simpleParamErrs[paramIndex]);
      }


      if(m_currentCharge > 0){
        m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_currentRapIndex+1, dNdy);
        m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_currentRapIndex+1,dNdyErr);
        m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_currentRapIndex+1,TempValue);
        m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_currentRapIndex+1,TempValueErr);
        m_nominalFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = invariant_fitResult;
      }else{
        m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_currentRapIndex+1, dNdy);
        m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_currentRapIndex+1,dNdyErr);
        m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_currentRapIndex+1,TempValue);
        m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_currentRapIndex+1,TempValueErr);
        m_nominalFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = invariant_fitResult;
      }//is plus minus


      double dNdy_extrap_and_measured = m_dNdy_Fiducial_Measured[m_currentPartIndex][m_currentCentIndex][pmIndex]->GetBinContent(m_currentRapIndex+1) + dNdy_lowExtrap_fit;
      double dNdy_extrap_and_measured_err = PhysMath::addInQuadriture(m_dNdy_Fiducial_Measured[m_currentPartIndex][m_currentCentIndex][pmIndex]->GetBinError(m_currentRapIndex+1),dNdy_lowExtrap_fit_error);
      m_dNdy_Fiducial_And_Extrap_Nominal[m_currentPartIndex][m_currentCentIndex][pmIndex]->SetBinContent(m_currentRapIndex+1,dNdy_extrap_and_measured);
      m_dNdy_Fiducial_And_Extrap_Nominal[m_currentPartIndex][m_currentCentIndex][pmIndex]->SetBinError(m_currentRapIndex+1,dNdy_extrap_and_measured_err);


    }else{ // SYSTEMATIC  dN/dy is a varaible, so it is easy



      vector<int> parsToKeep = {yIndexIndex,numSpectraToFit,numSpectraToFit+1,numSpectraToFit+2,numSpectraToFit+3};
      TMatrixDSym singleRapCovMatrix = PhysMath::reduceCovMatrix_keepPassedVector(covMatrix,parsToKeep);

      if(m_currentPartIndex == 0){
        TMatrixDSym singleRapCovMatrix_full = PhysMath::addZerosToCovMatrix(singleRapCovMatrix, 2); // need extra mass and rapidity variables
        double singleRapParameters[7] = {
          finalParams[parsToKeep[0]],finalParams[parsToKeep[1]],finalParams[parsToKeep[2]],finalParams[parsToKeep[3]],finalParams[parsToKeep[4]],particleMass,rapidity};
        for(int paramIndex = 0; paramIndex < 7; paramIndex++){
          m_boseEinstein_NotInvariant_WithLegendreTemp->SetParameter(paramIndex, singleRapParameters[paramIndex]);
        }
        dNdy_lowExtrap_fit    = m_boseEinstein_NotInvariant_WithLegendreTemp->Integral(0,lowestMtM0);
        dNdy_lowExtrap_fit_error = m_boseEinstein_NotInvariant_WithLegendreTemp->IntegralError(0,lowestMtM0, singleRapParameters, singleRapCovMatrix_full.GetMatrixArray(),0.1);
      }else if(m_currentPartIndex == 1){
        TMatrixDSym singleRapCovMatrix_full = PhysMath::addZerosToCovMatrix(singleRapCovMatrix, 2); // need extra mass and rapidity variables
        double singleRapParameters[7] = {
          finalParams[parsToKeep[0]],finalParams[parsToKeep[1]],finalParams[parsToKeep[2]],finalParams[parsToKeep[3]],finalParams[parsToKeep[4]],particleMass,rapidity};
        for(int paramIndex = 0; paramIndex < 7; paramIndex++){
          m_mTm0Exponential_NotInvariant_WithLegendreTemp->SetParameter(paramIndex, singleRapParameters[paramIndex]);
        }
        dNdy_lowExtrap_fit    = m_mTm0Exponential_NotInvariant_WithLegendreTemp->Integral(0,lowestMtM0);
        dNdy_lowExtrap_fit_error = m_mTm0Exponential_NotInvariant_WithLegendreTemp->IntegralError(0,lowestMtM0, singleRapParameters, singleRapCovMatrix_full.GetMatrixArray(),0.1);
      }else if(m_currentPartIndex == 2){
        TMatrixDSym singleRapCovMatrix_full = PhysMath::addZerosToCovMatrix(singleRapCovMatrix, 1); // need extra rapidity variables
        double singleRapParameters[6] = {
          finalParams[parsToKeep[0]],finalParams[parsToKeep[1]],finalParams[parsToKeep[2]],finalParams[parsToKeep[3]],finalParams[parsToKeep[4]],rapidity};
        for(int paramIndex = 0; paramIndex < 6; paramIndex++){
          m_thermal_NotInvariant_WithLegendreTemp->SetParameter(paramIndex, singleRapParameters[paramIndex]);
        }
        dNdy_lowExtrap_fit    = m_thermal_NotInvariant_WithLegendreTemp->Integral(0,lowestMtM0);
        dNdy_lowExtrap_fit_error = m_thermal_NotInvariant_WithLegendreTemp->IntegralError(0,lowestMtM0, singleRapParameters, singleRapCovMatrix_full.GetMatrixArray(),0.1);
      }


      fitParsTxt->AddText(Form("dN/dy \t %f#pm%f",dNdy,dNdyErr));
      fitParsTxt->AddText(Form("T \t %f#pm%f",TempValue,TempValueErr));

      simpleParamNames.push_back("dN/dy");
      simpleParams.push_back(finalParams[yIndexIndex]);
      simpleParamErrs.push_back(sqrt(covMatrix[yIndexIndex][yIndexIndex]));
      simpleParamNames.push_back("T");
      simpleParams.push_back(TempValue);
      simpleParamErrs.push_back(TempValueErr);
      if(m_currentPartIndex != 1){
        fitParsTxt->AddText(Form("m_{p} \t %f (fixed)",particleMass));
        simpleParamNames.push_back("m_p");
        simpleParams.push_back(particleMass);
        simpleParamErrs.push_back(0.0);
      }

      int numSimpleParams = 3;
      if(m_currentPartIndex == 0){
        functionName = "Bose-Einstein";
        invariant_fitResult = (TF1*) m_boseEinstein->Clone();
        invariant_fitResult->SetName(Form("SystematicFit_Cent%02d_yIndex%02d",m_currentCentIndex,m_liveRapiditySpectra[yIndexIndex]));
        nonInvariant_fitResult = (TF1*) m_boseEinstein_NotInvariant->Clone();
        nonInvariant_fitResult->SetName(Form("SystematicFit_Cent%02d_yIndex%02d_NotInvariant",m_currentCentIndex,m_liveRapiditySpectra[yIndexIndex]));
      }else if(m_currentPartIndex == 1){
        numSimpleParams = 2;
        functionName = "mTm0Exponential";
        invariant_fitResult = (TF1*) m_mTm0Exponential->Clone();
        invariant_fitResult->SetName(Form("SystematicFit_Cent%02d_yIndex%02d",m_currentCentIndex,m_liveRapiditySpectra[yIndexIndex]));
        nonInvariant_fitResult = (TF1*) m_mTm0Exponential_NotInvariant->Clone();
        nonInvariant_fitResult->SetName(Form("SystematicFit_Cent%02d_yIndex%02d_NotInvariant",m_currentCentIndex,m_liveRapiditySpectra[yIndexIndex]));
      }else if(m_currentPartIndex == 2){
        functionName = "Thermal";
        invariant_fitResult = (TF1*) m_thermal->Clone();
        invariant_fitResult->SetName(Form("SystematicFit_Cent%02d_yIndex%02d",m_currentCentIndex,m_liveRapiditySpectra[yIndexIndex]));
        nonInvariant_fitResult = (TF1*) m_thermal_NotInvariant->Clone();
        nonInvariant_fitResult->SetName(Form("SystematicFit_Cent%02d_yIndex%02d_NotInvariant",m_currentCentIndex,m_liveRapiditySpectra[yIndexIndex]));
      }
      invariant_fitResult->SetLineColor(kViolet);
      nonInvariant_fitResult->SetLineColor(kViolet);
      for(int paramIndex = 0; paramIndex < numSimpleParams; paramIndex++){
        invariant_fitResult->SetParameter(paramIndex, simpleParams[paramIndex]);
        invariant_fitResult->SetParError(paramIndex,simpleParamErrs[paramIndex]);
        nonInvariant_fitResult->SetParameter(paramIndex, simpleParams[paramIndex]);
        nonInvariant_fitResult->SetParError(paramIndex,simpleParamErrs[paramIndex]);
      }
      if(m_currentCharge > 0){
        m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_currentRapIndex+1,dNdy);
        m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(  m_currentRapIndex+1,dNdyErr);
        m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_currentRapIndex+1,TempValue);
        m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(  m_currentRapIndex+1,TempValueErr);
        m_systematicFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = invariant_fitResult;
      }else{
        m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_currentRapIndex+1,dNdy);
        m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(  m_currentRapIndex+1,dNdyErr);
        m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_currentRapIndex+1,TempValue);
        m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(  m_currentRapIndex+1,TempValueErr);
        m_systematicFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = invariant_fitResult;
      }//is plus minus

      double dNdy_extrap_and_measured = m_dNdy_Fiducial_Measured[m_currentPartIndex][m_currentCentIndex][pmIndex]->GetBinContent(m_currentRapIndex+1) + dNdy_lowExtrap_fit;
      double dNdy_extrap_and_measured_err = PhysMath::addInQuadriture(m_dNdy_Fiducial_Measured[m_currentPartIndex][m_currentCentIndex][pmIndex]->GetBinError(m_currentRapIndex+1),dNdy_lowExtrap_fit_error);
      m_dNdy_Fiducial_And_Extrap_Systematic[m_currentPartIndex][m_currentCentIndex][pmIndex]->SetBinContent(m_currentRapIndex+1,dNdy_extrap_and_measured);
      m_dNdy_Fiducial_And_Extrap_Systematic[m_currentPartIndex][m_currentCentIndex][pmIndex]->SetBinError(m_currentRapIndex+1,dNdy_extrap_and_measured_err);

    }// end if nominal/systematic

    invariant_fitResult->SetRange(m_currentLowFitRange,m_currentHighFitRange);
    nonInvariant_fitResult->SetRange(m_currentLowFitRange,m_currentHighFitRange);


    #ifdef _SPECTRA_FITTER_DEBUG_
      cout << "Simple Parameters for yIndex " << m_currentRapIndex << " y= " << rapidity << " : " << endl;
    #endif

    for(int paramIndex = 0; paramIndex < invariant_fitResult->GetNpar(); paramIndex++){
      //Fill the parameter result histograms
      TH1D* paramHistoToModify = NULL;
      if(m_currentCharge > 0){
        if(a_isNominal){
          paramHistoToModify = m_Simultaneous_Nominal_Fit_Params_Plus[m_currentPartIndex][m_currentCentIndex][paramIndex];
        }else{
          paramHistoToModify = m_Simultaneous_Systematic_Fit_Params_Plus[m_currentPartIndex][m_currentCentIndex][paramIndex];
        }
      }else{
        if(a_isNominal){
          paramHistoToModify = m_Simultaneous_Nominal_Fit_Params_Minus[m_currentPartIndex][m_currentCentIndex][paramIndex];
        }else{
          paramHistoToModify = m_Simultaneous_Systematic_Fit_Params_Minus[m_currentPartIndex][m_currentCentIndex][paramIndex];
        }
      }

      if(HistogramUtilities::isEmpty(paramHistoToModify)){
        string original_name = paramHistoToModify->GetName();
        paramHistoToModify->SetName(Form("%s_%s",original_name.c_str(),invariant_fitResult->GetParName(paramIndex)));
        paramHistoToModify->SetTitle(Form("%s Cent %d %s %s Param: %s;y;%s",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,a_isNominal ? "Nominal" : "Systematic" ,functionName.c_str(),invariant_fitResult->GetParName(paramIndex),invariant_fitResult->GetParName(paramIndex)));
      }
      paramHistoToModify->SetBinContent(m_currentRapIndex+1,invariant_fitResult->GetParameter(paramIndex));
      paramHistoToModify->SetBinError(  m_currentRapIndex+1,  invariant_fitResult->GetParError(paramIndex));

      #ifdef _SPECTRA_FITTER_DEBUG_
        cout << "      " << invariant_fitResult->GetParName(paramIndex) << " = " << invariant_fitResult->GetParameter(paramIndex) << " +/- " << invariant_fitResult->GetParError(paramIndex) << endl;
      #endif

    }

    //####    DRAW THE INDIVIDUAL FIT FOR SANITY   ######


    TGraphAsymmErrors* pullGraph = HistogramUtilities::makeFitPullGraph(m_currentSpectra, invariant_fitResult, false);// last param is do integral
    pullGraph->SetMarkerStyle(20);
    pullGraph->SetMarkerSize(0.5);
    pullGraph->SetMarkerColor(kBlack);
    pullGraph->SetLineColor(kBlack);



    //gStyle->SetOptStat(1000000001); // just name of histogram
    //gStyle->SetOptTitle(1); // print name of histogram

    double lowYRange = 0;
    double highYRange = 0;
    HistogramUtilities::verticalDrawRange(m_currentSpectra,lowYRange,highYRange,0.0,10.0,true);
    #ifdef _SPECTRA_FITTER_DEBUG_
       cout << " Setting Plotting Ranges to : " << 0.0 << " , " << lowYRange << " , " << m_currentSpectra->GetX()[m_currentSpectra->GetN()-1]+0.05 << " , " << highYRange << endl;
    #endif
    TH1F *frame3 = gPad->DrawFrame(0.0,lowYRange,m_currentSpectra->GetX()[m_currentSpectra->GetN()-1]+m_currentSpectra->GetEX()[m_currentSpectra->GetN()-1]+0.05,highYRange);
    frame3->SetTitle(Form("%s %s Cent %1.2f-%1.2f%% y=[%1.2f,%1.2f]; m_{T}-m_{p} (GeV/c^{2}); #frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}",
          m_currentCharge > 0 ? "p":"#bar{p}",
          functionName.c_str(),
          m_cuts->getLowCentPercent(m_currentCentIndex),
          m_cuts->getHighCentPercent(m_currentCentIndex),
          m_cuts->getRapMtM0BinStructure(m_currentPartIndex,1)->GetBinLowEdge(m_currentRapIndex+1),
          m_cuts->getRapMtM0BinStructure(m_currentPartIndex,1)->GetBinLowEdge(m_currentRapIndex+2)
          ));
    gPad->SetLogy(true);
    m_currentSpectra->Draw("PSame");
    invariant_fitResult->Draw("same");
    fitParsTxt->Draw("same");

    ///############   DRAW THE PULL GRAPH  ###############
    bottomPad->cd();
    gStyle->SetOptStat(0);
    gStyle->SetOptTitle(0);
    gPad->SetLogy(false);
    double lowPullRange = -5.0;
    double highPullRange = 5.0;
    HistogramUtilities::verticalDrawRange(pullGraph,lowPullRange,highPullRange,0.0,10.0,false);
    TH1F *frame_pull = gPad->DrawFrame(0.0,lowPullRange,m_currentSpectra->GetX()[m_currentSpectra->GetN()-1] + m_currentSpectra->GetEX()[m_currentSpectra->GetN()-1]+0.05,highPullRange);
    frame_pull->SetTitle(Form("; m_{T}-m_{0} (GeV/c^{2}); Std. Pull"));
    pullGraph->Draw("PSame");
    TLine* oneLine = new TLine(0.0,0.0,m_currentSpectra->GetX()[m_currentSpectra->GetN()-1] + m_currentSpectra->GetEX()[m_currentSpectra->GetN()-1] + 0.05,0.0);
    oneLine->SetLineStyle(7);
    oneLine->SetLineColor(kBlack);
    oneLine->Draw("same");

    fittingCanvas->Update();
    gSystem->ProcessEvents();

    fittingCanvas->SaveAs(Form("%s/%s/SimultaneousFit_%s_Cent%02d_yIndex%02d_%s.png",m_imageDir.c_str(),
      m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),a_isNominal ? "Nom" : "Sys",m_currentCentIndex,m_currentRapIndex,functionName.c_str()));

  }//  end rapidity index index loop (yIndexIndex)

} // end of proton fitting function








//############################################################################################################################################################
//###########################################################################################################################################################




void SpectraFitter::fitProtonSpectra(int a_centIndex, int a_charge, bool a_constrainBetaS, int a_numTrialsForDnDyBootstrap, double a_lowRapBound_BetaS_Constraint, double a_highRapBound_BetaS_Constraint){
  cout << "#####################  Starting SpectraFitter::fitProtonSpectra() ########################" << endl;
  TVirtualFitter::SetMaxIterations( 1000000 );
  m_currentPartIndex = 2;
  bool useAvgParamsForSeparateFits = true;

  TCanvas* fittingCanvas = new TCanvas("fittingCanvas_Proton","Fitting Canvas");
  fittingCanvas->SetWindowSize(1300,700);
  fittingCanvas->SetCanvasSize(1200,600);
  double protonMass = m_partInfo->GetParticleMass(m_currentPartIndex);

  //#########################    CENTRALITY LOOP  ###########################
  for(unsigned int centIndex = 0; centIndex < 16; centIndex++){
    if(a_centIndex != centIndex) continue;
    m_currentCentIndex = centIndex;
    for(int pmIndex = 0; pmIndex < 2; pmIndex++){
      m_currentCharge = 1;
      if(pmIndex == 1) m_currentCharge = -1;
      if(a_charge != m_currentCharge) continue;
      m_liveRapidityProtonSpectra.clear();
      double ampWeight = 0.0;
      double avgAmpFirst = 0.0;
      double tempWeight = 0.0;
      double avgTempFirst = 0.0;
      double avgBetaSFirst = 0.0;
      double betaSWeight = 0.0;
      vector< double > ampStorage;
      vector< double > tempStorage;
      vector< double > betaSStorage;

      double ampWeight_sys = 0.0;
      double avgAmpFirst_sys = 0.0;
      double tempWeight_sys = 0.0;
      double avgTempFirst_sys = 0.0;
      vector< double > ampStorage_sys;
      vector< double > tempStorage_sys;

      //Fit with single blastwaves first
      m_protonFittingStage = 1;
      m_isTemperatureConstrained = false;
      int counter = 0;
      for(unsigned int yIndex = 0; yIndex < m_cuts->getRapMtM0BinStructure(m_currentPartIndex, 1)->GetNbinsX(); yIndex++){
        m_currentRapValue = m_cuts->getRapMtM0BinStructure(m_currentPartIndex, 1)->GetBinCenter(yIndex+1);
        m_currentRapIndex = yIndex;
        TGraphErrors* specPM[2];
        specPM[0] = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][yIndex];
        specPM[1] = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][yIndex];
        if( !specPM[pmIndex] || specPM[pmIndex]->GetN() <= 4 ) continue; //############################################   MUST BE SAME AS ABOVE! ###################################
        m_liveRapidityProtonSpectra.push_back(yIndex);
        m_liveRapidityValueProtonSpectra.push_back(m_currentRapValue);
        cout << "Proton Fitting: Cent " << m_currentCentIndex << " yIndex " << yIndex
             << " charge: " << m_currentCharge << " ptr: " << specPM[pmIndex] << " charge: " << m_currentCharge
             << " N: " << specPM[pmIndex]->GetN() <<  endl;

        //##########  FIT WITH NOMINAL FIT FUNCTION ##########
        m_isCurrentFitNominal = true;
        m_currentSpectra = (TGraphErrors*) specPM[pmIndex]->Clone();
        init_blastWave();
        init_thermal();

        //cout << " Fixing Beta_S to 0.4 for initial fit..." << endl;
        //m_blastWave->FixParameter(2,0.4);
        m_blastWave->SetParameter(2,0.6);

        TF1* initial_BW_fit = new TF1(
          Form("InitFit_%s_Cent%02d_yIndex%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_currentRapIndex),
          this,&SpectraFitter::blastWaveModelFit,0,10,6,"SpectraFitter","blastWaveModelFit");
        initial_BW_fit->SetParNames("A","T_kin","#beta_S","W","R","m_p");
        initial_BW_fit->SetParameter(0,m_blastWave->GetParameter(0));
        initial_BW_fit->SetParameter(1,m_blastWave->GetParameter(1));
        initial_BW_fit->SetParameter(2,m_blastWave->GetParameter(2));
        initial_BW_fit->FixParameter(3,m_blastWave->GetParameter(3));
        initial_BW_fit->FixParameter(4,m_blastWave->GetParameter(4));
        initial_BW_fit->SetParameter(5,m_blastWave->GetParameter(5));


        initial_BW_fit->SetLineColor(kYellow);
        int status = m_currentSpectra->Fit("m_blastWave","EV EX0","",0,10);
        TF1* fitResult = m_currentSpectra->GetFunction("m_blastWave");

        if(fitResult){
          ampWeight += 1.0 / (fitResult->GetParError(0)*fitResult->GetParError(0));
          avgAmpFirst += 1.0 / (fitResult->GetParError(0)*fitResult->GetParError(0)) * fitResult->GetParameter(0);
          tempWeight += 1.0 / (fitResult->GetParError(1)*fitResult->GetParError(1));
          avgTempFirst += 1.0 / (fitResult->GetParError(1)*fitResult->GetParError(1)) * fitResult->GetParameter(1);
          betaSWeight += 1.0 / (fitResult->GetParError(2)*fitResult->GetParError(2));
          avgBetaSFirst += 1.0 / (fitResult->GetParError(2)*fitResult->GetParError(2)) * fitResult->GetParameter(2);

          ampStorage.push_back(fitResult->GetParameter(0));
          tempStorage.push_back(fitResult->GetParameter(1));
          betaSStorage.push_back(fitResult->GetParameter(2));

        }else{
          ampStorage.push_back(-1);
          tempStorage.push_back(-1);
          betaSStorage.push_back(-1);
        }

        //make the fit image
        fittingCanvas->cd();
        double smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
        double largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
        if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
        frame->SetTitle(Form("p^{%s} Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
                    m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
                    m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
        //frame->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
        //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame->GetXaxis()->SetTitle("m_{T}-m_{p} (GeV/c^{2})");
        frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);
        initial_BW_fit->Draw("same");
        m_currentSpectra->Draw("P");
        fittingCanvas->Update();
        fittingCanvas->SaveAs(Form("%s/%s/FirstFit_Nom_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));
        //delete m_currentSpectra;
        //delete initial_BW_fit;


        fittingCanvas->Clear();


        TF1* initial_thermal_fit = new TF1(
          Form("InitFit_Sys_%s_Cent%02d_yIndex%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_currentRapIndex),
          "[0] * (x+[2]) * exp(-x/[1]) / ((2*3.14159265) * [1] * ([2]*[2] + 2*[2]*[1] + 2*[1]*[1]))",0,10);
        initial_thermal_fit->SetParNames("dN/dy","T","m");
        initial_thermal_fit->SetParameter(0,m_blastWave->GetParameter(0));
        initial_thermal_fit->SetParameter(1,m_blastWave->GetParameter(1));
        initial_thermal_fit->FixParameter(2,m_partInfo->GetParticleMass(m_currentPartIndex));


        initial_thermal_fit->SetLineColor(kYellow);
        int status_sys = m_currentSpectra->Fit("m_thermal","EV EX0","",0,10);
        TF1* fitResult_sys = m_currentSpectra->GetFunction("m_thermal");


        if(fitResult_sys){
          ampWeight_sys += 1.0 / (fitResult_sys->GetParError(0)*fitResult_sys->GetParError(0));
          avgAmpFirst_sys += 1.0 / (fitResult_sys->GetParError(0)*fitResult_sys->GetParError(0)) * fitResult_sys->GetParameter(0);
          tempWeight_sys += 1.0 / (fitResult_sys->GetParError(1)*fitResult_sys->GetParError(1));
          avgTempFirst_sys += 1.0 / (fitResult_sys->GetParError(1)*fitResult_sys->GetParError(1)) * fitResult_sys->GetParameter(1);

          ampStorage_sys.push_back(fitResult_sys->GetParameter(0));
          tempStorage_sys.push_back(fitResult_sys->GetParameter(1));

        }else{
          ampStorage_sys.push_back(-1);
          tempStorage_sys.push_back(-1);
        }

        //double smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
        //double largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
        //if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame_sys = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
        frame_sys->SetTitle(Form("p^{%s} Systematic Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
                    m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
                    m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
        //frame->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
        //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame_sys->GetXaxis()->SetTitle("m_{T}-m_{p} (GeV/c^{2})");
        frame_sys->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);
        initial_thermal_fit->Draw("same");
        //m_currentSpectra->GetFunction("m_blastWave")->SetBit(TF1::kNotDraw);
        m_currentSpectra->Draw("P");
        fittingCanvas->Update();
        fittingCanvas->SaveAs(Form("%s/%s/FirstFit_Sys_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));


        if(!fitResult) cout << "No Fit Result: yindex: " << yIndex << endl;
        if(!fitResult_sys) cout << "No Fit Result Sys: yindex: " << yIndex << endl;
        counter+=2;
      }

      avgAmpFirst = avgAmpFirst/ampWeight;
      avgTempFirst = avgTempFirst/tempWeight;
      avgBetaSFirst = avgBetaSFirst/betaSWeight;

      if(std::isnan(avgBetaSFirst)) avgBetaSFirst = 0.5;

      cout << " AvgAmp: " << avgAmpFirst << "  AvgTemp: " << avgTempFirst << "  AvgBetsS: " << avgBetaSFirst << endl;

      avgAmpFirst_sys = avgAmpFirst_sys/ampWeight_sys;
      avgTempFirst_sys = avgTempFirst_sys/tempWeight_sys;

      TGraph *temp_init_sys = new TGraph(m_liveRapidityValueProtonSpectra.size(),&m_liveRapidityValueProtonSpectra[0],&tempStorage_sys[0]);
      temp_init_sys->SetTitle("Temp Systematic Initial Values");
      temp_init_sys->GetXaxis()->SetTitle("y_{lab}");
      temp_init_sys->GetYaxis()->SetTitle("Temp (GeV)");
      temp_init_sys->SetMarkerStyle(20);

      TF1 *temp_fitInit_sys = new TF1("temp_fitInit_sys","[0]/TMath::CosH([2]*(x-[1]))",-2,2);
      temp_fitInit_sys->SetParameters(0.1,m_cuts->getYCM(),1.0);
      temp_fitInit_sys->FixParameter(1,m_cuts->getYCM());
      temp_fitInit_sys->SetParLimits(0,0.01,0.3);

      temp_init_sys->Fit(temp_fitInit_sys);
      temp_init_sys->Draw("AP");
      temp_fitInit_sys->Draw("Same");

      TCanvas *fitParsCanvas = new TCanvas("fitParsCanvas","Fit Parameters Canvas");
      fitParsCanvas->SetWindowSize(1300,700);
      fitParsCanvas->SetCanvasSize(1200,600);

      fitParsCanvas->SaveAs(Form("%s/%s/tempInit_Sys_Cent%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));

      fitParsCanvas->Clear();

      //setup minimizer
      int numSpectraToFit = (int) m_liveRapidityProtonSpectra.size();
      //systematic fitting
      m_minimizer_sys = ROOT::Math::Factory::CreateMinimizer();
      m_chiSqrdFunctor_sys = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_thermal_ChiSqr,(numSpectraToFit) + 3);
      cout << "created chi squared sys functor with NDim " << m_chiSqrdFunctor_sys->NDim() << "  functor: " << &SpectraFitter::simultaneous_thermal_ChiSqr  << endl;
      m_minimizer_sys->SetFunction(*m_chiSqrdFunctor_sys);
      for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size(); iii++){
        if(useAvgParamsForSeparateFits){
          m_minimizer_sys->SetVariable(iii, Form("dNdy_sys_%02d",m_liveRapidityProtonSpectra[iii]), avgAmpFirst_sys , 0.1*avgAmpFirst_sys);
          m_minimizer_sys->SetVariableLimits(iii, 0.0, avgAmpFirst_sys*10000.0);
        }else{
          m_minimizer_sys->SetVariable(iii, Form("dNdy_sys_%02d",m_liveRapidityProtonSpectra[iii]), ampStorage_sys[iii] , 0.1*ampStorage_sys[iii]);
          m_minimizer_sys->SetVariableLimits(iii, 0.0, ampStorage_sys[iii]*10000.0);
        }
      }

      m_minimizer_sys->SetVariable(counter/2, "Amp_T_sys" ,temp_fitInit_sys->GetParameter(0), 0.01);
      m_minimizer_sys->SetVariableLimits(counter/2,0.0001, 0.3);
      m_minimizer_sys->SetVariable(counter/2+1, "Mu_T_sys" ,m_cuts->getYCM(), 0.2);
      m_minimizer_sys->FixVariable(counter/2+1);
      m_minimizer_sys->SetVariable(counter/2+2, "Sigma_T_sys" ,temp_fitInit_sys->GetParameter(2), 2.0);
      m_minimizer_sys->SetVariableLimits(counter/2+2,0.0, 2.0);




      cout << "######################################################################" << endl;
      cout << "          STAGE 2   Proton Sys Fitting - Use Separate Rap Fit Results as Seeds to Simultaneous Fitter" << endl;
      //m_blastWave->SetParLimits(2,0.0,1.0);
      m_protonFittingStage = 2;
      //init_simul_blastWave();  //only do this if not initialized by single fits above
      m_minimizer_sys->SetPrintLevel(5);
      m_minimizer_sys->SetMaxIterations(3000);
      m_minimizer_sys->SetMaxFunctionCalls(200000);
      m_minimizer_sys->SetValidError(true);
      m_minimizer_sys->Minimize();
      int status_sys = m_minimizer_sys->Status();
      const double* finalParams_sys = m_minimizer_sys->X();
      if(status_sys == 0){
        cout << "Proton Sys Fit Status: " << status_sys << endl;
      }
      else{
        cout << "################################  First Pass Fit:  STATUS OF SYS FIT = " << status_sys << "   IS BAD!!!!!  ################################" << endl;
        cout << "Current Parameters: " << endl;
        for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size() + 3; iii++){
          cout << "  " << finalParams_sys[iii];
        }
        cout << endl;
        continue;
      }

      vector< double > uncert_sys;
      for(int iii=0; iii < (int) m_liveRapidityProtonSpectra.size() + 3; iii++){
        uncert_sys.push_back(sqrt(m_minimizer_sys->CovMatrix(iii,iii)));
      }


            cout << "######################################################################" << endl;
      cout << "          STAGE 3   Proton Fitting Sys - Bootstrap Individual Amplitudes" << endl;


      for(int iii = 0; iii < m_liveRapidityProtonSpectra.size(); iii++){

        double rapidity = m_liveRapidityValueProtonSpectra[iii];


        double dNdy_sys = finalParams_sys[iii];
        double dNdy_err_sys = sqrt( m_minimizer_sys->CovMatrix(iii,iii) );

        double temp_sys = finalParams_sys[m_liveRapidityProtonSpectra.size()]/TMath::CosH(finalParams_sys[m_liveRapidityProtonSpectra.size() + 2]*(rapidity - finalParams_sys[m_liveRapidityProtonSpectra.size()+1]));

        double tempErr_sys = sqrt( pow(temp_sys*uncert_sys[m_liveRapidityProtonSpectra.size()]/finalParams_sys[m_liveRapidityProtonSpectra.size()],2) + pow(temp_sys*uncert_sys[m_liveRapidityProtonSpectra.size()+2]*TMath::TanH(finalParams_sys[m_liveRapidityProtonSpectra.size()+2]*(rapidity - finalParams_sys[m_liveRapidityProtonSpectra.size()+1]))*(rapidity - finalParams_sys[m_liveRapidityProtonSpectra.size()+1]),2) );

        TF1* fitFunct_sys = new TF1(
          Form("SystematicFit_Cent%02d_yIndex%02d",m_currentCentIndex,m_liveRapidityProtonSpectra[iii]),
          "[0] * (x+[2]) * exp(-x/[1]) / ((2*3.14159265) * [1] * ([2]*[2] + 2*[2]*[1] + 2*[1]*[1]))",0.0,10.0);
        fitFunct_sys->SetParNames("dN/dy","T","m");
        fitFunct_sys->SetParameter(0,dNdy_sys);
        fitFunct_sys->SetParError(0,dNdy_err_sys);
        fitFunct_sys->SetParameter(1,temp_sys);
        fitFunct_sys->SetParError(1,tempErr_sys);
        fitFunct_sys->FixParameter(2,m_partInfo->GetParticleMass(m_currentPartIndex));

        TGraphErrors* spectrum = NULL;
        if(m_currentCharge == 1) spectrum = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]];
        else spectrum = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]];



        TCanvas *finalCanvas = new TCanvas("finalCanvas","Final Canvas");
        finalCanvas->SetWindowSize(1300,700);
        finalCanvas->SetCanvasSize(1200,600);

        finalCanvas->cd();

        double smallYVal =  HistogramUtilities::findSmallestYVal(spectrum)*0.25;
        double largeXVal =  HistogramUtilities::findLargestXVal(spectrum)*1.3;
        if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame_sys = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(spectrum)*4.0);
        frame_sys->SetTitle(Form("p^{%s} Systematic Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
          m_cuts->getRapidityRangeLow(m_liveRapidityProtonSpectra[iii],m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(m_liveRapidityProtonSpectra[iii],m_currentPartIndex,1),
          m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
          //frame->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
          //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame_sys->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
        frame_sys->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);

        spectrum->SetMarkerStyle(20);
        spectrum->Draw("P");
        fitFunct_sys->Draw("same");

        TPaveText *fitParsTxt_sys = new TPaveText(0.65,0.15,0.95,0.85,"NDC");
        fitParsTxt_sys->AddText(Form("dN/dy \t %f#pm%f",dNdy_sys,dNdy_err_sys));
        fitParsTxt_sys->AddText(Form("T \t %f#pm%f",temp_sys,tempErr_sys));
        fitParsTxt_sys->AddText(Form("m \t %f",m_partInfo->GetParticleMass(m_currentPartIndex)));

        fitParsTxt_sys->SetFillStyle(0);
        fitParsTxt_sys->SetBorderSize(5);

        fitParsTxt_sys->Draw("same");

        finalCanvas->Update();
        finalCanvas->SaveAs(Form("%s/%s/FinalFit_Sys_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
          m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_liveRapidityProtonSpectra[iii]));



        if(m_currentCharge == 1){

          m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdy_sys);
          m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdy_err_sys);

          m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,temp_sys);
          m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,tempErr_sys);

          m_systematicFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct_sys;

        }else{

          m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdy_sys);
          m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdy_err_sys);

          m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,temp_sys);
          m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,tempErr_sys);

          m_systematicFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct_sys;
        }//is plus minus

      }//rap loop



      //nominal fitting
      m_minimizer = ROOT::Math::Factory::CreateMinimizer();
      m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_blastWave_ChiSqr,(2*numSpectraToFit) + 1);
      cout << "created chi squared functor with NDim " << m_chiSqrdFunctor->NDim() << "  functor: " << &SpectraFitter::simultaneous_blastWave_ChiSqr  << endl;
      m_minimizer->SetFunction(*m_chiSqrdFunctor);
      for(int iii = 0; iii < (int) 2*m_liveRapidityProtonSpectra.size(); iii+=2){
        if(useAvgParamsForSeparateFits){
          m_minimizer->SetVariable(iii, Form("A_%02d",m_liveRapidityProtonSpectra[iii/2]), avgAmpFirst , 0.1*avgAmpFirst);
          m_minimizer->SetVariableLimits(iii, 0.0, avgAmpFirst*10000.0);
          m_minimizer->SetVariable(iii+1, Form("Beta_S_%02d", m_liveRapidityProtonSpectra[iii/2]), avgBetaSFirst, 0.3);
          m_minimizer->SetVariableLimits(iii+1, 0.0, 1.0);
        }else{
          m_minimizer->SetVariable(iii, Form("A_%02d",m_liveRapidityProtonSpectra[iii/2]), ampStorage[iii/2] , 0.1*ampStorage[iii/2]);
          m_minimizer->SetVariableLimits(iii, 0.0, ampStorage[iii/2]*10000.0);
          m_minimizer->SetVariable(iii+1, Form("Beta_S_%02d", m_liveRapidityProtonSpectra[iii/2]), betaSStorage[iii/2], 0.1);
          m_minimizer->SetVariableLimits(iii+1, 0.0, 1.0);
        }
      }

      m_minimizer->SetVariable(counter, "T" ,avgTempFirst, 0.15);
      m_minimizer->SetVariableLimits(counter,0.0, 2.0);








      cout << "######################################################################" << endl;
      cout << "          STAGE 2   Proton Fitting - Use Separate Rap Fit Results as Seeds to Simultaneous Fitter" << endl;
      m_blastWave->SetParLimits(2,0.0,1.0);
      m_protonFittingStage = 2;
      //init_simul_blastWave();  //only do this if not initialized by single fits above
      m_minimizer->SetPrintLevel(5);
      m_minimizer->SetMaxIterations(3000);
      m_minimizer->SetMaxFunctionCalls(200000);
      m_minimizer->SetValidError(true);
      m_minimizer->Minimize();
      int status = m_minimizer->Status();
      const double* finalParams_RoundOne = m_minimizer->X();
      if(status == 0){
        cout << "Proton Fit Status: " << status << endl;
      }
      else{
        cout << "################################  First Pass Fit:  STATUS OF FIT = " << status << "   IS BAD!!!!!  ################################" << endl;
        cout << "Current Parameters: " << endl;
        for(int iii = 0; iii < (int) 2*m_liveRapidityProtonSpectra.size() + 1; iii++){
          cout << "  " << finalParams_RoundOne[iii];
        }
        cout << endl;
        continue;
      }



      if(a_constrainBetaS){
        double tempFinal = finalParams_RoundOne[2*m_liveRapidityProtonSpectra.size()];
        double tempFinalErr = sqrt( m_minimizer->CovMatrix(2*m_liveRapidityProtonSpectra.size(),2*m_liveRapidityProtonSpectra.size()) );
        cout << " ptrs: " << m_Proton_Temp_Plus_Nom << "   " << m_Proton_Temp_Minus_Nom << endl;
        if(!std::isnan(tempFinal) && !std::isnan(tempFinalErr)){
          if(m_currentCharge == 1){
            m_Proton_Temp_Plus_Nom->SetBinContent(m_currentCentIndex+1,tempFinal);
            m_Proton_Temp_Plus_Nom->SetBinError(m_currentCentIndex+1,tempFinalErr);
          }else{
            m_Proton_Temp_Minus_Nom->SetBinContent(m_currentCentIndex+1,tempFinal);
            m_Proton_Temp_Minus_Nom->SetBinError(m_currentCentIndex+1,tempFinalErr);
          }
        }

        cout << "Final Temperature: " << tempFinal << endl;
        //cout << "Final Beta_S: " << betaSFinal << endl;

        for(int iii = 0; iii < m_liveRapidityProtonSpectra.size(); iii++){
          double Amp = finalParams_RoundOne[2*iii];
          double AmpErr = sqrt( m_minimizer->CovMatrix(2*iii,2*iii) );
          //double rapidity = currentBetaSHisto->GetBinCenter(m_liveRapidityProtonSpectra[iii]+1);
          double betaSNow = finalParams_RoundOne[2*iii+1];
          cout << "Ready for bootstraper: Amp: " << Amp << " AmpErr: " << AmpErr <<  " BetaS: " << betaSNow << " Temp: " << tempFinal << endl;
          TF1* fitFunct = new TF1(
            Form("NominalFit_Cent%02d_yIndex%02d",m_currentCentIndex,m_liveRapidityProtonSpectra[iii]),
            this,&SpectraFitter::blastWaveModelFit,0,10,6,"SpectraFitter","blastWaveModelFit");
          fitFunct->SetParNames("A","T_kin","#beta_S","W","R","m_p");
          fitFunct->SetParameter(0,Amp);
          fitFunct->SetParameter(1,tempFinal);
          fitFunct->SetParameter(2,betaSNow);
          fitFunct->FixParameter(3,0.5);
          fitFunct->FixParameter(4,1.0);
          fitFunct->SetParameter(5,m_partInfo->GetParticleMass(2));


          double dNdy = 0;
          double dNdyAvg = 0;
          double dNdyErr = 0;
          //double &a_integral, double &a_avgIntegral, double &a_integralError,TF1* a_fitFunction, TFitResult* a_fitResult, double a_mass, int a_parameterToVary,int a_numTrials, double a_paramError,double a_lowIntegralBound, double a_highIntegralBound
          vector< double > integralListNom = FitUtilities::bootstrapIntegralSingleParameter(dNdy,dNdyAvg, dNdyErr, fitFunct, NULL, protonMass,0, a_numTrialsForDnDyBootstrap, AmpErr);
          double smallest = *min_element(integralListNom.begin(), integralListNom.end());
          double biggest = *max_element(integralListNom.begin(), integralListNom.end());
          TH1D* integralHistoryHisto_Nom = new TH1D("paramHisto","Sampled Integrals; Integral Value;Counts",100,0.98*smallest, 1.02*biggest);
          for(int iii = 0; iii < (int) integralListNom.size(); iii++) integralHistoryHisto_Nom->Fill(integralListNom[iii]);
          integralHistoryHisto_Nom->SetName(Form("dNdy_Nom_History_%s_Cent%02d_Rap%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_liveRapidityProtonSpectra[iii]));
          HistogramUtilities::makeSqrtNErrors(integralHistoryHisto_Nom);
          m_gausFunct->SetRange(integralHistoryHisto_Nom->GetBinLowEdge(1),integralHistoryHisto_Nom->GetBinLowEdge(integralHistoryHisto_Nom->GetNbinsX()+1));
          double mean = integralHistoryHisto_Nom->GetMean();
          double stdDev = integralHistoryHisto_Nom->GetStdDev();
          double counts = integralHistoryHisto_Nom->GetBinContent(integralHistoryHisto_Nom->FindBin(mean))*stdDev/0.3989422804;
          m_gausFunct->SetParameter(0,counts);
          m_gausFunct->SetParLimits(0,0.5*counts,2.0*counts);
          m_gausFunct->SetParameter(1,mean);
          m_gausFunct->SetParLimits(1,integralHistoryHisto_Nom->GetBinLowEdge(1),integralHistoryHisto_Nom->GetBinLowEdge(integralHistoryHisto_Nom->GetNbinsX()+1));
          m_gausFunct->SetParameter(2,stdDev);
          m_gausFunct->SetParLimits(2,0.5*stdDev,2.0*stdDev);
          int statusDnDy = integralHistoryHisto_Nom->Fit("m_gausFunct","EQ");
          TF1* fitResultDnDyBootstrap = integralHistoryHisto_Nom->GetFunction("m_gausFunct");
          if(fitResultDnDyBootstrap &&!std::isnan(fitResultDnDyBootstrap->GetParameter(1)) && !std::isnan(fitResultDnDyBootstrap->GetParameter(2)) ){

            dNdyAvg = fitResultDnDyBootstrap->GetParameter(1);
            dNdyErr = fitResultDnDyBootstrap->GetParameter(2);
            cout << "dNdy: " << dNdy << " dNdyAvg: " << dNdyAvg << " +/- " << dNdyErr/dNdyAvg*100.0 << "%" << endl;
            if(m_currentCharge == 1){
              m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdyAvg);
              m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdyErr);
              m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
              m_nominalFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
              m_bootstrapData_Nom_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
              //m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSNow);
            }else{
              m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdyAvg);
              m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdyErr);
              m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
              m_nominalFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
              m_bootstrapData_Nom_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
              //m_BetaS_Minus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSFinal);
            }//is plus minus
          }else{
            cout << "Error: dN/dy Bootstrap Failed! " << endl;
            dNdyAvg = fitResultDnDyBootstrap->GetParameter(1);
            dNdyErr = fitResultDnDyBootstrap->GetParameter(2);
            if(m_currentCharge == 1){
              m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, 0.0);
              m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,0.0);
              m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
              m_nominalFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
              m_bootstrapData_Nom_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
              //m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSNow);
            }else{
              m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, 0.0);
              m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,0.0);
              m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
              m_nominalFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
              m_bootstrapData_Nom_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
              //m_BetaS_Minus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSFinal);
            }//is plus minus




          }
        }//rap loop

        continue;
      }






      //#######   CREATE BETA_S HISTOGRAM AND FIT TO CONSTRAIN THE PARAMETERS  ##########

      TH1D* currentBetaSHisto = NULL;
      if(m_currentCharge == 1){
        currentBetaSHisto = m_BetaS_Plus_Nominal[m_currentCentIndex];
      }else{
        currentBetaSHisto = m_BetaS_Minus_Nominal[m_currentCentIndex];
      }
      const double* initailFitParams = m_minimizer->X();
      for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size(); iii++){
        double beta_s_temp = initailFitParams[2*iii+1];
        double beta_s_error_temp = sqrt( m_minimizer->CovMatrix(2*iii+1, 2*iii+1) );
        cout << "reading out BetaS for y=" << m_liveRapidityProtonSpectra[iii] << "   " << beta_s_temp << " +/- " << beta_s_error_temp << endl;
        currentBetaSHisto->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,beta_s_temp);
        currentBetaSHisto->SetBinError(m_liveRapidityProtonSpectra[iii]+1,beta_s_error_temp);
      }


      TF1* flatTopFunct = new TF1("flatTopFunct", "[0]*pow(x-[1], 2.0) + [2]*pow(x-[1], 4.0) + [3]", a_lowRapBound_BetaS_Constraint, a_highRapBound_BetaS_Constraint);
      flatTopFunct->SetParameter(0,-0.2);
      flatTopFunct->SetParLimits(0,-10.0,0.0);
      flatTopFunct->FixParameter(1,m_cuts->getYCM());
      flatTopFunct->SetParameter(2,-0.2);
      flatTopFunct->SetParLimits(2,-10.0,0.0);
      flatTopFunct->SetParameter(3,currentBetaSHisto->GetBinContent(currentBetaSHisto->FindBin(m_cuts->getYCM())));
      flatTopFunct->SetParLimits(3,0.0,1.0);
      int status_betaS = currentBetaSHisto->Fit("flatTopFunct","E","", a_lowRapBound_BetaS_Constraint, a_highRapBound_BetaS_Constraint);
      TF1* fitResult_BetaS = currentBetaSHisto->GetFunction("flatTopFunct");

      cout << "Done With BetaS Parabola Fit" << endl;
      fittingCanvas->cd();
      gPad->SetLogy(false);
      currentBetaSHisto->Draw("E");
      fittingCanvas->SaveAs(Form("%s/%s/FixedBetaS_Fit_Cent%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));

      if(!fitResult_BetaS){
        cout << " Fitting of Beta_S to Constrain Failed " << endl << "  Cannot Continue... " << endl;
        continue;
      }else{
        cout << " BetaS Fit Result Exists" << endl;
      }

      if(m_constrainAntiProtonBetaS_withParamsFromProtons && m_currentCharge == -1){
        fitResult_BetaS = m_BetaS_Plus_Nominal[m_currentCentIndex]->GetFunction("flatTopFunct");
      }

      //##### CREATE A NEW MINIMIZER #################
      //bc you cant use setVariableValue after minimization?
      m_minimizer = ROOT::Math::Factory::CreateMinimizer();
      m_minimizer->SetFunction(*m_chiSqrdFunctor);
      for(int iii = 0; iii < 2*m_liveRapidityProtonSpectra.size(); iii+=2 ){
        double rapidity = currentBetaSHisto->GetBinCenter(m_liveRapidityProtonSpectra[iii/2]+1);
        double betaSNowFixed = fitResult_BetaS->Eval(rapidity);

        if(betaSNowFixed <= 0.0) betaSNowFixed = 0.0;
         m_minimizer->SetVariable(iii, Form("A_%02d",m_liveRapidityProtonSpectra[iii/2]), finalParams_RoundOne[iii], 0.1*finalParams_RoundOne[iii]);
         m_minimizer->SetVariableLimits(iii, 0.01*finalParams_RoundOne[iii], finalParams_RoundOne[iii]*100.0);
         m_minimizer->SetVariable(iii+1, Form("Beta_S_%02d", m_liveRapidityProtonSpectra[iii/2]), betaSNowFixed, 0.1);
         m_minimizer->FixVariable(iii+1);
      }
      double theLastTemp = finalParams_RoundOne[2*m_liveRapidityProtonSpectra.size()];
      m_minimizer->SetVariable(2*m_liveRapidityProtonSpectra.size(), "T" ,theLastTemp, 0.1);
      m_minimizer->SetVariableLimits(2*m_liveRapidityProtonSpectra.size() ,0.6*theLastTemp, 1.4*theLastTemp);
      m_minimizer->SetPrintLevel(5);
      m_minimizer->SetMaxIterations(3000);
      m_minimizer->SetMaxFunctionCalls(100000);

      /*//Fix the BetaS Parameters
      for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size(); iii++){
        double rapidity = currentBetaSHisto->GetBinCenter(m_liveRapidityProtonSpectra[iii]+1);
        cout << " Rapidity: " << rapidity << endl;
        double betaSNowFixed = fitResult_BetaS->Eval(rapidity);
        cout << "constrainedBeta = " << betaSNowFixed << endl;
        if(m_minimizer){
          cout << "Minimizer exists with " << m_minimizer->NDim() << endl;
        }else{
          cout << "Minimizer doesn't exist" << endl;
        }
        m_minimizer->SetVariableValue((2*iii)+1,betaSNowFixed);
        cout << "setting variable " << 2*iii+1 << endl;
        m_minimizer->FixVariable(2*iii+1);
        cout << " Fixing Variable " << 2*iii+1 << " " << Form("Beta_S_%02d", m_liveRapidityProtonSpectra[iii]) <<  " to " << betaSNowFixed << endl;
      }

      //fix temperature
      cout << "Fixing Temperature Varaible Num: " << 2*m_liveRapidityProtonSpectra.size() << endl;
      m_minimizer->FixVariable(2*m_liveRapidityProtonSpectra.size());
      //m_minimizer->FixVariable(m_liveRapidityProtonSpectra.size()+1);

      cout << "Fixed the temperature and all of the surface velocities (BetaS) " << endl;
      */

      //###### FIT Just the amplitudes #########
      m_minimizer->SetValidError(true);
      m_minimizer->Minimize();
      status = m_minimizer->Status();
      if(status == 0){
        cout << "Proton Fit Status Successful with Status = 0 " << endl;
      }else{
        cout << "############!!!!!!!!!!!#############  Second Pass Fit:   STATUS OF FIT = " << status << "   IS BAD!!!!!  ############!!!!!!!!!!##########";
        continue;
      }

      const double* finalParams = m_minimizer->X();
      double tempFinal = finalParams[2*m_liveRapidityProtonSpectra.size()];
      double tempFinalErr = sqrt( m_minimizer->CovMatrix(2*m_liveRapidityProtonSpectra.size(),2*m_liveRapidityProtonSpectra.size()) );
      cout << " ptrs: " << m_Proton_Temp_Plus_Nom << "   " << m_Proton_Temp_Minus_Nom << endl;
      if(!std::isnan(tempFinal) && !std::isnan(tempFinalErr)){
        if(m_currentCharge == 1){
          m_Proton_Temp_Plus_Nom->SetBinContent(m_currentCentIndex+1,tempFinal);
          m_Proton_Temp_Plus_Nom->SetBinError(m_currentCentIndex+1,tempFinalErr);
        }else{
          m_Proton_Temp_Minus_Nom->SetBinContent(m_currentCentIndex+1,tempFinal);
          m_Proton_Temp_Minus_Nom->SetBinError(m_currentCentIndex+1,tempFinalErr);
        }
      }

      cout << "Final Temperature: " << tempFinal << endl;
      //cout << "Final Beta_S: " << betaSFinal << endl;

      cout << "######################################################################" << endl;
      cout << "          STAGE 3   Proton Fitting - Bootstrap Individual Amplitudes" << endl;


      for(int iii = 0; iii < m_liveRapidityProtonSpectra.size(); iii++){
        double Amp = finalParams[2*iii];
        double AmpErr = sqrt( m_minimizer->CovMatrix(2*iii,2*iii) );
        double rapidity = currentBetaSHisto->GetBinCenter(m_liveRapidityProtonSpectra[iii]+1);
        double betaSNow = fitResult_BetaS->Eval(rapidity);
        cout << "Ready for bootstraper: Amp: " << Amp << " AmpErr: " << AmpErr << " Rap: " << rapidity << " BetaS: " << betaSNow << " Temp: " << tempFinal << endl;
        TF1* fitFunct = new TF1(
          Form("NominalFit_Cent%02d_yIndex%02d",m_currentCentIndex,m_liveRapidityProtonSpectra[iii]),
          this,&SpectraFitter::blastWaveModelFit,0,10,6,"SpectraFitter","blastWaveModelFit");
        fitFunct->SetParNames("A","T_kin","#beta_S","W","R","m_p");
        fitFunct->SetParameter(0,Amp);
        fitFunct->SetParameter(1,tempFinal);
        fitFunct->SetParameter(2,betaSNow);
        fitFunct->FixParameter(3,0.5);
        fitFunct->FixParameter(4,1.0);
        fitFunct->SetParameter(5,m_partInfo->GetParticleMass(2));

        TCanvas *protonFinalCanvas = new TCanvas();

        protonFinalCanvas->SetLogy();
        if(pmIndex == 0) m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]]->Draw("AP");
        else if(pmIndex == 1) m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]]->Draw("AP");
        fitFunct->Draw("SAME");

        protonFinalCanvas->SaveAs(Form("%s/%s/FinalFit_Nom_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_liveRapidityProtonSpectra[iii]));

        delete protonFinalCanvas;


        double dNdy = 0;
        double dNdyAvg = 0;
        double dNdyErr = 0;
        //double &a_integral, double &a_avgIntegral, double &a_integralError,TF1* a_fitFunction, TFitResult* a_fitResult, double a_mass, int a_parameterToVary,int a_numTrials, double a_paramError,double a_lowIntegralBound, double a_highIntegralBound
        vector< double > integralListNom = FitUtilities::bootstrapIntegralSingleParameter(dNdy,dNdyAvg, dNdyErr, fitFunct, NULL, protonMass,0, a_numTrialsForDnDyBootstrap, AmpErr);
        double smallest = *min_element(integralListNom.begin(), integralListNom.end());
        double biggest = *max_element(integralListNom.begin(), integralListNom.end());
        TH1D* integralHistoryHisto_Nom = new TH1D("paramHisto","Sampled Integrals; Integral Value;Counts",100,0.98*smallest, 1.02*biggest);
        for(int iii = 0; iii < (int) integralListNom.size(); iii++) integralHistoryHisto_Nom->Fill(integralListNom[iii]);
        integralHistoryHisto_Nom->SetName(Form("dNdy_Nom_History_%s_Cent%02d_Rap%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_liveRapidityProtonSpectra[iii]));
        HistogramUtilities::makeSqrtNErrors(integralHistoryHisto_Nom);
        m_gausFunct->SetRange(integralHistoryHisto_Nom->GetBinLowEdge(1),integralHistoryHisto_Nom->GetBinLowEdge(integralHistoryHisto_Nom->GetNbinsX()+1));
        double mean = integralHistoryHisto_Nom->GetMean();
        double stdDev = integralHistoryHisto_Nom->GetStdDev();
        double counts = integralHistoryHisto_Nom->GetBinContent(integralHistoryHisto_Nom->FindBin(mean))*stdDev/0.3989422804;
        m_gausFunct->SetParameter(0,counts);
        m_gausFunct->SetParLimits(0,0.5*counts,2.0*counts);
        m_gausFunct->SetParameter(1,mean);
        m_gausFunct->SetParLimits(1,integralHistoryHisto_Nom->GetBinLowEdge(1),integralHistoryHisto_Nom->GetBinLowEdge(integralHistoryHisto_Nom->GetNbinsX()+1));
        m_gausFunct->SetParameter(2,stdDev);
        m_gausFunct->SetParLimits(2,0.5*stdDev,2.0*stdDev);
        int statusDnDy = integralHistoryHisto_Nom->Fit("m_gausFunct","EQ");
        TF1* fitResultDnDyBootstrap = integralHistoryHisto_Nom->GetFunction("m_gausFunct");
        if(fitResultDnDyBootstrap &&!std::isnan(fitResultDnDyBootstrap->GetParameter(1)) && !std::isnan(fitResultDnDyBootstrap->GetParameter(2)) ){

          dNdyAvg = fitResultDnDyBootstrap->GetParameter(1);
          dNdyErr = fitResultDnDyBootstrap->GetParameter(2);
          cout << "dNdy: " << dNdy << " dNdyAvg: " << dNdyAvg << " +/- " << dNdyErr/dNdyAvg*100.0 << "%" << endl;
          if(m_currentCharge == 1){
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdyAvg);
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdyErr);
            m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
            m_nominalFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
            m_bootstrapData_Nom_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
            //m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSNow);
          }else{
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdyAvg);
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdyErr);
            m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
            m_nominalFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
            m_bootstrapData_Nom_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
            //m_BetaS_Minus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSFinal);
          }//is plus minus
        }else{
          cout << "Error: dN/dy Bootstrap Failed! " << endl;
          dNdyAvg = fitResultDnDyBootstrap->GetParameter(1);
          dNdyErr = fitResultDnDyBootstrap->GetParameter(2);
          if(m_currentCharge == 1){
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, 0.0);
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,0.0);
            m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
            m_nominalFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
            m_bootstrapData_Nom_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
            //m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSNow);
          }else{
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, 0.0);
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,0.0);
            m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
            m_nominalFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
            m_bootstrapData_Nom_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
            //m_BetaS_Minus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSFinal);
          }//is plus minus




        }
      }//rap loop
    }// pm index
  }// cent index

}


//############################################################################################################################################################
//###########################################################################################################################################################




void SpectraFitter::fitProtonSpectraFXT(bool a_constrainBetaS, int a_numTrialsForDnDyBootstrap, double a_lowRapBound_BetaS_Constraint, double a_highRapBound_BetaS_Constraint){
  cout << "#####################  Starting SpectraFitter::fitProtonSpectra() ########################" << endl;
  TVirtualFitter::SetMaxIterations( 1000000 );
  m_currentPartIndex = 2;
  bool useAvgParamsForSeparateFits = true;

  TCanvas* fittingCanvas = new TCanvas("fittingCanvas_Proton","Fitting Canvas");
  fittingCanvas->SetWindowSize(1300,700);
  fittingCanvas->SetCanvasSize(1200,600);
  double protonMass = m_partInfo->GetParticleMass(m_currentPartIndex);
  for(unsigned int centIndex = 0; centIndex < 16; centIndex++){
    m_currentCentIndex = centIndex;
    for(int pmIndex = 0; pmIndex < 2; pmIndex++){
      m_currentCharge = 1;
      if(pmIndex == 1) m_currentCharge = -1;

      m_liveRapidityProtonSpectra.clear();
      double ampWeight = 0.0;
      double avgAmpFirst = 0.0;
      double tempWeight = 0.0;
      double avgTempFirst = 0.0;
      double avgBetaSFirst = 0.0;
      double betaSWeight = 0.0;
      vector< double > ampStorage;
      vector< double > tempStorage;
      vector< double > betaSStorage;

      double ampWeight_sys = 0.0;
      double avgAmpFirst_sys = 0.0;
      double tempWeight_sys = 0.0;
      double avgTempFirst_sys = 0.0;
      vector< double > ampStorage_sys;
      vector< double > tempStorage_sys;

      //Fit with single blastwaves first
      m_protonFittingStage = 1;
      m_isTemperatureConstrained = false;
      int counter = 0;
      for(unsigned int yIndex = 0; yIndex < m_cuts->getRapMtM0BinStructure(m_currentPartIndex, 1)->GetNbinsX(); yIndex++){
        m_currentRapValue = m_cuts->getRapMtM0BinStructure(m_currentPartIndex, 1)->GetBinCenter(yIndex+1);
        m_currentRapIndex = yIndex;
        TGraphErrors* specPM[2];
        specPM[0] = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][yIndex];
        specPM[1] = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][yIndex];
        if( !specPM[pmIndex] || specPM[pmIndex]->GetN() <= 4 ) continue; //############################################   MUST BE SAME AS ABOVE! ###################################
        m_liveRapidityProtonSpectra.push_back(yIndex);
        m_liveRapidityValueProtonSpectra.push_back(m_currentRapValue);
        cout << "Proton Fitting: Cent " << m_currentCentIndex << " yIndex " << yIndex
             << " charge: " << m_currentCharge << " ptr: " << specPM[pmIndex] << " charge: " << m_currentCharge
             << " N: " << specPM[pmIndex]->GetN() <<  endl;

        //##########  FIT WITH NOMINAL FIT FUNCTION ##########
        m_isCurrentFitNominal = true;
        m_currentSpectra = (TGraphErrors*) specPM[pmIndex]->Clone();
        init_blastWave();
        init_thermal();

        //cout << " Fixing Beta_S to 0.4 for initial fit..." << endl;
        //m_blastWave->FixParameter(2,0.4);
        m_blastWave->SetParameter(2,0.4);

        TF1* initial_BW_fit = new TF1(
          Form("InitFit_%s_Cent%02d_yIndex%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_currentRapIndex),
          this,&SpectraFitter::blastWaveModelFit,0,10,6,"SpectraFitter","blastWaveModelFit");
        initial_BW_fit->SetParNames("A","T_kin","#beta_S","W","R","m_p");
        initial_BW_fit->SetParameter(0,m_blastWave->GetParameter(0));
        initial_BW_fit->SetParameter(1,m_blastWave->GetParameter(1));
        initial_BW_fit->SetParameter(2,m_blastWave->GetParameter(2));
        initial_BW_fit->FixParameter(3,m_blastWave->GetParameter(3));
        initial_BW_fit->FixParameter(4,m_blastWave->GetParameter(4));
        initial_BW_fit->SetParameter(5,m_blastWave->GetParameter(5));


        initial_BW_fit->SetLineColor(kYellow);
        int status = m_currentSpectra->Fit("m_blastWave","EV EX0","",0,10);
        TF1* fitResult = m_currentSpectra->GetFunction("m_blastWave");

        if(fitResult){
          ampWeight += 1.0 / (fitResult->GetParError(0)*fitResult->GetParError(0));
          avgAmpFirst += 1.0 / (fitResult->GetParError(0)*fitResult->GetParError(0)) * fitResult->GetParameter(0);
          tempWeight += 1.0 / (fitResult->GetParError(1)*fitResult->GetParError(1));
          avgTempFirst += 1.0 / (fitResult->GetParError(1)*fitResult->GetParError(1)) * fitResult->GetParameter(1);
          betaSWeight += 1.0 / (fitResult->GetParError(2)*fitResult->GetParError(2));
          avgBetaSFirst += 1.0 / (fitResult->GetParError(2)*fitResult->GetParError(2)) * fitResult->GetParameter(2);

          ampStorage.push_back(fitResult->GetParameter(0));
          tempStorage.push_back(fitResult->GetParameter(1));
          betaSStorage.push_back(fitResult->GetParameter(2));

        }else{
          ampStorage.push_back(-1);
          tempStorage.push_back(-1);
          betaSStorage.push_back(-1);
        }

        //make the fit image
        fittingCanvas->cd();
        double smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
        double largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
        if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
        frame->SetTitle(Form("p^{%s} Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
                    m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
                    m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
        //frame->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
        //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame->GetXaxis()->SetTitle("m_{T}-m_{p} (GeV/c^{2})");
        frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);
        initial_BW_fit->Draw("same");
        m_currentSpectra->Draw("P");
        fittingCanvas->Update();
        fittingCanvas->SaveAs(Form("%s/%s/FirstFit_Nom_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));
        //delete m_currentSpectra;
        //delete initial_BW_fit;


        fittingCanvas->Clear();

        double thermalHighmTm0 = m_currentSpectra->GetX()[3]+m_currentSpectra->GetErrorX(3);

        TF1* initial_thermal_fit = new TF1(
          Form("InitFit_Sys_%s_Cent%02d_yIndex%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_currentRapIndex),
          "[0] * (x+[2]) * exp(-x/[1]) / ((2*3.14159265) * [1] * ([2]*[2] + 2*[2]*[1] + 2*[1]*[1]))",0,thermalHighmTm0);
        initial_thermal_fit->SetParNames("dN/dy","T","m");
        initial_thermal_fit->SetParameter(0,m_blastWave->GetParameter(0));
        initial_thermal_fit->SetParameter(1,m_blastWave->GetParameter(1));
        initial_thermal_fit->FixParameter(2,m_partInfo->GetParticleMass(m_currentPartIndex));


        initial_thermal_fit->SetLineColor(kYellow);
        int status_sys = m_currentSpectra->Fit("m_thermal","EV EX0","",0,thermalHighmTm0);
        TF1* fitResult_sys = m_currentSpectra->GetFunction("m_thermal");


        if(fitResult_sys){
          ampWeight_sys += 1.0 / (fitResult_sys->GetParError(0)*fitResult_sys->GetParError(0));
          avgAmpFirst_sys += 1.0 / (fitResult_sys->GetParError(0)*fitResult_sys->GetParError(0)) * fitResult_sys->GetParameter(0);
          tempWeight_sys += 1.0 / (fitResult_sys->GetParError(1)*fitResult_sys->GetParError(1));
          avgTempFirst_sys += 1.0 / (fitResult_sys->GetParError(1)*fitResult_sys->GetParError(1)) * fitResult_sys->GetParameter(1);

          ampStorage_sys.push_back(fitResult_sys->GetParameter(0));
          tempStorage_sys.push_back(fitResult_sys->GetParameter(1));

        }else{
          ampStorage_sys.push_back(-1);
          tempStorage_sys.push_back(-1);
        }

        //double smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
        //double largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
        //if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame_sys = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
        frame_sys->SetTitle(Form("p^{%s} Systematic Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
                    m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
                    m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
        //frame->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
        //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame_sys->GetXaxis()->SetTitle("m_{T}-m_{p} (GeV/c^{2})");
        frame_sys->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);
        initial_thermal_fit->Draw("same");
        //m_currentSpectra->GetFunction("m_blastWave")->SetBit(TF1::kNotDraw);
        m_currentSpectra->Draw("P");
        fittingCanvas->Update();
        fittingCanvas->SaveAs(Form("%s/%s/FirstFit_Sys_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));


        if(!fitResult) cout << "No Fit Result: yindex: " << yIndex << endl;
        if(!fitResult_sys) cout << "No Fit Result Sys: yindex: " << yIndex << endl;
        counter+=2;
      }

      avgAmpFirst = avgAmpFirst/ampWeight;
      avgTempFirst = avgTempFirst/tempWeight;
      avgBetaSFirst = avgBetaSFirst/betaSWeight;

      if(std::isnan(avgBetaSFirst)) avgBetaSFirst = 0.5;

      cout << " AvgAmp: " << avgAmpFirst << "  AvgTemp: " << avgTempFirst << "  AvgBetsS: " << avgBetaSFirst << endl;

      avgAmpFirst_sys = avgAmpFirst_sys/ampWeight_sys;
      avgTempFirst_sys = avgTempFirst_sys/tempWeight_sys;

      TGraph *temp_init_sys = new TGraph(m_liveRapidityValueProtonSpectra.size(),&m_liveRapidityValueProtonSpectra[0],&tempStorage_sys[0]);
      temp_init_sys->SetTitle("Temp Systematic Initial Values");
      temp_init_sys->GetXaxis()->SetTitle("y_{lab}");
      temp_init_sys->GetYaxis()->SetTitle("Temp (GeV)");
      temp_init_sys->SetMarkerStyle(20);

      TF1 *temp_fitInit_sys = new TF1("temp_fitInit_sys","[0]/TMath::CosH([2]*(x-[1]))",-2,2);
      temp_fitInit_sys->SetParameters(0.1,m_cuts->getYCM(),1.0);
      temp_fitInit_sys->FixParameter(1,m_cuts->getYCM());
      temp_fitInit_sys->SetParLimits(0,0.01,0.3);

      temp_init_sys->Fit(temp_fitInit_sys);
      temp_init_sys->Draw("AP");
      temp_fitInit_sys->Draw("Same");

      TCanvas *fitParsCanvas = new TCanvas("fitParsCanvas","Fit Parameters Canvas");
      fitParsCanvas->SetWindowSize(1300,700);
      fitParsCanvas->SetCanvasSize(1200,600);

      fitParsCanvas->SaveAs(Form("%s/%s/tempInit_Sys_Cent%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));

      fitParsCanvas->Clear();

      //setup minimizer
      int numSpectraToFit = (int) m_liveRapidityProtonSpectra.size();
      //systematic fitting
      m_minimizer_sys = ROOT::Math::Factory::CreateMinimizer();
      m_chiSqrdFunctor_sys = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_thermal_FXT_ChiSqr,(numSpectraToFit) + 3);
      cout << "created chi squared sys functor with NDim " << m_chiSqrdFunctor_sys->NDim() << "  functor: " << &SpectraFitter::simultaneous_thermal_FXT_ChiSqr  << endl;
      m_minimizer_sys->SetFunction(*m_chiSqrdFunctor_sys);
      for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size(); iii++){
        if(useAvgParamsForSeparateFits){
          m_minimizer_sys->SetVariable(iii, Form("dNdy_sys_%02d",m_liveRapidityProtonSpectra[iii]), avgAmpFirst_sys , 0.1*avgAmpFirst_sys);
          m_minimizer_sys->SetVariableLimits(iii, 0.0, avgAmpFirst_sys*10000.0);
        }else{
          m_minimizer_sys->SetVariable(iii, Form("dNdy_sys_%02d",m_liveRapidityProtonSpectra[iii]), ampStorage_sys[iii] , 0.1*ampStorage_sys[iii]);
          m_minimizer_sys->SetVariableLimits(iii, 0.0, ampStorage_sys[iii]*10000.0);
        }
      }

      m_minimizer_sys->SetVariable(counter/2, "Amp_T_sys" ,temp_fitInit_sys->GetParameter(0), 0.01);
      m_minimizer_sys->SetVariableLimits(counter/2,0.0001, 0.3);
      m_minimizer_sys->SetVariable(counter/2+1, "Mu_T_sys" ,m_cuts->getYCM(), 0.2);
      m_minimizer_sys->FixVariable(counter/2+1);
      m_minimizer_sys->SetVariable(counter/2+2, "Sigma_T_sys" ,temp_fitInit_sys->GetParameter(2), 2.0);
      m_minimizer_sys->SetVariableLimits(counter/2+2,0.0, 2.0);




      cout << "######################################################################" << endl;
      cout << "          STAGE 2   Proton Sys Fitting - Use Separate Rap Fit Results as Seeds to Simultaneous Fitter" << endl;
      //m_blastWave->SetParLimits(2,0.0,1.0);
      m_protonFittingStage = 2;
      //init_simul_blastWave();  //only do this if not initialized by single fits above
      m_minimizer_sys->SetPrintLevel(5);
      m_minimizer_sys->SetMaxIterations(3000);
      m_minimizer_sys->SetMaxFunctionCalls(200000);
      m_minimizer_sys->SetValidError(true);
      m_minimizer_sys->Minimize();
      int status_sys = m_minimizer_sys->Status();
      const double* finalParams_sys = m_minimizer_sys->X();
      if(status_sys == 0){
        cout << "Proton Sys Fit Status: " << status_sys << endl;
      }
      else{
        cout << "################################  First Pass Fit:  STATUS OF SYS FIT = " << status_sys << "   IS BAD!!!!!  ################################" << endl;
        cout << "Current Parameters: " << endl;
        for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size() + 3; iii++){
          cout << "  " << finalParams_sys[iii];
        }
        cout << endl;
        continue;
      }


            cout << "######################################################################" << endl;
      cout << "          STAGE 3   Proton Fitting Sys - Bootstrap Individual Amplitudes" << endl;


      for(int iii = 0; iii < m_liveRapidityProtonSpectra.size(); iii++){

        double rapidity = m_liveRapidityValueProtonSpectra[iii];

        TGraphErrors* spectrum = NULL;
        if(m_currentCharge == 1) spectrum = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]];
        else spectrum = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]];

        double dNdy_sys = finalParams_sys[iii];
        double dNdy_err_sys = sqrt( m_minimizer_sys->CovMatrix(iii,iii) );

        double temp_sys = finalParams_sys[m_liveRapidityProtonSpectra.size()]/TMath::CosH(finalParams_sys[m_liveRapidityProtonSpectra.size() + 2]*(rapidity - finalParams_sys[m_liveRapidityProtonSpectra.size()+1]));

        double tempErr_sys = sqrt( pow(temp_sys*m_minimizer_sys->CovMatrix(m_liveRapidityProtonSpectra.size(),m_liveRapidityProtonSpectra.size())/finalParams_sys[m_liveRapidityProtonSpectra.size()],2) + pow(temp_sys*m_minimizer_sys->CovMatrix(m_liveRapidityProtonSpectra.size()+2,m_liveRapidityProtonSpectra.size()+2)*TMath::TanH(finalParams_sys[m_liveRapidityProtonSpectra.size()+2]*(rapidity - finalParams_sys[m_liveRapidityProtonSpectra.size()+1]))*(rapidity - finalParams_sys[m_liveRapidityProtonSpectra.size()+1]),2) );

        double thermalHighmTm0 = spectrum->GetX()[3]+spectrum->GetErrorX(3);


        TF1* fitFunct_sys = new TF1(
          Form("SystematicFit_Cent%02d_yIndex%02d",m_currentCentIndex,m_liveRapidityProtonSpectra[iii]),
          "[0] * (x+[2]) * exp(-x/[1]) / ((2*3.14159265) * [1] * ([2]*[2] + 2*[2]*[1] + 2*[1]*[1]))",0.0,thermalHighmTm0);
        fitFunct_sys->SetParNames("dN/dy","T","m");
        fitFunct_sys->SetParameter(0,dNdy_sys);
        fitFunct_sys->SetParError(0,dNdy_err_sys);
        fitFunct_sys->SetParameter(1,temp_sys);
        fitFunct_sys->SetParError(1,tempErr_sys);
        fitFunct_sys->FixParameter(2,m_partInfo->GetParticleMass(m_currentPartIndex));




        TCanvas *finalCanvas = new TCanvas("finalCanvas","Final Canvas");
        finalCanvas->SetWindowSize(1300,700);
        finalCanvas->SetCanvasSize(1200,600);

        finalCanvas->cd();

        double smallYVal =  HistogramUtilities::findSmallestYVal(spectrum)*0.25;
        double largeXVal =  HistogramUtilities::findLargestXVal(spectrum)*1.3;
        if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame_sys = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(spectrum)*4.0);
        frame_sys->SetTitle(Form("p^{%s} Systematic Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
          m_cuts->getRapidityRangeLow(m_liveRapidityProtonSpectra[iii],m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(m_liveRapidityProtonSpectra[iii],m_currentPartIndex,1),
          m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
          //frame->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
          //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame_sys->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
        frame_sys->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);

        spectrum->SetMarkerStyle(20);
        spectrum->Draw("P");
        fitFunct_sys->Draw("same");

        TPaveText *fitParsTxt_sys = new TPaveText(0.65,0.15,0.95,0.85,"NDC");
        fitParsTxt_sys->AddText(Form("dN/dy \t %f#pm%f",dNdy_sys,dNdy_err_sys));
        fitParsTxt_sys->AddText(Form("T \t %f#pm%f",temp_sys,tempErr_sys));
        fitParsTxt_sys->AddText(Form("m \t %f",m_partInfo->GetParticleMass(m_currentPartIndex)));

        fitParsTxt_sys->SetFillStyle(0);
        fitParsTxt_sys->SetBorderSize(5);

        fitParsTxt_sys->Draw("same");

        finalCanvas->Update();
        finalCanvas->SaveAs(Form("%s/%s/FinalFit_Sys_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
          m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_liveRapidityProtonSpectra[iii]));



        if(m_currentCharge == 1){

          m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdy_sys);
          m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdy_err_sys);

          m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,temp_sys);
          m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,tempErr_sys);

          m_systematicFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct_sys;

        }else{

          m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdy_sys);
          m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdy_err_sys);

          m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,temp_sys);
          m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,tempErr_sys);

          m_systematicFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct_sys;
        }//is plus minus

      }//rap loop



      //nominal fitting
      m_minimizer = ROOT::Math::Factory::CreateMinimizer();
      m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_blastWave_ChiSqr,(2*numSpectraToFit) + 1);
      cout << "created chi squared functor with NDim " << m_chiSqrdFunctor->NDim() << "  functor: " << &SpectraFitter::simultaneous_blastWave_ChiSqr  << endl;
      m_minimizer->SetFunction(*m_chiSqrdFunctor);
      for(int iii = 0; iii < (int) 2*m_liveRapidityProtonSpectra.size(); iii+=2){
        if(useAvgParamsForSeparateFits){
          m_minimizer->SetVariable(iii, Form("A_%02d",m_liveRapidityProtonSpectra[iii/2]), avgAmpFirst , 0.1*avgAmpFirst);
          m_minimizer->SetVariableLimits(iii, 0.0, avgAmpFirst*10000.0);
          m_minimizer->SetVariable(iii+1, Form("Beta_S_%02d", m_liveRapidityProtonSpectra[iii/2]), avgBetaSFirst, 0.3);
          m_minimizer->SetVariableLimits(iii+1, 0.0, 1.0);
        }else{
          m_minimizer->SetVariable(iii, Form("A_%02d",m_liveRapidityProtonSpectra[iii/2]), ampStorage[iii/2] , 0.1*ampStorage[iii/2]);
          m_minimizer->SetVariableLimits(iii, 0.0, ampStorage[iii/2]*10000.0);
          m_minimizer->SetVariable(iii+1, Form("Beta_S_%02d", m_liveRapidityProtonSpectra[iii/2]), betaSStorage[iii/2], 0.1);
          m_minimizer->SetVariableLimits(iii+1, 0.0, 1.0);
        }
      }

      m_minimizer->SetVariable(counter, "T" ,avgTempFirst, 0.15);
      m_minimizer->SetVariableLimits(counter,0.0, 2.0);








      cout << "######################################################################" << endl;
      cout << "          STAGE 2   Proton Fitting - Use Separate Rap Fit Results as Seeds to Simultaneous Fitter" << endl;
      m_blastWave->SetParLimits(2,0.0,1.0);
      m_protonFittingStage = 2;
      //init_simul_blastWave();  //only do this if not initialized by single fits above
      m_minimizer->SetPrintLevel(5);
      m_minimizer->SetMaxIterations(3000);
      m_minimizer->SetMaxFunctionCalls(200000);
      m_minimizer->SetValidError(true);
      m_minimizer->Minimize();
      int status = m_minimizer->Status();
      const double* finalParams_RoundOne = m_minimizer->X();
      if(status == 0){
        cout << "Proton Fit Status: " << status << endl;
      }
      else{
        cout << "################################  First Pass Fit:  STATUS OF FIT = " << status << "   IS BAD!!!!!  ################################" << endl;
        cout << "Current Parameters: " << endl;
        for(int iii = 0; iii < (int) 2*m_liveRapidityProtonSpectra.size() + 1; iii++){
          cout << "  " << finalParams_RoundOne[iii];
        }
        cout << endl;
        continue;
      }



      if(a_constrainBetaS){
        double tempFinal = finalParams_RoundOne[2*m_liveRapidityProtonSpectra.size()];
        double tempFinalErr = sqrt( m_minimizer->CovMatrix(2*m_liveRapidityProtonSpectra.size(),2*m_liveRapidityProtonSpectra.size()) );
        cout << " ptrs: " << m_Proton_Temp_Plus_Nom << "   " << m_Proton_Temp_Minus_Nom << endl;
        if(!std::isnan(tempFinal) && !std::isnan(tempFinalErr)){
          if(m_currentCharge == 1){
            m_Proton_Temp_Plus_Nom->SetBinContent(m_currentCentIndex+1,tempFinal);
            m_Proton_Temp_Plus_Nom->SetBinError(m_currentCentIndex+1,tempFinalErr);
          }else{
            m_Proton_Temp_Minus_Nom->SetBinContent(m_currentCentIndex+1,tempFinal);
            m_Proton_Temp_Minus_Nom->SetBinError(m_currentCentIndex+1,tempFinalErr);
          }
        }

        cout << "Final Temperature: " << tempFinal << endl;
        //cout << "Final Beta_S: " << betaSFinal << endl;

        for(int iii = 0; iii < m_liveRapidityProtonSpectra.size(); iii++){
          double Amp = finalParams_RoundOne[2*iii];
          double AmpErr = sqrt( m_minimizer->CovMatrix(2*iii,2*iii) );
          //double rapidity = currentBetaSHisto->GetBinCenter(m_liveRapidityProtonSpectra[iii]+1);
          double betaSNow = finalParams_RoundOne[2*iii+1];
          cout << "Ready for bootstraper: Amp: " << Amp << " AmpErr: " << AmpErr <<  " BetaS: " << betaSNow << " Temp: " << tempFinal << endl;
          TF1* fitFunct = new TF1(
            Form("NominalFit_Cent%02d_yIndex%02d_blastwave",m_currentCentIndex,m_liveRapidityProtonSpectra[iii]),
            this,&SpectraFitter::blastWaveModelFit,0,10,6,"SpectraFitter","blastWaveModelFit");
          fitFunct->SetParNames("A","T_kin","#beta_S","W","R","m_p");
          fitFunct->SetParameter(0,Amp);
          fitFunct->SetParError(0,AmpErr);
          fitFunct->SetParameter(1,tempFinal);
          fitFunct->SetParameter(2,betaSNow);
          fitFunct->FixParameter(3,0.5);
          fitFunct->FixParameter(4,1.0);
          fitFunct->SetParameter(5,m_partInfo->GetParticleMass(2));


          double dNdy = 0;
          double dNdyAvg = 0;
          double dNdyErr = 0;
          //double &a_integral, double &a_avgIntegral, double &a_integralError,TF1* a_fitFunction, TFitResult* a_fitResult, double a_mass, int a_parameterToVary,int a_numTrials, double a_paramError,double a_lowIntegralBound, double a_highIntegralBound
          vector< double > integralListNom = FitUtilities::bootstrapIntegralSingleParameter(dNdy,dNdyAvg, dNdyErr, fitFunct, NULL, protonMass,0, a_numTrialsForDnDyBootstrap, AmpErr);
          double smallest = *min_element(integralListNom.begin(), integralListNom.end());
          double biggest = *max_element(integralListNom.begin(), integralListNom.end());
          TH1D* integralHistoryHisto_Nom = new TH1D("paramHisto","Sampled Integrals; Integral Value;Counts",100,0.98*smallest, 1.02*biggest);
          for(int iii = 0; iii < (int) integralListNom.size(); iii++) integralHistoryHisto_Nom->Fill(integralListNom[iii]);
          integralHistoryHisto_Nom->SetName(Form("dNdy_Nom_History_%s_Cent%02d_Rap%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_liveRapidityProtonSpectra[iii]));
          HistogramUtilities::makeSqrtNErrors(integralHistoryHisto_Nom);
          m_gausFunct->SetRange(integralHistoryHisto_Nom->GetBinLowEdge(1),integralHistoryHisto_Nom->GetBinLowEdge(integralHistoryHisto_Nom->GetNbinsX()+1));
          double mean = integralHistoryHisto_Nom->GetMean();
          double stdDev = integralHistoryHisto_Nom->GetStdDev();
          double counts = integralHistoryHisto_Nom->GetBinContent(integralHistoryHisto_Nom->FindBin(mean))*stdDev/0.3989422804;
          m_gausFunct->SetParameter(0,counts);
          m_gausFunct->SetParLimits(0,0.5*counts,2.0*counts);
          m_gausFunct->SetParameter(1,mean);
          m_gausFunct->SetParLimits(1,integralHistoryHisto_Nom->GetBinLowEdge(1),integralHistoryHisto_Nom->GetBinLowEdge(integralHistoryHisto_Nom->GetNbinsX()+1));
          m_gausFunct->SetParameter(2,stdDev);
          m_gausFunct->SetParLimits(2,0.5*stdDev,2.0*stdDev);
          int statusDnDy = integralHistoryHisto_Nom->Fit("m_gausFunct","EQ");
          TF1* fitResultDnDyBootstrap = integralHistoryHisto_Nom->GetFunction("m_gausFunct");
          if(fitResultDnDyBootstrap &&!std::isnan(fitResultDnDyBootstrap->GetParameter(1)) && !std::isnan(fitResultDnDyBootstrap->GetParameter(2)) ){

            dNdyAvg = fitResultDnDyBootstrap->GetParameter(1);
            dNdyErr = fitResultDnDyBootstrap->GetParameter(2);
            cout << "dNdy: " << dNdy << " dNdyAvg: " << dNdyAvg << " +/- " << dNdyErr/dNdyAvg*100.0 << "%" << endl;
            if(m_currentCharge == 1){
              m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdyAvg);
              m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdyErr);
              m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
              m_nominalFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
              m_bootstrapData_Nom_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
              //m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSNow);
            }else{
              m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdyAvg);
              m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdyErr);
              m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
              m_nominalFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
              m_bootstrapData_Nom_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
              //m_BetaS_Minus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSFinal);
            }//is plus minus
          }else{
            cout << "Error: dN/dy Bootstrap Failed! " << endl;
            dNdyAvg = fitResultDnDyBootstrap->GetParameter(1);
            dNdyErr = fitResultDnDyBootstrap->GetParameter(2);
            if(m_currentCharge == 1){
              m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, 0.0);
              m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,0.0);
              m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
              m_nominalFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
              m_bootstrapData_Nom_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
              //m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSNow);
            }else{
              m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, 0.0);
              m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,0.0);
              m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
              m_nominalFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
              m_bootstrapData_Nom_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
              //m_BetaS_Minus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSFinal);
            }//is plus minus




          }
        }//rap loop

        continue;
      }






      //#######   CREATE BETA_S HISTOGRAM AND FIT TO CONSTRAIN THE PARAMETERS  ##########

      TH1D* currentBetaSHisto = NULL;
      if(m_currentCharge == 1){
        currentBetaSHisto = m_BetaS_Plus_Nominal[m_currentCentIndex];
      }else{
        currentBetaSHisto = m_BetaS_Minus_Nominal[m_currentCentIndex];
      }
      const double* initailFitParams = m_minimizer->X();
      for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size(); iii++){
        double beta_s_temp = initailFitParams[2*iii+1];
        double beta_s_error_temp = sqrt( m_minimizer->CovMatrix(2*iii+1, 2*iii+1) );
        cout << "reading out BetaS for y=" << m_liveRapidityProtonSpectra[iii] << "   " << beta_s_temp << " +/- " << beta_s_error_temp << endl;
        currentBetaSHisto->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,beta_s_temp);
        currentBetaSHisto->SetBinError(m_liveRapidityProtonSpectra[iii]+1,beta_s_error_temp);
      }


      TF1* flatTopFunct = new TF1("flatTopFunct", "[0]*pow(x-[1], 2.0) + [2]*pow(x-[1], 4.0) + [3]", a_lowRapBound_BetaS_Constraint, a_highRapBound_BetaS_Constraint);
      flatTopFunct->SetParameter(0,-0.2);
      flatTopFunct->SetParLimits(0,-10.0,0.0);
      flatTopFunct->FixParameter(1,m_cuts->getYCM());
      flatTopFunct->SetParameter(2,-0.2);
      flatTopFunct->SetParLimits(2,-10.0,0.0);
      flatTopFunct->SetParameter(3,currentBetaSHisto->GetBinContent(currentBetaSHisto->FindBin(m_cuts->getYCM())));
      flatTopFunct->SetParLimits(3,0.0,1.0);
      int status_betaS = currentBetaSHisto->Fit("flatTopFunct","E","", a_lowRapBound_BetaS_Constraint, a_highRapBound_BetaS_Constraint);
      TF1* fitResult_BetaS = currentBetaSHisto->GetFunction("flatTopFunct");

      cout << "Done With BetaS Parabola Fit" << endl;
      fittingCanvas->cd();
      gPad->SetLogy(false);
      currentBetaSHisto->Draw("E");
      fittingCanvas->SaveAs(Form("%s/%s/FixedBetaS_Fit_Cent%02d.png",m_imageDir.c_str(),m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));

      if(!fitResult_BetaS){
        cout << " Fitting of Beta_S to Constrain Failed " << endl << "  Cannot Continue... " << endl;
        continue;
      }else{
        cout << " BetaS Fit Result Exists" << endl;
      }

      if(m_constrainAntiProtonBetaS_withParamsFromProtons && m_currentCharge == -1){
        fitResult_BetaS = m_BetaS_Plus_Nominal[m_currentCentIndex]->GetFunction("flatTopFunct");
      }

      //##### CREATE A NEW MINIMIZER #################
      //bc you cant use setVariableValue after minimization?
      m_minimizer = ROOT::Math::Factory::CreateMinimizer();
      m_minimizer->SetFunction(*m_chiSqrdFunctor);
      for(int iii = 0; iii < 2*m_liveRapidityProtonSpectra.size(); iii+=2 ){
        double rapidity = currentBetaSHisto->GetBinCenter(m_liveRapidityProtonSpectra[iii/2]+1);
        double betaSNowFixed = fitResult_BetaS->Eval(rapidity);

        if(betaSNowFixed <= 0.0) betaSNowFixed = 0.0;
         m_minimizer->SetVariable(iii, Form("A_%02d",m_liveRapidityProtonSpectra[iii/2]), finalParams_RoundOne[iii], 0.1*finalParams_RoundOne[iii]);
         m_minimizer->SetVariableLimits(iii, 0.01*finalParams_RoundOne[iii], finalParams_RoundOne[iii]*100.0);
         m_minimizer->SetVariable(iii+1, Form("Beta_S_%02d", m_liveRapidityProtonSpectra[iii/2]), betaSNowFixed, 0.1);
         m_minimizer->FixVariable(iii+1);
      }
      double theLastTemp = finalParams_RoundOne[2*m_liveRapidityProtonSpectra.size()];
      m_minimizer->SetVariable(2*m_liveRapidityProtonSpectra.size(), "T" ,theLastTemp, 0.1);
      m_minimizer->SetVariableLimits(2*m_liveRapidityProtonSpectra.size() ,0.6*theLastTemp, 1.4*theLastTemp);
      m_minimizer->SetPrintLevel(5);
      m_minimizer->SetMaxIterations(3000);
      m_minimizer->SetMaxFunctionCalls(100000);

      /*//Fix the BetaS Parameters
      for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size(); iii++){
        double rapidity = currentBetaSHisto->GetBinCenter(m_liveRapidityProtonSpectra[iii]+1);
        cout << " Rapidity: " << rapidity << endl;
        double betaSNowFixed = fitResult_BetaS->Eval(rapidity);
        cout << "constrainedBeta = " << betaSNowFixed << endl;
        if(m_minimizer){
          cout << "Minimizer exists with " << m_minimizer->NDim() << endl;
        }else{
          cout << "Minimizer doesn't exist" << endl;
        }
        m_minimizer->SetVariableValue((2*iii)+1,betaSNowFixed);
        cout << "setting variable " << 2*iii+1 << endl;
        m_minimizer->FixVariable(2*iii+1);
        cout << " Fixing Variable " << 2*iii+1 << " " << Form("Beta_S_%02d", m_liveRapidityProtonSpectra[iii]) <<  " to " << betaSNowFixed << endl;
      }

      //fix temperature
      cout << "Fixing Temperature Varaible Num: " << 2*m_liveRapidityProtonSpectra.size() << endl;
      m_minimizer->FixVariable(2*m_liveRapidityProtonSpectra.size());
      //m_minimizer->FixVariable(m_liveRapidityProtonSpectra.size()+1);

      cout << "Fixed the temperature and all of the surface velocities (BetaS) " << endl;
      */

      //###### FIT Just the amplitudes #########
      m_minimizer->SetValidError(true);
      m_minimizer->Minimize();
      status = m_minimizer->Status();
      if(status == 0){
        cout << "Proton Fit Status Successful with Status = 0 " << endl;
      }else{
        cout << "############!!!!!!!!!!!#############  Second Pass Fit:   STATUS OF FIT = " << status << "   IS BAD!!!!!  ############!!!!!!!!!!##########";
        continue;
      }

      const double* finalParams = m_minimizer->X();
      double tempFinal = finalParams[2*m_liveRapidityProtonSpectra.size()];
      double tempFinalErr = sqrt( m_minimizer->CovMatrix(2*m_liveRapidityProtonSpectra.size(),2*m_liveRapidityProtonSpectra.size()) );
      cout << " ptrs: " << m_Proton_Temp_Plus_Nom << "   " << m_Proton_Temp_Minus_Nom << endl;
      if(!std::isnan(tempFinal) && !std::isnan(tempFinalErr)){
        if(m_currentCharge == 1){
          m_Proton_Temp_Plus_Nom->SetBinContent(m_currentCentIndex+1,tempFinal);
          m_Proton_Temp_Plus_Nom->SetBinError(m_currentCentIndex+1,tempFinalErr);
        }else{
          m_Proton_Temp_Minus_Nom->SetBinContent(m_currentCentIndex+1,tempFinal);
          m_Proton_Temp_Minus_Nom->SetBinError(m_currentCentIndex+1,tempFinalErr);
        }
      }

      cout << "Final Temperature: " << tempFinal << endl;
      //cout << "Final Beta_S: " << betaSFinal << endl;

      cout << "######################################################################" << endl;
      cout << "          STAGE 3   Proton Fitting - Bootstrap Individual Amplitudes" << endl;


      for(int iii = 0; iii < m_liveRapidityProtonSpectra.size(); iii++){
        double Amp = finalParams[2*iii];
        double AmpErr = sqrt( m_minimizer->CovMatrix(2*iii,2*iii) );
        double rapidity = currentBetaSHisto->GetBinCenter(m_liveRapidityProtonSpectra[iii]+1);
        double betaSNow = fitResult_BetaS->Eval(rapidity);
        cout << "Ready for bootstraper: Amp: " << Amp << " AmpErr: " << AmpErr << " Rap: " << rapidity << " BetaS: " << betaSNow << " Temp: " << tempFinal << endl;
        TF1* fitFunct = new TF1(
          Form("NominalFit_Cent%02d_yIndex%02d_blastwave",m_currentCentIndex,m_liveRapidityProtonSpectra[iii]),
          this,&SpectraFitter::blastWaveModelFit,0,10,6,"SpectraFitter","blastWaveModelFit");
        fitFunct->SetParNames("A","T_kin","#beta_S","W","R","m_p");
        fitFunct->SetParameter(0,Amp);
        fitFunct->SetParError(0,AmpErr);
        fitFunct->SetParameter(1,tempFinal);
        fitFunct->SetParameter(2,betaSNow);
        fitFunct->FixParameter(3,0.5);
        fitFunct->FixParameter(4,1.0);
        fitFunct->SetParameter(5,m_partInfo->GetParticleMass(2));

        TCanvas *protonFinalCanvas = new TCanvas();

        protonFinalCanvas->SetLogy();
        if(pmIndex == 0) m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]]->Draw("AP");
        else if(pmIndex == 1) m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]]->Draw("AP");
        fitFunct->Draw("SAME");

        protonFinalCanvas->SaveAs(Form("%s/%s/FinalFit_Nom_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_liveRapidityProtonSpectra[iii]));

        delete protonFinalCanvas;


        double dNdy = 0;
        double dNdyAvg = 0;
        double dNdyErr = 0;
        //double &a_integral, double &a_avgIntegral, double &a_integralError,TF1* a_fitFunction, TFitResult* a_fitResult, double a_mass, int a_parameterToVary,int a_numTrials, double a_paramError,double a_lowIntegralBound, double a_highIntegralBound
        vector< double > integralListNom = FitUtilities::bootstrapIntegralSingleParameter(dNdy,dNdyAvg, dNdyErr, fitFunct, NULL, protonMass,0, a_numTrialsForDnDyBootstrap, AmpErr);
        double smallest = *min_element(integralListNom.begin(), integralListNom.end());
        double biggest = *max_element(integralListNom.begin(), integralListNom.end());
        TH1D* integralHistoryHisto_Nom = new TH1D("paramHisto","Sampled Integrals; Integral Value;Counts",100,0.98*smallest, 1.02*biggest);
        for(int iii = 0; iii < (int) integralListNom.size(); iii++) integralHistoryHisto_Nom->Fill(integralListNom[iii]);
        integralHistoryHisto_Nom->SetName(Form("dNdy_Nom_History_%s_Cent%02d_Rap%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_liveRapidityProtonSpectra[iii]));
        HistogramUtilities::makeSqrtNErrors(integralHistoryHisto_Nom);
        m_gausFunct->SetRange(integralHistoryHisto_Nom->GetBinLowEdge(1),integralHistoryHisto_Nom->GetBinLowEdge(integralHistoryHisto_Nom->GetNbinsX()+1));
        double mean = integralHistoryHisto_Nom->GetMean();
        double stdDev = integralHistoryHisto_Nom->GetStdDev();
        double counts = integralHistoryHisto_Nom->GetBinContent(integralHistoryHisto_Nom->FindBin(mean))*stdDev/0.3989422804;
        m_gausFunct->SetParameter(0,counts);
        m_gausFunct->SetParLimits(0,0.5*counts,2.0*counts);
        m_gausFunct->SetParameter(1,mean);
        m_gausFunct->SetParLimits(1,integralHistoryHisto_Nom->GetBinLowEdge(1),integralHistoryHisto_Nom->GetBinLowEdge(integralHistoryHisto_Nom->GetNbinsX()+1));
        m_gausFunct->SetParameter(2,stdDev);
        m_gausFunct->SetParLimits(2,0.5*stdDev,2.0*stdDev);
        int statusDnDy = integralHistoryHisto_Nom->Fit("m_gausFunct","EQ");
        TF1* fitResultDnDyBootstrap = integralHistoryHisto_Nom->GetFunction("m_gausFunct");
        if(fitResultDnDyBootstrap &&!std::isnan(fitResultDnDyBootstrap->GetParameter(1)) && !std::isnan(fitResultDnDyBootstrap->GetParameter(2)) ){

          dNdyAvg = fitResultDnDyBootstrap->GetParameter(1);
          dNdyErr = fitResultDnDyBootstrap->GetParameter(2);
          cout << "dNdy: " << dNdy << " dNdyAvg: " << dNdyAvg << " +/- " << dNdyErr/dNdyAvg*100.0 << "%" << endl;
          if(m_currentCharge == 1){
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdyAvg);
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdyErr);
            m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
            m_nominalFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
            m_bootstrapData_Nom_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
            //m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSNow);
          }else{
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdyAvg);
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdyErr);
            m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
            m_nominalFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
            m_bootstrapData_Nom_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
            //m_BetaS_Minus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSFinal);
          }//is plus minus
        }else{
          cout << "Error: dN/dy Bootstrap Failed! " << endl;
          dNdyAvg = fitResultDnDyBootstrap->GetParameter(1);
          dNdyErr = fitResultDnDyBootstrap->GetParameter(2);
          if(m_currentCharge == 1){
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, 0.0);
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,0.0);
            m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
            m_nominalFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
            m_bootstrapData_Nom_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
            //m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSNow);
          }else{
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, 0.0);
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,0.0);
            m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
            m_nominalFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
            m_bootstrapData_Nom_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
            //m_BetaS_Minus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSFinal);
          }//is plus minus




        }
      }//rap loop
    }// pm index
  }// cent index

}

//################################################################

void SpectraFitter::fitProtonSpectraFXT_betaConstr(bool a_constrainBetaS, int a_numTrialsForDnDyBootstrap, double a_lowRapBound_BetaS_Constraint, double a_highRapBound_BetaS_Constraint){
  cout << "#####################  Starting SpectraFitter::fitProtonSpectra() ########################" << endl;
  TVirtualFitter::SetMaxIterations( 1000000 );
  m_currentPartIndex = 2;
  bool useAvgParamsForSeparateFits = true;

  TCanvas* fittingCanvas = new TCanvas("fittingCanvas_Proton","Fitting Canvas");
  fittingCanvas->SetWindowSize(1300,700);
  fittingCanvas->SetCanvasSize(1200,600);
  double protonMass = m_partInfo->GetParticleMass(m_currentPartIndex);
  for(unsigned int centIndex = 0; centIndex < 16; centIndex++){
    m_currentCentIndex = centIndex;
    for(int pmIndex = 0; pmIndex < 2; pmIndex++){
      m_currentCharge = 1;
      if(pmIndex == 1) m_currentCharge = -1;

      m_liveRapidityProtonSpectra.clear();
      double ampWeight = 0.0;
      double avgAmpFirst = 0.0;
      double tempWeight = 0.0;
      double avgTempFirst = 0.0;
      double avgBetaSFirst = 0.0;
      double betaSWeight = 0.0;
      double avgNFirst = 0.0;
      double nWeight = 0.0;
      vector< double > ampStorage;
      vector< double > tempStorage;
      vector< double > betaSStorage;

      double ampWeight_sys = 0.0;
      double avgAmpFirst_sys = 0.0;
      double tempWeight_sys = 0.0;
      double avgTempFirst_sys = 0.0;
      vector< double > ampStorage_sys;
      vector< double > tempStorage_sys;

      //Fit with single blastwaves first
      m_protonFittingStage = 1;
      m_isTemperatureConstrained = false;
      int counter = 0;
      for(unsigned int yIndex = 0; yIndex < m_cuts->getRapMtM0BinStructure(m_currentPartIndex, 1)->GetNbinsX(); yIndex++){
        m_currentRapValue = m_cuts->getRapMtM0BinStructure(m_currentPartIndex, 1)->GetBinCenter(yIndex+1);
        m_currentRapIndex = yIndex;
        TGraphErrors* specPM[2];
        specPM[0] = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][yIndex];
        specPM[1] = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][yIndex];
        if( !specPM[pmIndex] || specPM[pmIndex]->GetN() <= 4 ) continue; //############################################   MUST BE SAME AS ABOVE! ###################################
        m_liveRapidityProtonSpectra.push_back(yIndex);
        m_liveRapidityValueProtonSpectra.push_back(m_currentRapValue);
        cout << "Proton Fitting: Cent " << m_currentCentIndex << " yIndex " << yIndex
             << " charge: " << m_currentCharge << " ptr: " << specPM[pmIndex] << " charge: " << m_currentCharge
             << " N: " << specPM[pmIndex]->GetN() <<  endl;

        //##########  FIT WITH NOMINAL FIT FUNCTION ##########
        m_isCurrentFitNominal = true;
        m_currentSpectra = (TGraphErrors*) specPM[pmIndex]->Clone();
        init_blastWave();
        init_thermal();

        //cout << " Fixing Beta_S to 0.4 for initial fit..." << endl;
        //m_blastWave->FixParameter(2,0.4);
        m_blastWave->SetParameter(2,0.4);
        m_blastWave->SetParLimits(2,0.2,0.8);

        TF1* initial_BW_fit = new TF1(
          Form("InitFit_%s_Cent%02d_yIndex%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_currentRapIndex),
          this,&SpectraFitter::blastWaveModelFit,0,10,6,"SpectraFitter","blastWaveModelFit");
        initial_BW_fit->SetParNames("A","T_kin","#beta_S","W","R","m_p");
        initial_BW_fit->SetParameter(0,m_blastWave->GetParameter(0));
        initial_BW_fit->SetParameter(1,m_blastWave->GetParameter(1));
        initial_BW_fit->SetParameter(2,m_blastWave->GetParameter(2));
        if(SpectraFitter::getBlastWaveNFix() > 0) initial_BW_fit->FixParameter(3,SpectraFitter::getBlastWaveNFix());
        else initial_BW_fit->FixParameter(3,0.5);
        initial_BW_fit->FixParameter(4,m_blastWave->GetParameter(4));
        initial_BW_fit->SetParameter(5,m_blastWave->GetParameter(5));


        initial_BW_fit->SetLineColor(kYellow);
        int status = m_currentSpectra->Fit("m_blastWave","EV EX0","",0,10);
        TF1* fitResult = m_currentSpectra->GetFunction("m_blastWave");

        if(fitResult){
          ampWeight += 1.0 / (fitResult->GetParError(0)*fitResult->GetParError(0));
          avgAmpFirst += 1.0 / (fitResult->GetParError(0)*fitResult->GetParError(0)) * fitResult->GetParameter(0);
          tempWeight += 1.0 / (fitResult->GetParError(1)*fitResult->GetParError(1));
          avgTempFirst += 1.0 / (fitResult->GetParError(1)*fitResult->GetParError(1)) * fitResult->GetParameter(1);
          betaSWeight += 1.0 / (fitResult->GetParError(2)*fitResult->GetParError(2));
          avgBetaSFirst += 1.0 / (fitResult->GetParError(2)*fitResult->GetParError(2)) * fitResult->GetParameter(2);
          nWeight += 1.0/ (fitResult->GetParError(3)*fitResult->GetParError(3));
          avgNFirst += 1.0 / (fitResult->GetParError(3)*fitResult->GetParError(3)) * fitResult->GetParameter(3);

          ampStorage.push_back(fitResult->GetParameter(0));
          tempStorage.push_back(fitResult->GetParameter(1));
          betaSStorage.push_back(fitResult->GetParameter(2));

        }else{
          ampStorage.push_back(-1);
          tempStorage.push_back(-1);
          betaSStorage.push_back(-1);
        }

        //make the fit image
        fittingCanvas->cd();
        double smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
        double largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
        if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
        frame->SetTitle(Form("p^{%s} Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
                    m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
                    m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
        //frame->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
        //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame->GetXaxis()->SetTitle("m_{T}-m_{p} (GeV/c^{2})");
        frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);
        initial_BW_fit->Draw("same");
        m_currentSpectra->Draw("P");
        fittingCanvas->Update();
        fittingCanvas->SaveAs(Form("%s/%s/FirstFit_Nom_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));
        //delete m_currentSpectra;
        //delete initial_BW_fit;


        fittingCanvas->Clear();

        double thermalHighmTm0 = m_currentSpectra->GetX()[3]+m_currentSpectra->GetErrorX(3);

        TF1* initial_thermal_fit = new TF1(
          Form("InitFit_Sys_%s_Cent%02d_yIndex%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_currentRapIndex),
          "[0] * (x+[2]) * exp(-x/[1]) / ((2*3.14159265) * [1] * ([2]*[2] + 2*[2]*[1] + 2*[1]*[1]))",0,thermalHighmTm0);
        initial_thermal_fit->SetParNames("dN/dy","T","m");
        initial_thermal_fit->SetParameter(0,m_blastWave->GetParameter(0));
        initial_thermal_fit->SetParameter(1,m_blastWave->GetParameter(1));
        initial_thermal_fit->FixParameter(2,m_partInfo->GetParticleMass(m_currentPartIndex));


        initial_thermal_fit->SetLineColor(kYellow);
        int status_sys = m_currentSpectra->Fit("m_thermal","EV EX0","",0,thermalHighmTm0);
        TF1* fitResult_sys = m_currentSpectra->GetFunction("m_thermal");


        if(fitResult_sys){
          ampWeight_sys += 1.0 / (fitResult_sys->GetParError(0)*fitResult_sys->GetParError(0));
          avgAmpFirst_sys += 1.0 / (fitResult_sys->GetParError(0)*fitResult_sys->GetParError(0)) * fitResult_sys->GetParameter(0);
          tempWeight_sys += 1.0 / (fitResult_sys->GetParError(1)*fitResult_sys->GetParError(1));
          avgTempFirst_sys += 1.0 / (fitResult_sys->GetParError(1)*fitResult_sys->GetParError(1)) * fitResult_sys->GetParameter(1);

          ampStorage_sys.push_back(fitResult_sys->GetParameter(0));
          tempStorage_sys.push_back(fitResult_sys->GetParameter(1));

        }else{
          ampStorage_sys.push_back(-1);
          tempStorage_sys.push_back(-1);
        }

        //double smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
        //double largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
        //if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame_sys = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
        frame_sys->SetTitle(Form("p^{%s} Systematic Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
                    m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
                    m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
        //frame->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
        //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame_sys->GetXaxis()->SetTitle("m_{T}-m_{p} (GeV/c^{2})");
        frame_sys->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);
        initial_thermal_fit->Draw("same");
        //m_currentSpectra->GetFunction("m_blastWave")->SetBit(TF1::kNotDraw);
        m_currentSpectra->Draw("P");
        fittingCanvas->Update();
        fittingCanvas->SaveAs(Form("%s/%s/FirstFit_Sys_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));


        if(!fitResult) cout << "No Fit Result: yindex: " << yIndex << endl;
        if(!fitResult_sys) cout << "No Fit Result Sys: yindex: " << yIndex << endl;
        counter++;
      }

      avgAmpFirst = avgAmpFirst/ampWeight;
      avgTempFirst = avgTempFirst/tempWeight;
      avgBetaSFirst = avgBetaSFirst/betaSWeight;
      avgNFirst = avgNFirst/nWeight;

      if(std::isnan(avgBetaSFirst)) avgBetaSFirst = 0.5;

      cout << " AvgAmp: " << avgAmpFirst << "  AvgTemp: " << avgTempFirst << "  AvgBetsS: " << avgBetaSFirst << endl;

      avgAmpFirst_sys = avgAmpFirst_sys/ampWeight_sys;
      avgTempFirst_sys = avgTempFirst_sys/tempWeight_sys;

      TCanvas *fitParsCanvas = new TCanvas("fitParsCanvas","Fit Parameters Canvas");
      fitParsCanvas->SetWindowSize(1300,700);
      fitParsCanvas->SetCanvasSize(1200,600);

      TGraph *temp_init_nom = new TGraph(m_liveRapidityValueProtonSpectra.size(),&m_liveRapidityValueProtonSpectra[0],&tempStorage[0]);
      temp_init_nom->SetTitle("Temp Nominal Initial Values");
      temp_init_nom->GetXaxis()->SetTitle("y_{lab}");
      temp_init_nom->GetYaxis()->SetTitle("Temp (GeV)");
      temp_init_nom->SetMarkerStyle(20);
      temp_init_nom->Draw("AP");

      fitParsCanvas->SaveAs(Form("%s/%s/tempInit_Nom_Cent%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));

      TGraph *beta_init_nom = new TGraph(m_liveRapidityValueProtonSpectra.size(),&m_liveRapidityValueProtonSpectra[0],&betaSStorage[0]);
      beta_init_nom->SetTitle("#beta_{S} Nominal Initial Values");
      beta_init_nom->GetXaxis()->SetTitle("y_{lab}");
      beta_init_nom->GetYaxis()->SetTitle("#beta_{S}");
      beta_init_nom->SetMarkerStyle(20);
      beta_init_nom->Draw("AP");

      fitParsCanvas->SaveAs(Form("%s/%s/betaInit_Nom_Cent%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));

      fitParsCanvas->Clear();

      TGraph *temp_init_sys = new TGraph(m_liveRapidityValueProtonSpectra.size(),&m_liveRapidityValueProtonSpectra[0],&tempStorage_sys[0]);
      temp_init_sys->SetTitle("Temp Systematic Initial Values");
      temp_init_sys->GetXaxis()->SetTitle("y_{lab}");
      temp_init_sys->GetYaxis()->SetTitle("Temp (GeV)");
      temp_init_sys->SetMarkerStyle(20);

      fitParsCanvas->Clear();

      TF1 *temp_fitInit_sys = new TF1("temp_fitInit_sys","[0]/TMath::CosH([2]*(x-[1]))",-2,2);
      temp_fitInit_sys->SetParameters(0.1,m_cuts->getYCM(),1.0);
      temp_fitInit_sys->FixParameter(1,m_cuts->getYCM());
      temp_fitInit_sys->SetParLimits(0,0.01,0.3);

      temp_init_sys->Fit(temp_fitInit_sys);
      temp_init_sys->Draw("AP");
      temp_fitInit_sys->Draw("Same");


      fitParsCanvas->SaveAs(Form("%s/%s/tempInit_Sys_Cent%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));

      fitParsCanvas->Clear();

      //setup minimizer
      int numSpectraToFit = (int) m_liveRapidityProtonSpectra.size();
      //systematic fitting
      m_minimizer_sys = ROOT::Math::Factory::CreateMinimizer();
      m_chiSqrdFunctor_sys = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_thermal_FXT_ChiSqr,(numSpectraToFit) + 3);
      cout << "created chi squared sys functor with NDim " << m_chiSqrdFunctor_sys->NDim() << "  functor: " << &SpectraFitter::simultaneous_thermal_FXT_ChiSqr  << endl;
      m_minimizer_sys->SetFunction(*m_chiSqrdFunctor_sys);
      for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size(); iii++){
        if(useAvgParamsForSeparateFits){
          m_minimizer_sys->SetVariable(iii, Form("dNdy_sys_%02d",m_liveRapidityProtonSpectra[iii]), avgAmpFirst_sys , 0.1*avgAmpFirst_sys);
          m_minimizer_sys->SetVariableLimits(iii, 0.0, avgAmpFirst_sys*10000.0);
        }else{
          m_minimizer_sys->SetVariable(iii, Form("dNdy_sys_%02d",m_liveRapidityProtonSpectra[iii]), ampStorage_sys[iii] , 0.1*ampStorage_sys[iii]);
          m_minimizer_sys->SetVariableLimits(iii, 0.0, ampStorage_sys[iii]*10000.0);
        }
      }

      m_minimizer_sys->SetVariable(counter, "Amp_T_sys" ,temp_fitInit_sys->GetParameter(0), 0.01);
      m_minimizer_sys->SetVariableLimits(counter,0.0001, 0.3);
      m_minimizer_sys->SetVariable(counter+1, "Mu_T_sys" ,m_cuts->getYCM(), 0.2);
      m_minimizer_sys->FixVariable(counter+1);
      m_minimizer_sys->SetVariable(counter+2, "Sigma_T_sys" ,temp_fitInit_sys->GetParameter(2), 2.0);
      m_minimizer_sys->SetVariableLimits(counter+2,0.0, 2.0);




      cout << "######################################################################" << endl;
      cout << "          STAGE 2   Proton Sys Fitting - Use Separate Rap Fit Results as Seeds to Simultaneous Fitter" << endl;
      //m_blastWave->SetParLimits(2,0.0,1.0);
      m_protonFittingStage = 2;
      //init_simul_blastWave();  //only do this if not initialized by single fits above
      m_minimizer_sys->SetPrintLevel(5);
      m_minimizer_sys->SetMaxIterations(3000);
      m_minimizer_sys->SetMaxFunctionCalls(200000);
      m_minimizer_sys->SetValidError(true);
      m_minimizer_sys->Minimize();
      int status_sys = m_minimizer_sys->Status();
      const double* finalParams_sys = m_minimizer_sys->X();
      if(status_sys == 0){
        cout << "Proton Sys Fit Status: " << status_sys << endl;
      }
      else{
        cout << "################################  First Pass Fit:  STATUS OF SYS FIT = " << status_sys << "   IS BAD!!!!!  ################################" << endl;
        cout << "Current Parameters: " << endl;
        for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size() + 3; iii++){
          cout << "  " << finalParams_sys[iii];
        }
        cout << endl;
        continue;
      }


            cout << "######################################################################" << endl;
      cout << "          STAGE 3   Proton Fitting Sys - Bootstrap Individual Amplitudes" << endl;


      for(int iii = 0; iii < m_liveRapidityProtonSpectra.size(); iii++){

        double rapidity = m_liveRapidityValueProtonSpectra[iii];

        TGraphErrors* spectrum = NULL;
        if(m_currentCharge == 1) spectrum = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]];
        else spectrum = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]];

        double dNdy_sys = finalParams_sys[iii];
        double dNdy_err_sys = sqrt( m_minimizer_sys->CovMatrix(iii,iii) );

        double temp_sys = finalParams_sys[m_liveRapidityProtonSpectra.size()]/TMath::CosH(finalParams_sys[m_liveRapidityProtonSpectra.size() + 2]*(rapidity - finalParams_sys[m_liveRapidityProtonSpectra.size()+1]));

        double tempErr_sys = sqrt( pow(temp_sys*m_minimizer_sys->CovMatrix(m_liveRapidityProtonSpectra.size(),m_liveRapidityProtonSpectra.size())/finalParams_sys[m_liveRapidityProtonSpectra.size()],2) + pow(temp_sys*m_minimizer_sys->CovMatrix(m_liveRapidityProtonSpectra.size()+2,m_liveRapidityProtonSpectra.size()+2)*TMath::TanH(finalParams_sys[m_liveRapidityProtonSpectra.size()+2]*(rapidity - finalParams_sys[m_liveRapidityProtonSpectra.size()+1]))*(rapidity - finalParams_sys[m_liveRapidityProtonSpectra.size()+1]),2) );

        double thermalHighmTm0 = spectrum->GetX()[3]+spectrum->GetErrorX(3);


        TF1* fitFunct_sys = new TF1(
          Form("SystematicFit_Cent%02d_yIndex%02d",m_currentCentIndex,m_liveRapidityProtonSpectra[iii]),
          "[0] * (x+[2]) * exp(-x/[1]) / ((2*3.14159265) * [1] * ([2]*[2] + 2*[2]*[1] + 2*[1]*[1]))",0.0,thermalHighmTm0);
        fitFunct_sys->SetParNames("dN/dy","T","m");
        fitFunct_sys->SetParameter(0,dNdy_sys);
        fitFunct_sys->SetParError(0,dNdy_err_sys);
        fitFunct_sys->SetParameter(1,temp_sys);
        fitFunct_sys->SetParError(1,tempErr_sys);
        fitFunct_sys->FixParameter(2,m_partInfo->GetParticleMass(m_currentPartIndex));




        TCanvas *finalCanvas = new TCanvas("finalCanvas","Final Canvas");
        finalCanvas->SetWindowSize(1300,700);
        finalCanvas->SetCanvasSize(1200,600);

        finalCanvas->cd();

        double smallYVal =  HistogramUtilities::findSmallestYVal(spectrum)*0.25;
        double largeXVal =  HistogramUtilities::findLargestXVal(spectrum)*1.3;
        if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame_sys = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(spectrum)*4.0);
        frame_sys->SetTitle(Form("p^{%s} Systematic Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
          m_cuts->getRapidityRangeLow(m_liveRapidityProtonSpectra[iii],m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(m_liveRapidityProtonSpectra[iii],m_currentPartIndex,1),
          m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
          //frame->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
          //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame_sys->GetXaxis()->SetTitle("m_{T}-m_{p} (GeV/c^{2})");
        frame_sys->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);

        spectrum->SetMarkerStyle(20);
        spectrum->Draw("P");
        fitFunct_sys->Draw("same");

        TPaveText *fitParsTxt_sys = new TPaveText(0.65,0.15,0.95,0.85,"NDC");
        fitParsTxt_sys->AddText(Form("dN/dy \t %f#pm%f",dNdy_sys,dNdy_err_sys));
        fitParsTxt_sys->AddText(Form("T \t %f#pm%f",temp_sys,tempErr_sys));
        fitParsTxt_sys->AddText(Form("m \t %f",m_partInfo->GetParticleMass(m_currentPartIndex)));

        fitParsTxt_sys->SetFillStyle(0);
        fitParsTxt_sys->SetBorderSize(5);

        fitParsTxt_sys->Draw("same");

        finalCanvas->Update();
        finalCanvas->SaveAs(Form("%s/%s/FinalFit_Sys_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
          m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_liveRapidityProtonSpectra[iii]));



        if(m_currentCharge == 1){

          m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdy_sys);
          m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdy_err_sys);

          m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,temp_sys);
          m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,tempErr_sys);

          m_systematicFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct_sys;

        }else{

          m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdy_sys);
          m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdy_err_sys);

          m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,temp_sys);
          m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,tempErr_sys);

          m_systematicFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct_sys;
        }//is plus minus

      }//rap loop



      //nominal fitting
      m_minimizer = ROOT::Math::Factory::CreateMinimizer();
      m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_blastWave_betaConstr_ChiSqr,(numSpectraToFit) + 6);
      cout << "created chi squared functor with NDim " << m_chiSqrdFunctor->NDim() << "  functor: " << &SpectraFitter::simultaneous_blastWave_betaConstr_ChiSqr  << endl;
      m_minimizer->SetFunction(*m_chiSqrdFunctor);
      for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size(); iii++){
        if(useAvgParamsForSeparateFits){
          m_minimizer->SetVariable(iii, Form("A_%02d",m_liveRapidityProtonSpectra[iii]), avgAmpFirst , 0.1*avgAmpFirst);
          m_minimizer->SetVariableLimits(iii, 0.0, avgAmpFirst*10000.0);
        }else{
          m_minimizer->SetVariable(iii, Form("A_%02d",m_liveRapidityProtonSpectra[iii]), ampStorage[iii] , 0.1*ampStorage[iii]);
          m_minimizer->SetVariableLimits(iii, 0.0, ampStorage[iii]*10000.0);
        }
      }

      m_minimizer->SetVariable(counter, "T" ,avgTempFirst, 0.15);
      m_minimizer->SetVariableLimits(counter,0.0, 2.0);
      m_minimizer->SetVariable(counter+1,"beta_p4",-0.2,0.15);
      m_minimizer->SetVariableLimits(counter+1,-10.0,0.0);
      m_minimizer->SetVariable(counter+2,"beta_shift",m_cuts->getYCM(),0.15);
      m_minimizer->FixVariable(counter+2);
      //test ben
      m_minimizer->SetVariable(counter+3,"beta_p2",0.0,0.15);
      m_minimizer->SetVariableLimits(counter+3,0.0,0.0);
      m_minimizer->SetVariable(counter+4,"beta_const",avgBetaSFirst,0.05);
      m_minimizer->SetVariableLimits(counter+4,0.0,1.0);
      if(SpectraFitter::getBlastWaveNFix() > 0){
        m_minimizer->SetVariable(counter+5,"n",SpectraFitter::getBlastWaveNFix(),0.05);
        m_minimizer->FixVariable(counter+5);
      }else{
        m_minimizer->SetVariable(counter+5,"n",avgNFirst,0.05);
        m_minimizer->SetVariableLimits(counter+5,0.0,5.0);
      }









      cout << "######################################################################" << endl;
      cout << "          STAGE 2   Proton Fitting - Use Separate Rap Fit Results as Seeds to Simultaneous Fitter" << endl;
      m_blastWave->SetParLimits(2,0.0,1.0);
      m_protonFittingStage = 2;
      //init_simul_blastWave();  //only do this if not initialized by single fits above
      m_minimizer->SetPrintLevel(5);
      m_minimizer->SetMaxIterations(3000);
      m_minimizer->SetMaxFunctionCalls(200000);
      m_minimizer->SetValidError(true);
      m_minimizer->Minimize();
      int status = m_minimizer->Status();
      const double* finalParams_RoundOne = m_minimizer->X();
      if(status == 0){
        cout << "Proton Fit Status: " << status << endl;
      }
      else{
        cout << "################################  First Pass Fit:  STATUS OF FIT = " << status << "   IS BAD!!!!!  ################################" << endl;
        cout << "Current Parameters: " << endl;
        for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size() + 6; iii++){
          cout << "  " << finalParams_RoundOne[iii];
        }
        cout << endl;
        continue;
      }

      const double* finalParams = m_minimizer->X();
      double tempFinal = finalParams[m_liveRapidityProtonSpectra.size()];
      double tempFinalErr = sqrt( m_minimizer->CovMatrix(m_liveRapidityProtonSpectra.size(),m_liveRapidityProtonSpectra.size()) );
      cout << " ptrs: " << m_Proton_Temp_Plus_Nom << "   " << m_Proton_Temp_Minus_Nom << endl;
      if(!std::isnan(tempFinal) && !std::isnan(tempFinalErr)){
        if(m_currentCharge == 1){
          m_Proton_Temp_Plus_Nom->SetBinContent(m_currentCentIndex+1,tempFinal);
          m_Proton_Temp_Plus_Nom->SetBinError(m_currentCentIndex+1,tempFinalErr);
        }else{
          m_Proton_Temp_Minus_Nom->SetBinContent(m_currentCentIndex+1,tempFinal);
          m_Proton_Temp_Minus_Nom->SetBinError(m_currentCentIndex+1,tempFinalErr);
        }
      }

      cout << "Final Temperature: " << tempFinal << endl;
      //cout << "Final Beta_S: " << betaSFinal << endl;

      cout << "######################################################################" << endl;
      cout << "          STAGE 3   Proton Fitting - Bootstrap Individual Amplitudes" << endl;


      for(int iii = 0; iii < m_liveRapidityProtonSpectra.size(); iii++){
        double Amp = finalParams[iii];
        double AmpErr = sqrt( m_minimizer->CovMatrix(iii,iii) );
        double rapidity = m_liveRapidityProtonSpectra[iii];
        double betaSNow = finalParams[m_liveRapidityProtonSpectra.size()+1]*pow(m_liveRapidityValueProtonSpectra[iii]- finalParams[m_liveRapidityProtonSpectra.size()+2],4)+finalParams[m_liveRapidityProtonSpectra.size()+3]*pow(m_liveRapidityValueProtonSpectra[iii]- finalParams[m_liveRapidityProtonSpectra.size()+2],2)+finalParams[m_liveRapidityProtonSpectra.size()+4];
        double betaSNowError = sqrt(pow(m_liveRapidityValueProtonSpectra[iii]- finalParams[m_liveRapidityProtonSpectra.size()+2],8)*m_minimizer->CovMatrix(m_liveRapidityProtonSpectra.size()+1,m_liveRapidityProtonSpectra.size()+1)+pow(m_liveRapidityValueProtonSpectra[iii]- finalParams[m_liveRapidityProtonSpectra.size()+2],4)*m_minimizer->CovMatrix(m_liveRapidityProtonSpectra.size()+3,m_liveRapidityProtonSpectra.size()+3)+m_minimizer->CovMatrix(m_liveRapidityProtonSpectra.size()+4,m_liveRapidityProtonSpectra.size()+4)+pow(-4.0*finalParams[m_liveRapidityProtonSpectra.size()+1]*pow(m_liveRapidityValueProtonSpectra[iii]- m_liveRapidityProtonSpectra.size()+2,3)-2.0*finalParams[m_liveRapidityProtonSpectra.size()+3]*(m_liveRapidityValueProtonSpectra[iii]- finalParams[m_liveRapidityProtonSpectra.size()+2]),2)*m_minimizer->CovMatrix(m_liveRapidityProtonSpectra.size()+2,m_liveRapidityProtonSpectra.size()+2));
        cout << "Ready for bootstraper: Amp: " << Amp << " AmpErr: " << AmpErr << " Rap: " << rapidity << " BetaS: " << betaSNow << " Temp: " << tempFinal << endl;
        TF1* fitFunct = new TF1(
          Form("NominalFit_Cent%02d_yIndex%02d_blastwave",m_currentCentIndex,m_liveRapidityProtonSpectra[iii]),
          this,&SpectraFitter::blastWaveModelFit,0,10,6,"SpectraFitter","blastWaveModelFit");
        fitFunct->SetParNames("A","T_kin","#beta_S","W","R","m_p");
        fitFunct->SetParameter(0,Amp);
        fitFunct->SetParError(0,AmpErr);
        fitFunct->SetParameter(1,tempFinal);
        fitFunct->SetParameter(2,betaSNow);
        if(SpectraFitter::getBlastWaveNFix() > 0)fitFunct->FixParameter(3,SpectraFitter::getBlastWaveNFix());
        else{
          fitFunct->SetParameter(3,finalParams[m_liveRapidityProtonSpectra.size()+5]);
          fitFunct->SetParError(3,sqrt(m_minimizer->CovMatrix(m_liveRapidityProtonSpectra.size()+5,m_liveRapidityProtonSpectra.size()+5)));
        }
        fitFunct->FixParameter(4,1.0);
        fitFunct->SetParameter(5,m_partInfo->GetParticleMass(2));

        TCanvas *protonFinalCanvas = new TCanvas();
        protonFinalCanvas->SetWindowSize(1300,700);
        protonFinalCanvas->SetCanvasSize(1200,600);

        protonFinalCanvas->cd();

        double smallYVal;
        double largeXVal;
        if(pmIndex == 0){
          largeXVal =  HistogramUtilities::findLargestXVal(m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]])*1.3;
          smallYVal =  HistogramUtilities::findSmallestYVal(m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]])*0.25;
        }else if(pmIndex == 1){
          largeXVal =  HistogramUtilities::findLargestXVal(m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]])*1.3;
          smallYVal =  HistogramUtilities::findSmallestYVal(m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]])*0.25;
        }
        if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame_nom = protonFinalCanvas->DrawFrame(0.0,smallYVal,largeXVal,(pmIndex==0)?HistogramUtilities::findLargestYVal(m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]])*4.0:HistogramUtilities::findLargestYVal(m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]])*4.0);
        frame_nom->SetTitle(Form("p^{%s} Systematic Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
          m_cuts->getRapidityRangeLow(m_liveRapidityProtonSpectra[iii],m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(m_liveRapidityProtonSpectra[iii],m_currentPartIndex,1),
          m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
          //frame->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
          //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame_nom->GetXaxis()->SetTitle("m_{T}-m_{p} (GeV/c^{2})");
        frame_nom->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);

        protonFinalCanvas->SetLogy();
        if(pmIndex == 0) m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]]->Draw("AP");
        else if(pmIndex == 1) m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]]->Draw("AP");
        fitFunct->Draw("SAME");

        TPaveText *fitParsTxt = new TPaveText(0.65,0.15,0.95,0.85,"NDC");
        fitParsTxt->AddText(Form("A \t %f#pm%f",Amp,AmpErr));
        fitParsTxt->AddText(Form("T \t %f#pm%f",tempFinal,tempFinalErr));
        fitParsTxt->AddText(Form("#beta_{S} \t %f#pm%f",betaSNow,betaSNowError));
        if(SpectraFitter::getBlastWaveNFix() > 0)fitParsTxt->AddText(Form("n \t %f",SpectraFitter::getBlastWaveNFix()));
        else fitParsTxt->AddText(Form("n \t %f#pm%f",m_blastWave->GetParameter(3),m_blastWave->GetParError(3)));
        fitParsTxt->AddText(Form("R \t %f",1.0));
        fitParsTxt->AddText(Form("m \t %f",m_partInfo->GetParticleMass(m_currentPartIndex)));

        fitParsTxt->SetFillStyle(0);
        fitParsTxt->SetBorderSize(5);

        fitParsTxt->Draw("same");

        protonFinalCanvas->SaveAs(Form("%s/%s/FinalFit_Nom_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_liveRapidityProtonSpectra[iii]));

        delete protonFinalCanvas;


        double dNdy = 0;
        double dNdyAvg = 0;
        double dNdyErr = 0;
        //double &a_integral, double &a_avgIntegral, double &a_integralError,TF1* a_fitFunction, TFitResult* a_fitResult, double a_mass, int a_parameterToVary,int a_numTrials, double a_paramError,double a_lowIntegralBound, double a_highIntegralBound
        vector< double > integralListNom = FitUtilities::bootstrapIntegralSingleParameter(dNdy,dNdyAvg, dNdyErr, fitFunct, NULL, protonMass,0, a_numTrialsForDnDyBootstrap, AmpErr);
        double smallest = *min_element(integralListNom.begin(), integralListNom.end());
        double biggest = *max_element(integralListNom.begin(), integralListNom.end());
        TH1D* integralHistoryHisto_Nom = new TH1D("paramHisto","Sampled Integrals; Integral Value;Counts",100,0.98*smallest, 1.02*biggest);
        for(int iii = 0; iii < (int) integralListNom.size(); iii++) integralHistoryHisto_Nom->Fill(integralListNom[iii]);
        integralHistoryHisto_Nom->SetName(Form("dNdy_Nom_History_%s_Cent%02d_Rap%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_liveRapidityProtonSpectra[iii]));
        HistogramUtilities::makeSqrtNErrors(integralHistoryHisto_Nom);
        m_gausFunct->SetRange(integralHistoryHisto_Nom->GetBinLowEdge(1),integralHistoryHisto_Nom->GetBinLowEdge(integralHistoryHisto_Nom->GetNbinsX()+1));
        double mean = integralHistoryHisto_Nom->GetMean();
        double stdDev = integralHistoryHisto_Nom->GetStdDev();
        double counts = integralHistoryHisto_Nom->GetBinContent(integralHistoryHisto_Nom->FindBin(mean))*stdDev/0.3989422804;
        m_gausFunct->SetParameter(0,counts);
        m_gausFunct->SetParLimits(0,0.5*counts,2.0*counts);
        m_gausFunct->SetParameter(1,mean);
        m_gausFunct->SetParLimits(1,integralHistoryHisto_Nom->GetBinLowEdge(1),integralHistoryHisto_Nom->GetBinLowEdge(integralHistoryHisto_Nom->GetNbinsX()+1));
        m_gausFunct->SetParameter(2,stdDev);
        m_gausFunct->SetParLimits(2,0.5*stdDev,2.0*stdDev);
        int statusDnDy = integralHistoryHisto_Nom->Fit("m_gausFunct","EQ");
        TF1* fitResultDnDyBootstrap = integralHistoryHisto_Nom->GetFunction("m_gausFunct");
        if(fitResultDnDyBootstrap &&!std::isnan(fitResultDnDyBootstrap->GetParameter(1)) && !std::isnan(fitResultDnDyBootstrap->GetParameter(2)) ){

          dNdyAvg = fitResultDnDyBootstrap->GetParameter(1);
          dNdyErr = fitResultDnDyBootstrap->GetParameter(2);
          cout << "dNdy: " << dNdy << " dNdyAvg: " << dNdyAvg << " +/- " << dNdyErr/dNdyAvg*100.0 << "%" << endl;
          if(m_currentCharge == 1){
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdyAvg);
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdyErr);
            m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSNow);
            m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,betaSNowError);
            m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
            m_nominalFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
            m_bootstrapData_Nom_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
            //m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSNow);
          }else{
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdyAvg);
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdyErr);
            m_BetaS_Minus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSNow);
            m_BetaS_Minus_Nominal[m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,betaSNowError);
            m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
            m_nominalFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
            m_bootstrapData_Nom_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
            //m_BetaS_Minus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSFinal);
          }//is plus minus
        }else{
          cout << "Error: dN/dy Bootstrap Failed! " << endl;
          dNdyAvg = fitResultDnDyBootstrap->GetParameter(1);
          dNdyErr = fitResultDnDyBootstrap->GetParameter(2);
          if(m_currentCharge == 1){
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, 0.0);
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,0.0);
            m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
            m_nominalFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
            m_bootstrapData_Nom_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
            //m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSNow);
          }else{
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, 0.0);
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,0.0);
            m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
            m_nominalFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
            m_bootstrapData_Nom_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
            //m_BetaS_Minus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSFinal);
          }//is plus minus




        }
      }//rap loop
    }// pm index
  }// cent index

}


//################################################################

void SpectraFitter::fitProtonSpectraFXT_betaConstr_newIntegration(bool a_constrainBetaS, double a_lowRapBound_BetaS_Constraint, double a_highRapBound_BetaS_Constraint){
  cout << "#####################  Starting SpectraFitter::fitProtonSpectra() ########################" << endl;
  TVirtualFitter::SetMaxIterations( 1000000 );
  m_currentPartIndex = 2;
  bool useAvgParamsForSeparateFits = true;

  TCanvas* fittingCanvas = new TCanvas("fittingCanvas_Proton","Fitting Canvas");
  fittingCanvas->SetWindowSize(1300,700);
  fittingCanvas->SetCanvasSize(1200,600);
  double protonMass = m_partInfo->GetParticleMass(m_currentPartIndex);
  for(unsigned int centIndex = 0; centIndex < 16; centIndex++){
    m_currentCentIndex = centIndex;
    for(int pmIndex = 0; pmIndex < 2; pmIndex++){
      m_currentCharge = 1;
      if(pmIndex == 1) m_currentCharge = -1;

      m_liveRapidityProtonSpectra.clear();
      m_liveRapidityValueProtonSpectra.clear();
      double ampWeight = 0.0;
      double avgAmpFirst = 0.0;
      double tempWeight = 0.0;
      double avgTempFirst = 0.0;
      double avgBetaSFirst = 0.0;
      double betaSWeight = 0.0;
      double avgNFirst = 0.0;
      double nWeight = 0.0;
      vector< double > ampStorage;
      vector< double > tempStorage;
      vector< double > betaSStorage;

      double ampWeight_sys = 0.0;
      double avgAmpFirst_sys = 0.0;
      double tempWeight_sys = 0.0;
      double avgTempFirst_sys = 0.0;
      vector< double > ampStorage_sys;
      vector< double > tempStorage_sys;

      //Fit with single blastwaves first
      m_protonFittingStage = 1;
      m_isTemperatureConstrained = false;
      int counter = 0;
      for(unsigned int yIndex = 0; yIndex < m_cuts->getRapMtM0BinStructure(m_currentPartIndex, 1)->GetNbinsX(); yIndex++){
        m_currentRapValue = m_cuts->getRapMtM0BinStructure(m_currentPartIndex, 1)->GetBinCenter(yIndex+1);
        m_currentRapIndex = yIndex;
        TGraphErrors* specPM[2];
        specPM[0] = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][yIndex];
        specPM[1] = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][yIndex];
        if( !specPM[pmIndex] || specPM[pmIndex]->GetN() <= 4 ) continue; //############################################   MUST BE SAME AS ABOVE! ###################################
        m_liveRapidityProtonSpectra.push_back(yIndex);
        m_liveRapidityValueProtonSpectra.push_back(m_currentRapValue);
        cout << "Proton Fitting: Cent " << m_currentCentIndex << " yIndex " << yIndex
             << " charge: " << m_currentCharge << " ptr: " << specPM[pmIndex] << " charge: " << m_currentCharge
             << " N: " << specPM[pmIndex]->GetN() <<  endl;

        //##########  FIT WITH NOMINAL FIT FUNCTION ##########
        m_isCurrentFitNominal = true;
        m_currentSpectra = (TGraphErrors*) specPM[pmIndex]->Clone();
        init_blastWave();
        init_thermal();

        //cout << " Fixing Beta_S to 0.4 for initial fit..." << endl;
        //m_blastWave->FixParameter(2,0.4);
        m_blastWave->SetParameter(2,0.4);
        m_blastWave->SetParLimits(2,0.2,0.8);

        TF1* initial_BW_fit = new TF1(
          Form("InitFit_%s_Cent%02d_yIndex%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_currentRapIndex),
          this,&SpectraFitter::blastWaveModelFit,0,10,6,"SpectraFitter","blastWaveModelFit");
        initial_BW_fit->SetParNames("A","T_kin","#beta_S","W","R","m_p");
        initial_BW_fit->SetParameter(0,m_blastWave->GetParameter(0));
        initial_BW_fit->SetParameter(1,m_blastWave->GetParameter(1));
        initial_BW_fit->SetParameter(2,m_blastWave->GetParameter(2));
        if(SpectraFitter::getBlastWaveNFix() > 0) initial_BW_fit->FixParameter(3,SpectraFitter::getBlastWaveNFix());
        else initial_BW_fit->FixParameter(3,0.5);
        initial_BW_fit->FixParameter(4,m_blastWave->GetParameter(4));
        initial_BW_fit->SetParameter(5,m_blastWave->GetParameter(5));


        initial_BW_fit->SetLineColor(kYellow);
        int status = m_currentSpectra->Fit("m_blastWave","EV EX0","",0,10);
        TF1* fitResult = m_currentSpectra->GetFunction("m_blastWave");

        if(fitResult){
          ampWeight += 1.0 / (fitResult->GetParError(0)*fitResult->GetParError(0));
          avgAmpFirst += 1.0 / (fitResult->GetParError(0)*fitResult->GetParError(0)) * fitResult->GetParameter(0);
          tempWeight += 1.0 / (fitResult->GetParError(1)*fitResult->GetParError(1));
          avgTempFirst += 1.0 / (fitResult->GetParError(1)*fitResult->GetParError(1)) * fitResult->GetParameter(1);
          betaSWeight += 1.0 / (fitResult->GetParError(2)*fitResult->GetParError(2));
          avgBetaSFirst += 1.0 / (fitResult->GetParError(2)*fitResult->GetParError(2)) * fitResult->GetParameter(2);
          nWeight += 1.0/ (fitResult->GetParError(3)*fitResult->GetParError(3));
          avgNFirst += 1.0 / (fitResult->GetParError(3)*fitResult->GetParError(3)) * fitResult->GetParameter(3);

          ampStorage.push_back(fitResult->GetParameter(0));
          tempStorage.push_back(fitResult->GetParameter(1));
          betaSStorage.push_back(fitResult->GetParameter(2));

        }else{
          ampStorage.push_back(-1);
          tempStorage.push_back(-1);
          betaSStorage.push_back(-1);
        }

        //make the fit image
        fittingCanvas->cd();
        double smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
        double largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
        if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
        frame->SetTitle(Form("p^{%s} Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
                    m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
                    m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
        //frame->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
        //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame->GetXaxis()->SetTitle("m_{T}-m_{p} (GeV/c^{2})");
        frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);
        initial_BW_fit->Draw("same");
        m_currentSpectra->Draw("P");
        fittingCanvas->Update();
        fittingCanvas->SaveAs(Form("%s/%s/FirstFit_Nom_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));
        //delete m_currentSpectra;
        //delete initial_BW_fit;


        fittingCanvas->Clear();

        double thermalHighmTm0 = m_currentSpectra->GetX()[3]+m_currentSpectra->GetErrorX(3);

        TF1* initial_thermal_fit = new TF1(
          Form("InitFit_Sys_%s_Cent%02d_yIndex%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_currentRapIndex),
          "[0] * (x+[2]) * exp(-x/[1]) / ((2*3.14159265) * [1] * ([2]*[2] + 2*[2]*[1] + 2*[1]*[1]))",0,thermalHighmTm0);
        initial_thermal_fit->SetParNames("dN/dy","T","m");
        initial_thermal_fit->SetParameter(0,m_blastWave->GetParameter(0));
        initial_thermal_fit->SetParameter(1,m_blastWave->GetParameter(1));
        initial_thermal_fit->FixParameter(2,m_partInfo->GetParticleMass(m_currentPartIndex));


        initial_thermal_fit->SetLineColor(kYellow);
        int status_sys = m_currentSpectra->Fit("m_thermal","EV EX0","",0,thermalHighmTm0);
        TF1* fitResult_sys = m_currentSpectra->GetFunction("m_thermal");


        if(fitResult_sys){
          ampWeight_sys += 1.0 / (fitResult_sys->GetParError(0)*fitResult_sys->GetParError(0));
          avgAmpFirst_sys += 1.0 / (fitResult_sys->GetParError(0)*fitResult_sys->GetParError(0)) * fitResult_sys->GetParameter(0);
          tempWeight_sys += 1.0 / (fitResult_sys->GetParError(1)*fitResult_sys->GetParError(1));
          avgTempFirst_sys += 1.0 / (fitResult_sys->GetParError(1)*fitResult_sys->GetParError(1)) * fitResult_sys->GetParameter(1);

          ampStorage_sys.push_back(fitResult_sys->GetParameter(0));
          tempStorage_sys.push_back(fitResult_sys->GetParameter(1));

        }else{
          ampStorage_sys.push_back(-1);
          tempStorage_sys.push_back(-1);
        }

        //double smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
        //double largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
        //if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame_sys = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
        frame_sys->SetTitle(Form("p^{%s} Systematic Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
                    m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
                    m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
        //frame->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
        //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame_sys->GetXaxis()->SetTitle("m_{T}-m_{p} (GeV/c^{2})");
        frame_sys->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);
        initial_thermal_fit->Draw("same");
        //m_currentSpectra->GetFunction("m_blastWave")->SetBit(TF1::kNotDraw);
        m_currentSpectra->Draw("P");
        fittingCanvas->Update();
        fittingCanvas->SaveAs(Form("%s/%s/FirstFit_Sys_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));


        if(!fitResult) cout << "No Fit Result: yindex: " << yIndex << endl;
        if(!fitResult_sys) cout << "No Fit Result Sys: yindex: " << yIndex << endl;
        counter++;
      }

      avgAmpFirst = avgAmpFirst/ampWeight;
      avgTempFirst = avgTempFirst/tempWeight;
      avgBetaSFirst = avgBetaSFirst/betaSWeight;
      avgNFirst = avgNFirst/nWeight;

      if(std::isnan(avgBetaSFirst)) avgBetaSFirst = 0.5;

      cout << " AvgAmp: " << avgAmpFirst << "  AvgTemp: " << avgTempFirst << "  AvgBetsS: " << avgBetaSFirst << endl;

      avgAmpFirst_sys = avgAmpFirst_sys/ampWeight_sys;
      avgTempFirst_sys = avgTempFirst_sys/tempWeight_sys;

      TCanvas *fitParsCanvas = new TCanvas("fitParsCanvas","Fit Parameters Canvas");
      fitParsCanvas->SetWindowSize(1300,700);
      fitParsCanvas->SetCanvasSize(1200,600);

      TGraph *temp_init_nom = new TGraph(m_liveRapidityValueProtonSpectra.size(),&m_liveRapidityValueProtonSpectra[0],&tempStorage[0]);
      temp_init_nom->SetTitle("Temp Nominal Initial Values");
      temp_init_nom->GetXaxis()->SetTitle("y_{lab}");
      temp_init_nom->GetYaxis()->SetTitle("Temp (GeV)");
      temp_init_nom->SetMarkerStyle(20);
      temp_init_nom->Draw("AP");

      fitParsCanvas->SaveAs(Form("%s/%s/tempInit_Nom_Cent%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));

      TGraph *beta_init_nom = new TGraph(m_liveRapidityValueProtonSpectra.size(),&m_liveRapidityValueProtonSpectra[0],&betaSStorage[0]);
      beta_init_nom->SetTitle("#beta_{S} Nominal Initial Values");
      beta_init_nom->GetXaxis()->SetTitle("y_{lab}");
      beta_init_nom->GetYaxis()->SetTitle("#beta_{S}");
      beta_init_nom->SetMarkerStyle(20);
      beta_init_nom->Draw("AP");

      fitParsCanvas->SaveAs(Form("%s/%s/betaInit_Nom_Cent%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));

      fitParsCanvas->Clear();

      TGraph *temp_init_sys = new TGraph(m_liveRapidityValueProtonSpectra.size(),&m_liveRapidityValueProtonSpectra[0],&tempStorage_sys[0]);
      temp_init_sys->SetTitle("Temp Systematic Initial Values");
      temp_init_sys->GetXaxis()->SetTitle("y_{lab}");
      temp_init_sys->GetYaxis()->SetTitle("Temp (GeV)");
      temp_init_sys->SetMarkerStyle(20);

      fitParsCanvas->Clear();

      TF1 *temp_fitInit_sys = new TF1("temp_fitInit_sys","[0]/TMath::CosH([2]*(x-[1]))",-2,2);
      temp_fitInit_sys->SetParameters(0.1,m_cuts->getYCM(),1.0);
      temp_fitInit_sys->FixParameter(1,m_cuts->getYCM());
      temp_fitInit_sys->SetParLimits(0,0.01,0.3);

      temp_init_sys->Fit(temp_fitInit_sys);
      temp_init_sys->Draw("AP");
      temp_fitInit_sys->Draw("Same");


      fitParsCanvas->SaveAs(Form("%s/%s/tempInit_Sys_Cent%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));

      fitParsCanvas->Clear();

      //setup minimizer
      int numSpectraToFit = (int) m_liveRapidityProtonSpectra.size();
      //systematic fitting
      m_minimizer_sys = ROOT::Math::Factory::CreateMinimizer();
      m_chiSqrdFunctor_sys = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_thermal_FXT_ChiSqr,(numSpectraToFit) + 3);
      cout << "created chi squared sys functor with NDim " << m_chiSqrdFunctor_sys->NDim() << "  functor: " << &SpectraFitter::simultaneous_thermal_FXT_ChiSqr  << endl;
      m_minimizer_sys->SetFunction(*m_chiSqrdFunctor_sys);
      for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size(); iii++){
        if(useAvgParamsForSeparateFits){
          m_minimizer_sys->SetVariable(iii, Form("dNdy_sys_%02d",m_liveRapidityProtonSpectra[iii]), avgAmpFirst_sys , 0.1*avgAmpFirst_sys);
          m_minimizer_sys->SetVariableLimits(iii, 0.0, avgAmpFirst_sys*10000.0);
        }else{
          m_minimizer_sys->SetVariable(iii, Form("dNdy_sys_%02d",m_liveRapidityProtonSpectra[iii]), ampStorage_sys[iii] , 0.1*ampStorage_sys[iii]);
          m_minimizer_sys->SetVariableLimits(iii, 0.0, ampStorage_sys[iii]*10000.0);
        }
      }

      m_minimizer_sys->SetVariable(counter, "Amp_T_sys" ,temp_fitInit_sys->GetParameter(0), 0.01);
      m_minimizer_sys->SetVariableLimits(counter,0.0001, 0.3);
      m_minimizer_sys->SetVariable(counter+1, "Mu_T_sys" ,m_cuts->getYCM(), 0.2);
      m_minimizer_sys->FixVariable(counter+1);
      m_minimizer_sys->SetVariable(counter+2, "Sigma_T_sys" ,temp_fitInit_sys->GetParameter(2), 2.0);
      m_minimizer_sys->SetVariableLimits(counter+2,0.0, 2.0);




      cout << "######################################################################" << endl;
      cout << "          STAGE 2   Proton Sys Fitting - Use Separate Rap Fit Results as Seeds to Simultaneous Fitter" << endl;
      //m_blastWave->SetParLimits(2,0.0,1.0);
      m_protonFittingStage = 2;
      //init_simul_blastWave();  //only do this if not initialized by single fits above
      m_minimizer_sys->SetPrintLevel(5);
      m_minimizer_sys->SetMaxIterations(3000);
      m_minimizer_sys->SetMaxFunctionCalls(200000);
      m_minimizer_sys->SetValidError(true);
      m_minimizer_sys->Minimize();
      int status_sys = m_minimizer_sys->Status();
      const double* finalParams_sys = m_minimizer_sys->X();
      if(status_sys == 0){
        cout << "Proton Sys Fit Status: " << status_sys << endl;
      }
      else{
        cout << "################################  First Pass Fit:  STATUS OF SYS FIT = " << status_sys << "   IS BAD!!!!!  ################################" << endl;
        cout << "Current Parameters: " << endl;
        for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size() + 3; iii++){
          cout << "  " << finalParams_sys[iii];
        }
        cout << endl;
        continue;
      }


            cout << "######################################################################" << endl;
      cout << "          STAGE 3   Proton Fitting Sys - Bootstrap Individual Amplitudes" << endl;


      for(int iii = 0; iii < m_liveRapidityProtonSpectra.size(); iii++){

        double rapidity = m_liveRapidityValueProtonSpectra[iii];

        TGraphErrors* spectrum = NULL;
        if(m_currentCharge == 1) spectrum = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]];
        else spectrum = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]];

        double dNdy_sys = finalParams_sys[iii];
        double dNdy_err_sys = sqrt( m_minimizer_sys->CovMatrix(iii,iii) );

        double temp_sys = finalParams_sys[m_liveRapidityProtonSpectra.size()]/TMath::CosH(finalParams_sys[m_liveRapidityProtonSpectra.size() + 2]*(rapidity - finalParams_sys[m_liveRapidityProtonSpectra.size()+1]));

        double tempErr_sys = sqrt( pow(temp_sys*m_minimizer_sys->CovMatrix(m_liveRapidityProtonSpectra.size(),m_liveRapidityProtonSpectra.size())/finalParams_sys[m_liveRapidityProtonSpectra.size()],2) + pow(temp_sys*m_minimizer_sys->CovMatrix(m_liveRapidityProtonSpectra.size()+2,m_liveRapidityProtonSpectra.size()+2)*TMath::TanH(finalParams_sys[m_liveRapidityProtonSpectra.size()+2]*(rapidity - finalParams_sys[m_liveRapidityProtonSpectra.size()+1]))*(rapidity - finalParams_sys[m_liveRapidityProtonSpectra.size()+1]),2) );

        double thermalHighmTm0 = spectrum->GetX()[3]+spectrum->GetErrorX(3);


        TF1* fitFunct_sys = new TF1(
          Form("SystematicFit_Cent%02d_yIndex%02d",m_currentCentIndex,m_liveRapidityProtonSpectra[iii]),
          "[0] * (x+[2]) * exp(-x/[1]) / ((2*3.14159265) * [1] * ([2]*[2] + 2*[2]*[1] + 2*[1]*[1]))",0.0,thermalHighmTm0);
        fitFunct_sys->SetParNames("dN/dy","T","m");
        fitFunct_sys->SetParameter(0,dNdy_sys);
        fitFunct_sys->SetParError(0,dNdy_err_sys);
        fitFunct_sys->SetParameter(1,temp_sys);
        fitFunct_sys->SetParError(1,tempErr_sys);
        fitFunct_sys->FixParameter(2,m_partInfo->GetParticleMass(m_currentPartIndex));




        TCanvas *finalCanvas = new TCanvas("finalCanvas","Final Canvas");
        finalCanvas->SetWindowSize(1300,700);
        finalCanvas->SetCanvasSize(1200,600);

        finalCanvas->cd();

        double smallYVal =  HistogramUtilities::findSmallestYVal(spectrum)*0.25;
        double largeXVal =  HistogramUtilities::findLargestXVal(spectrum)*1.3;
        if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame_sys = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(spectrum)*4.0);
        frame_sys->SetTitle(Form("p^{%s} Systematic Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
          m_cuts->getRapidityRangeLow(m_liveRapidityProtonSpectra[iii],m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(m_liveRapidityProtonSpectra[iii],m_currentPartIndex,1),
          m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
          //frame->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
          //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame_sys->GetXaxis()->SetTitle("m_{T}-m_{p} (GeV/c^{2})");
        frame_sys->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);

        spectrum->SetMarkerStyle(20);
        spectrum->Draw("P");
        fitFunct_sys->Draw("same");

        TPaveText *fitParsTxt_sys = new TPaveText(0.65,0.15,0.95,0.85,"NDC");
        fitParsTxt_sys->AddText(Form("dN/dy \t %f#pm%f",dNdy_sys,dNdy_err_sys));
        fitParsTxt_sys->AddText(Form("T \t %f#pm%f",temp_sys,tempErr_sys));
        fitParsTxt_sys->AddText(Form("m \t %f",m_partInfo->GetParticleMass(m_currentPartIndex)));

        fitParsTxt_sys->SetFillStyle(0);
        fitParsTxt_sys->SetBorderSize(5);

        fitParsTxt_sys->Draw("same");

        finalCanvas->Update();
        finalCanvas->SaveAs(Form("%s/%s/FinalFit_Sys_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
          m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_liveRapidityProtonSpectra[iii]));



        if(m_currentCharge == 1){

          m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdy_sys);
          m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdy_err_sys);

          m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,temp_sys);
          m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,tempErr_sys);

          m_systematicFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct_sys;

        }else{

          m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdy_sys);
          m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdy_err_sys);

          m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,temp_sys);
          m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,tempErr_sys);

          m_systematicFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct_sys;
        }//is plus minus

      }//rap loop



      //nominal fitting
      m_minimizer = ROOT::Math::Factory::CreateMinimizer();
      m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_blastWave_betaConstr_ChiSqr,(numSpectraToFit) + 6);
      cout << "created chi squared functor with NDim " << m_chiSqrdFunctor->NDim() << "  functor: " << &SpectraFitter::simultaneous_blastWave_betaConstr_ChiSqr  << endl;
      m_minimizer->SetFunction(*m_chiSqrdFunctor);
      for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size(); iii++){
        if(useAvgParamsForSeparateFits){
          m_minimizer->SetVariable(iii, Form("A_%02d",m_liveRapidityProtonSpectra[iii]), avgAmpFirst , 0.1*avgAmpFirst);
          m_minimizer->SetVariableLimits(iii, 0.0, avgAmpFirst*10000.0);
        }else{
          m_minimizer->SetVariable(iii, Form("A_%02d",m_liveRapidityProtonSpectra[iii]), ampStorage[iii] , 0.1*ampStorage[iii]);
          m_minimizer->SetVariableLimits(iii, 0.0, ampStorage[iii]*10000.0);
        }
      }

      m_minimizer->SetVariable(counter, "T" ,avgTempFirst, 0.15);
      m_minimizer->SetVariableLimits(counter,0.0, 2.0);
      m_minimizer->SetVariable(counter+1,"beta_p4",-0.2,0.15);
      m_minimizer->SetVariableLimits(counter+1,-10.0,0.0);
      m_minimizer->SetVariable(counter+2,"beta_shift",m_cuts->getYCM(),0.15);
      m_minimizer->FixVariable(counter+2);
      //test ben
      m_minimizer->SetVariable(counter+3,"beta_p2",0.0,0.15);
      m_minimizer->SetVariableLimits(counter+3,0.0,0.0);
      m_minimizer->SetVariable(counter+4,"beta_const",avgBetaSFirst,0.05);
      m_minimizer->SetVariableLimits(counter+4,0.0,1.0);
      if(SpectraFitter::getBlastWaveNFix() > 0){
        m_minimizer->SetVariable(counter+5,"n",SpectraFitter::getBlastWaveNFix(),0.05);
        m_minimizer->FixVariable(counter+5);
      }else{
        m_minimizer->SetVariable(counter+5,"n",avgNFirst,0.05);
        m_minimizer->SetVariableLimits(counter+5,0.0,5.0);
      }









      cout << "######################################################################" << endl;
      cout << "          STAGE 2   Proton Fitting - Use Separate Rap Fit Results as Seeds to Simultaneous Fitter" << endl;
      m_blastWave->SetParLimits(2,0.0,1.0);
      m_protonFittingStage = 2;
      //init_simul_blastWave();  //only do this if not initialized by single fits above
      m_minimizer->SetPrintLevel(5);
      m_minimizer->SetMaxIterations(3000);
      m_minimizer->SetMaxFunctionCalls(200000);
      m_minimizer->SetValidError(true);
      m_minimizer->Minimize();
      int status = m_minimizer->Status();
      const double* finalParams_RoundOne = m_minimizer->X();
      if(status == 0){
        cout << "Proton Fit Status: " << status << endl;
      }
      else{
        cout << "################################  First Pass Fit:  STATUS OF FIT = " << status << "   IS BAD!!!!!  ################################" << endl;
        cout << "Current Parameters: " << endl;
        for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size() + 6; iii++){
          cout << "  " << finalParams_RoundOne[iii];
        }
        cout << endl;
        continue;
      }

      const double* finalParams = m_minimizer->X();
      double tempFinal = finalParams[m_liveRapidityProtonSpectra.size()];
      double tempFinalErr = sqrt( m_minimizer->CovMatrix(m_liveRapidityProtonSpectra.size(),m_liveRapidityProtonSpectra.size()) );
      cout << " ptrs: " << m_Proton_Temp_Plus_Nom << "   " << m_Proton_Temp_Minus_Nom << endl;
      if(!std::isnan(tempFinal) && !std::isnan(tempFinalErr)){
        if(m_currentCharge == 1){
          m_Proton_Temp_Plus_Nom->SetBinContent(m_currentCentIndex+1,tempFinal);
          m_Proton_Temp_Plus_Nom->SetBinError(m_currentCentIndex+1,tempFinalErr);
        }else{
          m_Proton_Temp_Minus_Nom->SetBinContent(m_currentCentIndex+1,tempFinal);
          m_Proton_Temp_Minus_Nom->SetBinError(m_currentCentIndex+1,tempFinalErr);
        }
      }


      cout << "Final Temperature: " << tempFinal << endl;
      //cout << "Final Beta_S: " << betaSFinal << endl;

      double covMatrix[110000];

      m_minimizer->GetCovMatrix(&covMatrix[0]);

      TMatrixDSym covMatrixDSym((numSpectraToFit) + 6, &covMatrix[0]);

      cout << "######################################################################" << endl;
      cout << "          STAGE 3   Proton Fitting - Bootstrap Individual Amplitudes" << endl;


      for(int iii = 0; iii < m_liveRapidityProtonSpectra.size(); iii++){
        double Amp = finalParams[iii];
        double AmpErr = sqrt( m_minimizer->CovMatrix(iii,iii) );
        double rapidity = m_liveRapidityProtonSpectra[iii];
        double betaSNow = finalParams[m_liveRapidityProtonSpectra.size()+1]*pow(m_liveRapidityValueProtonSpectra[iii]- finalParams[m_liveRapidityProtonSpectra.size()+2],4)+finalParams[m_liveRapidityProtonSpectra.size()+3]*pow(m_liveRapidityValueProtonSpectra[iii]- finalParams[m_liveRapidityProtonSpectra.size()+2],2)+finalParams[m_liveRapidityProtonSpectra.size()+4];
        double betaSNowError = sqrt(pow(m_liveRapidityValueProtonSpectra[iii]- finalParams[m_liveRapidityProtonSpectra.size()+2],8)*m_minimizer->CovMatrix(m_liveRapidityProtonSpectra.size()+1,m_liveRapidityProtonSpectra.size()+1)+pow(m_liveRapidityValueProtonSpectra[iii]- finalParams[m_liveRapidityProtonSpectra.size()+2],4)*m_minimizer->CovMatrix(m_liveRapidityProtonSpectra.size()+3,m_liveRapidityProtonSpectra.size()+3)+m_minimizer->CovMatrix(m_liveRapidityProtonSpectra.size()+4,m_liveRapidityProtonSpectra.size()+4)+pow(-4.0*finalParams[m_liveRapidityProtonSpectra.size()+1]*pow(m_liveRapidityValueProtonSpectra[iii]- m_liveRapidityProtonSpectra.size()+2,3)-2.0*finalParams[m_liveRapidityProtonSpectra.size()+3]*(m_liveRapidityValueProtonSpectra[iii]- finalParams[m_liveRapidityProtonSpectra.size()+2]),2)*m_minimizer->CovMatrix(m_liveRapidityProtonSpectra.size()+2,m_liveRapidityProtonSpectra.size()+2));
        cout << "Ready for bootstraper: Amp: " << Amp << " AmpErr: " << AmpErr << " Rap: " << rapidity << " BetaS: " << betaSNow << " Temp: " << tempFinal << endl;
        TF1* fitFunct = new TF1(
          Form("NominalFit_Cent%02d_yIndex%02d_blastwave",m_currentCentIndex,m_liveRapidityProtonSpectra[iii]),
          this,&SpectraFitter::blastWaveModelFit,0,10,6,"SpectraFitter","blastWaveModelFit");
        fitFunct->SetParNames("A","T_kin","#beta_S","W","R","m_p");
        fitFunct->SetParameter(0,Amp);
        fitFunct->SetParError(0,AmpErr);
        fitFunct->SetParameter(1,tempFinal);
        fitFunct->SetParameter(2,betaSNow);
        if(SpectraFitter::getBlastWaveNFix() > 0)fitFunct->FixParameter(3,SpectraFitter::getBlastWaveNFix());
        else{
          fitFunct->SetParameter(3,finalParams[m_liveRapidityProtonSpectra.size()+5]);
          fitFunct->SetParError(3,sqrt(m_minimizer->CovMatrix(m_liveRapidityProtonSpectra.size()+5,m_liveRapidityProtonSpectra.size()+5)));
        }
        fitFunct->FixParameter(4,1.0);
        fitFunct->SetParameter(5,m_partInfo->GetParticleMass(2));

        TCanvas *protonFinalCanvas = new TCanvas();
        protonFinalCanvas->SetWindowSize(1300,700);
        protonFinalCanvas->SetCanvasSize(1200,600);

        protonFinalCanvas->cd();

        double smallYVal;
        double largeXVal;
        if(pmIndex == 0){
          largeXVal =  HistogramUtilities::findLargestXVal(m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]])*1.3;
          smallYVal =  HistogramUtilities::findSmallestYVal(m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]])*0.25;
        }else if(pmIndex == 1){
          largeXVal =  HistogramUtilities::findLargestXVal(m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]])*1.3;
          smallYVal =  HistogramUtilities::findSmallestYVal(m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]])*0.25;
        }
        if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame_nom = protonFinalCanvas->DrawFrame(0.0,smallYVal,largeXVal,(pmIndex==0)?HistogramUtilities::findLargestYVal(m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]])*4.0:HistogramUtilities::findLargestYVal(m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]])*4.0);
        frame_nom->SetTitle(Form("p^{%s} Systematic Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
          m_cuts->getRapidityRangeLow(m_liveRapidityProtonSpectra[iii],m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(m_liveRapidityProtonSpectra[iii],m_currentPartIndex,1),
          m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
          //frame->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
          //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame_nom->GetXaxis()->SetTitle("m_{T}-m_{p} (GeV/c^{2})");
        frame_nom->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);

        protonFinalCanvas->SetLogy();
        if(pmIndex == 0) m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]]->Draw("AP");
        else if(pmIndex == 1) m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]]->Draw("AP");
        fitFunct->Draw("SAME");

        TPaveText *fitParsTxt = new TPaveText(0.65,0.15,0.95,0.85,"NDC");
        fitParsTxt->AddText(Form("A \t %f#pm%f",Amp,AmpErr));
        fitParsTxt->AddText(Form("T \t %f#pm%f",tempFinal,tempFinalErr));
        fitParsTxt->AddText(Form("#beta_{S} \t %f#pm%f",betaSNow,betaSNowError));
        if(SpectraFitter::getBlastWaveNFix() > 0)fitParsTxt->AddText(Form("n \t %f",SpectraFitter::getBlastWaveNFix()));
        else fitParsTxt->AddText(Form("n \t %f#pm%f",m_blastWave->GetParameter(3),m_blastWave->GetParError(3)));
        fitParsTxt->AddText(Form("R \t %f",1.0));
        fitParsTxt->AddText(Form("m \t %f",m_partInfo->GetParticleMass(m_currentPartIndex)));

        fitParsTxt->SetFillStyle(0);
        fitParsTxt->SetBorderSize(5);

        fitParsTxt->Draw("same");

        protonFinalCanvas->SaveAs(Form("%s/%s/FinalFit_Nom_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_liveRapidityProtonSpectra[iii]));

        delete protonFinalCanvas;


        vector<int> parsToKeep = {iii,(int)(m_liveRapidityProtonSpectra.size()),(int)(m_liveRapidityProtonSpectra.size()+1),(int)(m_liveRapidityProtonSpectra.size()+2),(int)(m_liveRapidityProtonSpectra.size()+3),(int)(m_liveRapidityProtonSpectra.size()+4),(int)(m_liveRapidityProtonSpectra.size()+5),-999,-999,-999};

        TMatrixDSym proCovMatrix = PhysMath::reduceCovMatrix_keepPassedVector(covMatrixDSym,parsToKeep);

        double proPars[11] = {finalParams[iii],finalParams[m_liveRapidityProtonSpectra.size()],finalParams[m_liveRapidityProtonSpectra.size()+1],finalParams[m_liveRapidityProtonSpectra.size()+2],finalParams[m_liveRapidityProtonSpectra.size()+3],finalParams[m_liveRapidityProtonSpectra.size()+4],finalParams[m_liveRapidityProtonSpectra.size()+5],1.0,m_partInfo->GetParticleMass(2),m_liveRapidityValueProtonSpectra[iii]};

        TF1 *blastWave_notInvariant = PhysMath::blastWaveFunct_betaConstr_NotInvariant(Form("blastWave_notInvariant_Cent%02d_yIndex%02d",m_currentCentIndex,m_liveRapidityProtonSpectra[iii]),finalParams[iii],finalParams[m_liveRapidityProtonSpectra.size()],finalParams[m_liveRapidityProtonSpectra.size()+1],finalParams[m_liveRapidityProtonSpectra.size()+2],finalParams[m_liveRapidityProtonSpectra.size()+3],finalParams[m_liveRapidityProtonSpectra.size()+4],finalParams[m_liveRapidityProtonSpectra.size()+5],1.0,m_partInfo->GetParticleMass(2),m_liveRapidityValueProtonSpectra[iii]);


        double dNdy = blastWave_notInvariant->Integral(0,10);
        double dNdyErr = blastWave_notInvariant->IntegralError(0,10, proPars, proCovMatrix.GetMatrixArray(),0.1);
          cout << "dNdy: " << dNdy << " +/- " << dNdyErr/dNdy*100.0 << "%" << endl;
          if(m_currentCharge == 1){
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdy);
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdyErr);
            m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSNow);
            m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,betaSNowError);
            m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
            m_nominalFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
            //m_bootstrapData_Nom_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
            //m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSNow);
          }else{
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdy);
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdyErr);
            m_BetaS_Minus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSNow);
            m_BetaS_Minus_Nominal[m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,betaSNowError);
            m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
            m_nominalFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
            //m_bootstrapData_Nom_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
            //m_BetaS_Minus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSFinal);
          }//is plus minus
      }//rap loop
    }// pm index
  }// cent index

}



//################################################################

void SpectraFitter::fitProtonSpectraFXT_betaConstr_newIntegration_forceSymmetry(bool a_constrainBetaS, double a_lowRapBound_BetaS_Constraint, double a_highRapBound_BetaS_Constraint){
  cout << "#####################  Starting SpectraFitter::fitProtonSpectra() ########################" << endl;
  TVirtualFitter::SetMaxIterations( 1000000 );
  m_currentPartIndex = 2;
  bool useAvgParamsForSeparateFits = false;

  TCanvas* fittingCanvas = new TCanvas("fittingCanvas_Proton","Fitting Canvas");
  fittingCanvas->SetWindowSize(1300,700);
  fittingCanvas->SetCanvasSize(1200,600);
  double protonMass = m_partInfo->GetParticleMass(m_currentPartIndex);
  for(unsigned int centIndex = 0; centIndex < 16; centIndex++){
    m_currentCentIndex = centIndex;
    for(int pmIndex = 0; pmIndex < 2; pmIndex++){
      m_currentCharge = 1;
      if(pmIndex == 1) m_currentCharge = -1;

      m_liveRapidityProtonSpectra.clear();
      m_liveRapidityValueProtonSpectra.clear();
      double ampWeight = 0.0;
      double avgAmpFirst = 0.0;
      double tempWeight = 0.0;
      double avgTempFirst = 0.0;
      double avgBetaSFirst = 0.0;
      double betaSWeight = 0.0;
      double avgNFirst = 0.0;
      double nWeight = 0.0;
      vector< double > ampStorage;
      vector< double > tempStorage;
      vector< double > betaSStorage;

      double ampWeight_sys = 0.0;
      double avgAmpFirst_sys = 0.0;
      double tempWeight_sys = 0.0;
      double avgTempFirst_sys = 0.0;
      vector< double > ampStorage_sys;
      vector< double > tempStorage_sys;

      //Fit with single blastwaves first
      m_protonFittingStage = 1;
      m_isTemperatureConstrained = false;
      int counter = 0;
      for(unsigned int yIndex = 0; yIndex < m_cuts->getRapMtM0BinStructure(m_currentPartIndex, 1)->GetNbinsX(); yIndex++){
        m_currentRapValue = m_cuts->getRapMtM0BinStructure(m_currentPartIndex, 1)->GetBinCenter(yIndex+1);
        m_currentRapIndex = yIndex;
        TGraphErrors* specPM[2];
        specPM[0] = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][yIndex];
        specPM[1] = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][yIndex];
        if( !specPM[pmIndex] || specPM[pmIndex]->GetN() <= 4 ) continue; //############################################   MUST BE SAME AS ABOVE! ###################################
        m_liveRapidityProtonSpectra.push_back(yIndex);
        m_liveRapidityValueProtonSpectra.push_back(m_currentRapValue);
        if(fabs(m_currentRapValue - m_cuts->getYCM()) < 1e-2) m_currentMidRapIndex = m_liveRapidityValueProtonSpectra.size() - 1;
        cout << "Proton Fitting: Cent " << m_currentCentIndex << " yIndex " << yIndex
             << " charge: " << m_currentCharge << " ptr: " << specPM[pmIndex] << " charge: " << m_currentCharge
             << " N: " << specPM[pmIndex]->GetN() <<  endl;

        //##########  FIT WITH NOMINAL FIT FUNCTION ##########
        m_isCurrentFitNominal = true;
        m_currentSpectra = (TGraphErrors*) specPM[pmIndex]->Clone();
        init_blastWave();
        init_thermal();

        //cout << " Fixing Beta_S to 0.4 for initial fit..." << endl;
        //m_blastWave->FixParameter(2,0.4);
        m_blastWave->SetParameter(2,0.4);
        m_blastWave->SetParLimits(2,0.2,0.8);

        TF1* initial_BW_fit = new TF1(
          Form("InitFit_%s_Cent%02d_yIndex%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_currentRapIndex),
          this,&SpectraFitter::blastWaveModelFit,0,10,6,"SpectraFitter","blastWaveModelFit");
        initial_BW_fit->SetParNames("A","T_kin","#beta_S","W","R","m_p");
        initial_BW_fit->SetParameter(0,m_blastWave->GetParameter(0));
        initial_BW_fit->SetParameter(1,m_blastWave->GetParameter(1));
        initial_BW_fit->SetParameter(2,m_blastWave->GetParameter(2));
        if(SpectraFitter::getBlastWaveNFix() > 0) initial_BW_fit->FixParameter(3,SpectraFitter::getBlastWaveNFix());
        else initial_BW_fit->FixParameter(3,0.5);
        initial_BW_fit->FixParameter(4,m_blastWave->GetParameter(4));
        initial_BW_fit->SetParameter(5,m_blastWave->GetParameter(5));


        initial_BW_fit->SetLineColor(kYellow);
        int status = m_currentSpectra->Fit("m_blastWave","EV EX0","",0,10);
        TF1* fitResult = m_currentSpectra->GetFunction("m_blastWave");

        if(fitResult){
          ampWeight += 1.0 / (fitResult->GetParError(0)*fitResult->GetParError(0));
          avgAmpFirst += 1.0 / (fitResult->GetParError(0)*fitResult->GetParError(0)) * fitResult->GetParameter(0);
          tempWeight += 1.0 / (fitResult->GetParError(1)*fitResult->GetParError(1));
          avgTempFirst += 1.0 / (fitResult->GetParError(1)*fitResult->GetParError(1)) * fitResult->GetParameter(1);
          betaSWeight += 1.0 / (fitResult->GetParError(2)*fitResult->GetParError(2));
          avgBetaSFirst += 1.0 / (fitResult->GetParError(2)*fitResult->GetParError(2)) * fitResult->GetParameter(2);
          nWeight += 1.0/ (fitResult->GetParError(3)*fitResult->GetParError(3));
          avgNFirst += 1.0 / (fitResult->GetParError(3)*fitResult->GetParError(3)) * fitResult->GetParameter(3);

          ampStorage.push_back(fitResult->GetParameter(0));
          tempStorage.push_back(fitResult->GetParameter(1));
          betaSStorage.push_back(fitResult->GetParameter(2));

        }else{
          ampStorage.push_back(-1);
          tempStorage.push_back(-1);
          betaSStorage.push_back(-1);
        }

        //make the fit image
        fittingCanvas->cd();
        double smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
        double largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
        if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
        frame->SetTitle(Form("p^{%s} Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
                    m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
                    m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
        //frame->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
        //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame->GetXaxis()->SetTitle("m_{T}-m_{p} (GeV/c^{2})");
        frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);
        initial_BW_fit->Draw("same");
        m_currentSpectra->Draw("P");
        fittingCanvas->Update();
        fittingCanvas->SaveAs(Form("%s/%s/FirstFit_Nom_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));
        //delete m_currentSpectra;
        //delete initial_BW_fit;


        fittingCanvas->Clear();

        double thermalHighmTm0 = m_currentSpectra->GetX()[3]+m_currentSpectra->GetErrorX(3);

        TF1* initial_thermal_fit = new TF1(
          Form("InitFit_Sys_%s_Cent%02d_yIndex%02d",m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_currentRapIndex),
          "[0] * (x+[2]) * exp(-x/[1]) / ((2*3.14159265) * [1] * ([2]*[2] + 2*[2]*[1] + 2*[1]*[1]))",0,thermalHighmTm0);
        initial_thermal_fit->SetParNames("dN/dy","T","m");
        initial_thermal_fit->SetParameter(0,m_blastWave->GetParameter(0));
        initial_thermal_fit->SetParameter(1,m_blastWave->GetParameter(1));
        initial_thermal_fit->FixParameter(2,m_partInfo->GetParticleMass(m_currentPartIndex));


        initial_thermal_fit->SetLineColor(kYellow);
        int status_sys = m_currentSpectra->Fit("m_thermal","EV EX0","",0,thermalHighmTm0);
        TF1* fitResult_sys = m_currentSpectra->GetFunction("m_thermal");


        if(fitResult_sys){
          ampWeight_sys += 1.0 / (fitResult_sys->GetParError(0)*fitResult_sys->GetParError(0));
          avgAmpFirst_sys += 1.0 / (fitResult_sys->GetParError(0)*fitResult_sys->GetParError(0)) * fitResult_sys->GetParameter(0);
          tempWeight_sys += 1.0 / (fitResult_sys->GetParError(1)*fitResult_sys->GetParError(1));
          avgTempFirst_sys += 1.0 / (fitResult_sys->GetParError(1)*fitResult_sys->GetParError(1)) * fitResult_sys->GetParameter(1);

          ampStorage_sys.push_back(fitResult_sys->GetParameter(0));
          tempStorage_sys.push_back(fitResult_sys->GetParameter(1));

        }else{
          ampStorage_sys.push_back(-1);
          tempStorage_sys.push_back(-1);
        }

        //double smallYVal =  HistogramUtilities::findSmallestYVal(m_currentSpectra)*0.25;
        //double largeXVal =  HistogramUtilities::findLargestXVal(m_currentSpectra)*1.3;
        //if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame_sys = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(m_currentSpectra)*4.0);
        frame_sys->SetTitle(Form("p^{%s} Systematic Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
                    m_cuts->getRapidityRangeLow(yIndex,m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(yIndex,m_currentPartIndex,1),
                    m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
        //frame->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
        //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame_sys->GetXaxis()->SetTitle("m_{T}-m_{p} (GeV/c^{2})");
        frame_sys->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);
        initial_thermal_fit->Draw("same");
        //m_currentSpectra->GetFunction("m_blastWave")->SetBit(TF1::kNotDraw);
        m_currentSpectra->Draw("P");
        fittingCanvas->Update();
        fittingCanvas->SaveAs(Form("%s/%s/FirstFit_Sys_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,yIndex));


        if(!fitResult) cout << "No Fit Result: yindex: " << yIndex << endl;
        if(!fitResult_sys) cout << "No Fit Result Sys: yindex: " << yIndex << endl;
        counter++;
      }

      avgAmpFirst = avgAmpFirst/ampWeight;
      avgTempFirst = avgTempFirst/tempWeight;
      avgBetaSFirst = avgBetaSFirst/betaSWeight;
      avgNFirst = avgNFirst/nWeight;

      if(std::isnan(avgBetaSFirst)) avgBetaSFirst = 0.5;

      cout << " AvgAmp: " << avgAmpFirst << "  AvgTemp: " << avgTempFirst << "  AvgBetsS: " << avgBetaSFirst << endl;

      avgAmpFirst_sys = avgAmpFirst_sys/ampWeight_sys;
      avgTempFirst_sys = avgTempFirst_sys/tempWeight_sys;

      TCanvas *fitParsCanvas = new TCanvas("fitParsCanvas","Fit Parameters Canvas");
      fitParsCanvas->SetWindowSize(1300,700);
      fitParsCanvas->SetCanvasSize(1200,600);

      TGraph *temp_init_nom = new TGraph(m_liveRapidityValueProtonSpectra.size(),&m_liveRapidityValueProtonSpectra[0],&tempStorage[0]);
      temp_init_nom->SetTitle("Temp Nominal Initial Values");
      temp_init_nom->GetXaxis()->SetTitle("y_{lab}");
      temp_init_nom->GetYaxis()->SetTitle("Temp (GeV)");
      temp_init_nom->SetMarkerStyle(20);


      TF1 *tempNomFit = new TF1("tempNomFit","[0]",-1.5,1.5);
      tempNomFit->SetParameter(0,0.12);
      temp_init_nom->Fit(tempNomFit);

      temp_init_nom->Draw("AP");
      tempNomFit->Draw("same");

      fitParsCanvas->SaveAs(Form("%s/%s/tempInit_Nom_Cent%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));

      TGraph *beta_init_nom = new TGraph(m_liveRapidityValueProtonSpectra.size(),&m_liveRapidityValueProtonSpectra[0],&betaSStorage[0]);
      beta_init_nom->SetTitle("#beta_{S} Nominal Initial Values");
      beta_init_nom->GetXaxis()->SetTitle("y_{lab}");
      beta_init_nom->GetYaxis()->SetTitle("#beta_{S}");
      beta_init_nom->SetMarkerStyle(20);
      beta_init_nom->Draw("AP");

      fitParsCanvas->SaveAs(Form("%s/%s/betaInit_Nom_Cent%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));

      fitParsCanvas->Clear();

      TGraph *temp_init_sys = new TGraph(m_liveRapidityValueProtonSpectra.size(),&m_liveRapidityValueProtonSpectra[0],&tempStorage_sys[0]);
      temp_init_sys->SetTitle("Temp Systematic Initial Values");
      temp_init_sys->GetXaxis()->SetTitle("y_{lab}");
      temp_init_sys->GetYaxis()->SetTitle("Temp (GeV)");
      temp_init_sys->SetMarkerStyle(20);

      fitParsCanvas->Clear();

      TF1 *temp_fitInit_sys = new TF1("temp_fitInit_sys","[0]/TMath::CosH([2]*(x-[1]))",-2,2);
      temp_fitInit_sys->SetParameters(0.1,m_cuts->getYCM(),1.0);
      temp_fitInit_sys->FixParameter(1,m_cuts->getYCM());
      temp_fitInit_sys->SetParLimits(0,0.01,0.3);

      temp_init_sys->Fit(temp_fitInit_sys);
      temp_init_sys->Draw("AP");
      temp_fitInit_sys->Draw("Same");


      fitParsCanvas->SaveAs(Form("%s/%s/tempInit_Sys_Cent%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex));

      fitParsCanvas->Clear();

      //setup minimizer
      int numSpectraToFit = (int) m_liveRapidityProtonSpectra.size();
      //systematic fitting
      m_minimizer_sys = ROOT::Math::Factory::CreateMinimizer();
      m_chiSqrdFunctor_sys = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_thermal_FXT_ChiSqr,(numSpectraToFit) + 3);
      cout << "created chi squared sys functor with NDim " << m_chiSqrdFunctor_sys->NDim() << "  functor: " << &SpectraFitter::simultaneous_thermal_FXT_ChiSqr  << endl;
      m_minimizer_sys->SetFunction(*m_chiSqrdFunctor_sys);
      for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size(); iii++){
        if(useAvgParamsForSeparateFits){
          m_minimizer_sys->SetVariable(iii, Form("dNdy_sys_%02d",m_liveRapidityProtonSpectra[iii]), avgAmpFirst_sys , 0.1*avgAmpFirst_sys);
          m_minimizer_sys->SetVariableLimits(iii, 0.0, avgAmpFirst_sys*10000.0);
        }else{
          m_minimizer_sys->SetVariable(iii, Form("dNdy_sys_%02d",m_liveRapidityProtonSpectra[iii]), ampStorage_sys[iii] , 0.1*ampStorage_sys[iii]);
          m_minimizer_sys->SetVariableLimits(iii, 0.0, ampStorage_sys[iii]*10000.0);
        }
      }

      m_minimizer_sys->SetVariable(counter, "Amp_T_sys" ,temp_fitInit_sys->GetParameter(0), 0.01);
      m_minimizer_sys->SetVariableLimits(counter,0.0001, 0.3);
      m_minimizer_sys->SetVariable(counter+1, "Mu_T_sys" ,m_cuts->getYCM(), 0.2);
      m_minimizer_sys->FixVariable(counter+1);
      m_minimizer_sys->SetVariable(counter+2, "Sigma_T_sys" ,temp_fitInit_sys->GetParameter(2), 2.0);
      m_minimizer_sys->SetVariableLimits(counter+2,0.0, 2.0);




      cout << "######################################################################" << endl;
      cout << "          STAGE 2   Proton Sys Fitting - Use Separate Rap Fit Results as Seeds to Simultaneous Fitter" << endl;
      //m_blastWave->SetParLimits(2,0.0,1.0);
      m_protonFittingStage = 2;
      //init_simul_blastWave();  //only do this if not initialized by single fits above
      m_minimizer_sys->SetPrintLevel(5);
      m_minimizer_sys->SetMaxIterations(3000);
      m_minimizer_sys->SetMaxFunctionCalls(200000);
      m_minimizer_sys->SetValidError(true);
      m_minimizer_sys->Minimize();
      int status_sys = m_minimizer_sys->Status();
      const double* finalParams_sys = m_minimizer_sys->X();
      if(status_sys == 0){
        cout << "Proton Sys Fit Status: " << status_sys << endl;
      }
      else{
        cout << "################################  First Pass Fit:  STATUS OF SYS FIT = " << status_sys << "   IS BAD!!!!!  ################################" << endl;
        cout << "Current Parameters: " << endl;
        for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size() + 3; iii++){
          cout << "  " << finalParams_sys[iii];
        }
        cout << endl;
        continue;
      }


            cout << "######################################################################" << endl;
      cout << "          STAGE 3   Proton Fitting Sys - Bootstrap Individual Amplitudes" << endl;


      for(int iii = 0; iii < m_liveRapidityProtonSpectra.size(); iii++){

        double rapidity = m_liveRapidityValueProtonSpectra[iii];

        TGraphErrors* spectrum = NULL;
        if(m_currentCharge == 1) spectrum = m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]];
        else spectrum = m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]];

        double dNdy_sys = finalParams_sys[iii];
        double dNdy_err_sys = sqrt( m_minimizer_sys->CovMatrix(iii,iii) );

        double temp_sys = finalParams_sys[m_liveRapidityProtonSpectra.size()]/TMath::CosH(finalParams_sys[m_liveRapidityProtonSpectra.size() + 2]*(rapidity - finalParams_sys[m_liveRapidityProtonSpectra.size()+1]));

        double tempErr_sys = sqrt( pow(temp_sys*m_minimizer_sys->CovMatrix(m_liveRapidityProtonSpectra.size(),m_liveRapidityProtonSpectra.size())/finalParams_sys[m_liveRapidityProtonSpectra.size()],2) + pow(temp_sys*m_minimizer_sys->CovMatrix(m_liveRapidityProtonSpectra.size()+2,m_liveRapidityProtonSpectra.size()+2)*TMath::TanH(finalParams_sys[m_liveRapidityProtonSpectra.size()+2]*(rapidity - finalParams_sys[m_liveRapidityProtonSpectra.size()+1]))*(rapidity - finalParams_sys[m_liveRapidityProtonSpectra.size()+1]),2) );

        double thermalHighmTm0 = spectrum->GetX()[3]+spectrum->GetErrorX(3);


        TF1* fitFunct_sys = new TF1(
          Form("SystematicFit_Cent%02d_yIndex%02d",m_currentCentIndex,m_liveRapidityProtonSpectra[iii]),
          "[0] * (x+[2]) * exp(-x/[1]) / ((2*3.14159265) * [1] * ([2]*[2] + 2*[2]*[1] + 2*[1]*[1]))",0.0,thermalHighmTm0);
        fitFunct_sys->SetParNames("dN/dy","T","m");
        fitFunct_sys->SetParameter(0,dNdy_sys);
        fitFunct_sys->SetParError(0,dNdy_err_sys);
        fitFunct_sys->SetParameter(1,temp_sys);
        fitFunct_sys->SetParError(1,tempErr_sys);
        fitFunct_sys->FixParameter(2,m_partInfo->GetParticleMass(m_currentPartIndex));




        TCanvas *finalCanvas = new TCanvas("finalCanvas","Final Canvas");
        finalCanvas->SetWindowSize(1300,700);
        finalCanvas->SetCanvasSize(1200,600);

        finalCanvas->cd();

        double smallYVal =  HistogramUtilities::findSmallestYVal(spectrum)*0.25;
        double largeXVal =  HistogramUtilities::findLargestXVal(spectrum)*1.3;
        if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame_sys = fittingCanvas->DrawFrame(0.0,smallYVal,largeXVal,HistogramUtilities::findLargestYVal(spectrum)*4.0);
        frame_sys->SetTitle(Form("p^{%s} Systematic Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
          m_cuts->getRapidityRangeLow(m_liveRapidityProtonSpectra[iii],m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(m_liveRapidityProtonSpectra[iii],m_currentPartIndex,1),
          m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
          //frame->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
          //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame_sys->GetXaxis()->SetTitle("m_{T}-m_{p} (GeV/c^{2})");
        frame_sys->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);

        spectrum->SetMarkerStyle(20);
        spectrum->Draw("P");
        fitFunct_sys->Draw("same");

        TPaveText *fitParsTxt_sys = new TPaveText(0.65,0.15,0.95,0.85,"NDC");
        fitParsTxt_sys->AddText(Form("dN/dy \t %f#pm%f",dNdy_sys,dNdy_err_sys));
        fitParsTxt_sys->AddText(Form("T \t %f#pm%f",temp_sys,tempErr_sys));
        fitParsTxt_sys->AddText(Form("m \t %f",m_partInfo->GetParticleMass(m_currentPartIndex)));

        fitParsTxt_sys->SetFillStyle(0);
        fitParsTxt_sys->SetBorderSize(5);

        fitParsTxt_sys->Draw("same");

        finalCanvas->Update();
        finalCanvas->SaveAs(Form("%s/%s/FinalFit_Sys_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
          m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_liveRapidityProtonSpectra[iii]));



        if(m_currentCharge == 1){

          m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdy_sys);
          m_dNdy_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdy_err_sys);

          m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,temp_sys);
          m_Temp_Plus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,tempErr_sys);

          m_systematicFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct_sys;

        }else{

          m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdy_sys);
          m_dNdy_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdy_err_sys);

          m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,temp_sys);
          m_Temp_Minus_Systematic[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,tempErr_sys);

          m_systematicFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct_sys;
        }//is plus minus

      }//rap loop



      //nominal fitting
      numSpectraToFit = m_liveRapidityProtonSpectra.size() - m_currentMidRapIndex;
      cout << "numSpectraToFit: " << numSpectraToFit << endl;
      cout << "total number of spectra: " << m_liveRapidityProtonSpectra.size() << endl;
      cout << "m_currentMidRapIndex: " << m_currentMidRapIndex << endl;
      m_minimizer = ROOT::Math::Factory::CreateMinimizer();
      m_chiSqrdFunctor = new ROOT::Math::Functor(this,&SpectraFitter::simultaneous_blastWave_betaConstr_forceSymmetry_ChiSqr,(numSpectraToFit) + 6);
      cout << "created chi squared functor with NDim " << m_chiSqrdFunctor->NDim() << "  functor: " << &SpectraFitter::simultaneous_blastWave_betaConstr_forceSymmetry_ChiSqr  << endl;
      m_minimizer->SetFunction(*m_chiSqrdFunctor);
      for(int iii = m_currentMidRapIndex; iii < (int) m_liveRapidityProtonSpectra.size(); iii++){
        if(useAvgParamsForSeparateFits){
          m_minimizer->SetVariable(iii - m_currentMidRapIndex, Form("A_%02d",m_liveRapidityProtonSpectra[iii]), avgAmpFirst , 0.1*avgAmpFirst);
          m_minimizer->SetVariableLimits(iii - m_currentMidRapIndex, 0.0, avgAmpFirst*10000.0);
        }else{
          m_minimizer->SetVariable(iii - m_currentMidRapIndex, Form("A_%02d",m_liveRapidityProtonSpectra[iii]), ampStorage[iii] , 0.1*ampStorage[iii - m_currentMidRapIndex]);
          m_minimizer->SetVariableLimits(iii - m_currentMidRapIndex, 0.0, ampStorage[iii]*10000.0);
        }
      }

      m_minimizer->SetVariable(numSpectraToFit, "T" ,tempNomFit->GetParameter(0), 0.01);
      m_minimizer->SetVariableLimits(numSpectraToFit,0.0, 2.0);
      m_minimizer->SetVariable(numSpectraToFit+1,"beta_p4",-0.06,0.15);
      m_minimizer->SetVariableLimits(numSpectraToFit+1,-10.0,0.0);
      m_minimizer->SetVariable(numSpectraToFit+2,"beta_shift",m_cuts->getYCM(),0.15);
      m_minimizer->FixVariable(numSpectraToFit+2);
      //test ben
      m_minimizer->SetVariable(numSpectraToFit+3,"beta_p2",-0.2,0.15);
      m_minimizer->SetVariableLimits(numSpectraToFit+3,-10,0.15);
      m_minimizer->SetVariable(numSpectraToFit+4,"beta_const",avgBetaSFirst,0.05);
      m_minimizer->SetVariableLimits(numSpectraToFit+4,0.0,1.0);
      if(SpectraFitter::getBlastWaveNFix() > 0){
        m_minimizer->SetVariable(numSpectraToFit+5,"n",SpectraFitter::getBlastWaveNFix(),0.05);
        m_minimizer->FixVariable(numSpectraToFit+5);
      }else{
        m_minimizer->SetVariable(numSpectraToFit+5,"n",avgNFirst,0.05);
        m_minimizer->SetVariableLimits(numSpectraToFit+5,0.0,5.0);
      }









      cout << "######################################################################" << endl;
      cout << "          STAGE 2   Proton Fitting - Use Separate Rap Fit Results as Seeds to Simultaneous Fitter" << endl;
      m_blastWave->SetParLimits(2,0.0,1.0);
      m_protonFittingStage = 2;
      //init_simul_blastWave();  //only do this if not initialized by single fits above
      m_minimizer->SetPrintLevel(5);
      m_minimizer->SetMaxIterations(3000);
      m_minimizer->SetMaxFunctionCalls(200000);
      m_minimizer->SetValidError(true);
      m_minimizer->Minimize();
      int status = m_minimizer->Status();
      const double* finalParams_RoundOne = m_minimizer->X();
      if(status == 0){
        cout << "Proton Fit Status: " << status << endl;
      }
      else{
        cout << "################################  First Pass Fit:  STATUS OF FIT = " << status << "   IS BAD!!!!!  ################################" << endl;
        cout << "Current Parameters: " << endl;
        for(int iii = 0; iii < (int) m_liveRapidityProtonSpectra.size() + 6; iii++){
          cout << "  " << finalParams_RoundOne[iii];
        }
        cout << endl;
        continue;
      }

      const double* finalParams = m_minimizer->X();
      double tempFinal = finalParams[numSpectraToFit];
      double tempFinalErr = sqrt( m_minimizer->CovMatrix(numSpectraToFit,numSpectraToFit) );
      cout << " ptrs: " << m_Proton_Temp_Plus_Nom << "   " << m_Proton_Temp_Minus_Nom << endl;
      if(!std::isnan(tempFinal) && !std::isnan(tempFinalErr)){
        if(m_currentCharge == 1){
          m_Proton_Temp_Plus_Nom->SetBinContent(m_currentCentIndex+1,tempFinal);
          m_Proton_Temp_Plus_Nom->SetBinError(m_currentCentIndex+1,tempFinalErr);
        }else{
          m_Proton_Temp_Minus_Nom->SetBinContent(m_currentCentIndex+1,tempFinal);
          m_Proton_Temp_Minus_Nom->SetBinError(m_currentCentIndex+1,tempFinalErr);
        }
      }


      cout << "Final Temperature: " << tempFinal << endl;
      //cout << "Final Beta_S: " << betaSFinal << endl;

      double covMatrix[110000];

      m_minimizer->GetCovMatrix(&covMatrix[0]);

      TMatrixDSym covMatrixDSym((numSpectraToFit) + 6, &covMatrix[0]);

      cout << "######################################################################" << endl;
      cout << "          STAGE 3   Proton Fitting - Bootstrap Individual Amplitudes" << endl;


      for(int iii = 0; iii < m_liveRapidityProtonSpectra.size(); iii++){
        cout << "rapidity value: " << m_liveRapidityValueProtonSpectra[iii] << endl;
        cout << "m_currentMidRapIndex: " << m_currentMidRapIndex << endl;
        cout << "current rapidity index: " << iii << endl;
        cout << "shift from midrapidity: " << iii - m_currentMidRapIndex << endl;
        cout << "mirror index: " << 2*m_currentMidRapIndex - iii << endl;
        double Amp;
        double AmpErr;
        if(iii < m_currentMidRapIndex){
          Amp = finalParams[abs(iii - m_currentMidRapIndex)];
          AmpErr = sqrt( m_minimizer->CovMatrix(abs(iii - m_currentMidRapIndex),abs(iii - m_currentMidRapIndex)));
        }else{
          Amp = finalParams[iii - m_currentMidRapIndex];
          AmpErr = sqrt( m_minimizer->CovMatrix(iii - m_currentMidRapIndex,iii - m_currentMidRapIndex) );
        }
        cout << "Amp: " << Amp << endl;
        double rapidity = m_liveRapidityProtonSpectra[iii];
        double betaSNow = finalParams[numSpectraToFit+1]*pow(m_liveRapidityValueProtonSpectra[iii]- finalParams[numSpectraToFit+2],4)+finalParams[numSpectraToFit+3]*pow(m_liveRapidityValueProtonSpectra[iii]- finalParams[numSpectraToFit+2],2)+finalParams[numSpectraToFit+4];
        double betaSNowError = sqrt(pow(m_liveRapidityValueProtonSpectra[iii]- finalParams[numSpectraToFit+2],8)*m_minimizer->CovMatrix(numSpectraToFit+1,numSpectraToFit+1)+pow(m_liveRapidityValueProtonSpectra[iii]- finalParams[numSpectraToFit+2],4)*m_minimizer->CovMatrix(numSpectraToFit+3,numSpectraToFit+3)+m_minimizer->CovMatrix(numSpectraToFit+4,numSpectraToFit+4)+pow(-4.0*finalParams[numSpectraToFit+1]*pow(m_liveRapidityValueProtonSpectra[iii]- numSpectraToFit+2,3)-2.0*finalParams[numSpectraToFit+3]*(m_liveRapidityValueProtonSpectra[iii]- finalParams[numSpectraToFit+2]),2)*m_minimizer->CovMatrix(numSpectraToFit+2,numSpectraToFit+2));
        cout << "Ready for bootstraper: Amp: " << Amp << " AmpErr: " << AmpErr << " Rap: " << rapidity << " BetaS: " << betaSNow << " Temp: " << tempFinal << endl;
        TF1* fitFunct = new TF1(
          Form("NominalFit_Cent%02d_yIndex%02d_blastwave",m_currentCentIndex,m_liveRapidityProtonSpectra[iii]),
          this,&SpectraFitter::blastWaveModelFit,0,10,6,"SpectraFitter","blastWaveModelFit");
        fitFunct->SetParNames("A","T_kin","#beta_S","W","R","m_p");
        fitFunct->SetParameter(0,Amp);
        fitFunct->SetParError(0,AmpErr);
        fitFunct->SetParameter(1,tempFinal);
        fitFunct->SetParameter(2,betaSNow);
        if(SpectraFitter::getBlastWaveNFix() > 0)fitFunct->FixParameter(3,SpectraFitter::getBlastWaveNFix());
        else{
          fitFunct->SetParameter(3,finalParams[numSpectraToFit+5]);
          fitFunct->SetParError(3,sqrt(m_minimizer->CovMatrix(numSpectraToFit+5,numSpectraToFit+5)));
        }
        fitFunct->FixParameter(4,1.0);
        fitFunct->SetParameter(5,m_partInfo->GetParticleMass(2));

        TCanvas *protonFinalCanvas = new TCanvas();
        protonFinalCanvas->SetWindowSize(1300,700);
        protonFinalCanvas->SetCanvasSize(1200,600);

        protonFinalCanvas->cd();

        double smallYVal;
        double largeXVal;
        if(pmIndex == 0){
          largeXVal =  HistogramUtilities::findLargestXVal(m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]])*1.3;
          smallYVal =  HistogramUtilities::findSmallestYVal(m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]])*0.25;
        }else if(pmIndex == 1){
          largeXVal =  HistogramUtilities::findLargestXVal(m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]])*1.3;
          smallYVal =  HistogramUtilities::findSmallestYVal(m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]])*0.25;
        }
        if(smallYVal < 0.0) smallYVal = 1e-6;
        TH1F *frame_nom = protonFinalCanvas->DrawFrame(0.0,smallYVal,largeXVal,(pmIndex==0)?HistogramUtilities::findLargestYVal(m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]])*4.0:HistogramUtilities::findLargestYVal(m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]])*4.0);
        frame_nom->SetTitle(Form("p^{%s} Systematic Spectra y=[%.2f,%.2f] %.0f-%.0f%% Centrality",pmIndex ? "-":"+",
          m_cuts->getRapidityRangeLow(m_liveRapidityProtonSpectra[iii],m_currentPartIndex,1),m_cuts->getRapidityRangeHigh(m_liveRapidityProtonSpectra[iii],m_currentPartIndex,1),
          m_cuts->getLowCentPercent(centIndex),m_cuts->getHighCentPercent(centIndex)));
          //frame->GetXaxis()->SetTitle("m_{T}-m_{K} (GeV/c^{2})");
          //frame->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{d^{2}N}{dm_{T}dy}");
        frame_nom->GetXaxis()->SetTitle("m_{T}-m_{p} (GeV/c^{2})");
        frame_nom->GetYaxis()->SetTitle("#frac{1}{N_{Evt}}#times#frac{1}{2#pi m_{T}}#times#frac{d^{2}N}{dm_{T}dy} (GeV/c^{2})^{-2}");
        gPad->SetLogy();
        gPad->SetRightMargin(0.4);

        protonFinalCanvas->SetLogy();
        if(pmIndex == 0) m_totalSpectra_Plus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]]->Draw("AP");
        else if(pmIndex == 1) m_totalSpectra_Minus[m_currentPartIndex][m_currentCentIndex][m_liveRapidityProtonSpectra[iii]]->Draw("AP");
        fitFunct->Draw("SAME");

        TPaveText *fitParsTxt = new TPaveText(0.65,0.15,0.95,0.85,"NDC");
        fitParsTxt->AddText(Form("A \t %f#pm%f",Amp,AmpErr));
        fitParsTxt->AddText(Form("T \t %f#pm%f",tempFinal,tempFinalErr));
        fitParsTxt->AddText(Form("#beta_{S} \t %f#pm%f",betaSNow,betaSNowError));
        if(SpectraFitter::getBlastWaveNFix() > 0)fitParsTxt->AddText(Form("n \t %f",SpectraFitter::getBlastWaveNFix()));
        else fitParsTxt->AddText(Form("n \t %f#pm%f",m_blastWave->GetParameter(3),m_blastWave->GetParError(3)));
        fitParsTxt->AddText(Form("R \t %f",1.0));
        fitParsTxt->AddText(Form("m \t %f",m_partInfo->GetParticleMass(m_currentPartIndex)));

        fitParsTxt->SetFillStyle(0);
        fitParsTxt->SetBorderSize(5);

        fitParsTxt->Draw("same");

        protonFinalCanvas->SaveAs(Form("%s/%s/FinalFit_Nom_Cent%02d_yIndex%02d.png",m_imageDir.c_str(),
                              m_partInfo->GetParticleName(m_currentPartIndex,m_currentCharge).Data(),m_currentCentIndex,m_liveRapidityProtonSpectra[iii]));

        delete protonFinalCanvas;


        vector<int> parsToKeep = {abs(iii - m_currentMidRapIndex),(int)(numSpectraToFit),(int)(numSpectraToFit+1),(int)(m_liveRapidityProtonSpectra.size()+2),(int)(numSpectraToFit+3),(int)(numSpectraToFit+4),(int)(numSpectraToFit+5),-999,-999,-999};

        double proPars[11] = {Amp,finalParams[numSpectraToFit],finalParams[numSpectraToFit+1],finalParams[numSpectraToFit+2],finalParams[numSpectraToFit+3],finalParams[numSpectraToFit+4],finalParams[numSpectraToFit+5],1.0,m_partInfo->GetParticleMass(2),m_liveRapidityValueProtonSpectra[iii]};


        TMatrixDSym proCovMatrix = PhysMath::reduceCovMatrix_keepPassedVector(covMatrixDSym,parsToKeep);



        TF1 *blastWave_notInvariant = PhysMath::blastWaveFunct_betaConstr_NotInvariant(Form("blastWave_notInvariant_Cent%02d_yIndex%02d",m_currentCentIndex,m_liveRapidityProtonSpectra[iii]),Amp,finalParams[numSpectraToFit],finalParams[numSpectraToFit+1],finalParams[numSpectraToFit+2],finalParams[numSpectraToFit+3],finalParams[numSpectraToFit+4],finalParams[numSpectraToFit+5],1.0,m_partInfo->GetParticleMass(2),m_liveRapidityValueProtonSpectra[iii]);


        double dNdy = blastWave_notInvariant->Integral(0,10);
        double dNdyErr = blastWave_notInvariant->IntegralError(0,10, proPars, proCovMatrix.GetMatrixArray(),0.1);
          cout << "dNdy: " << dNdy << " +/- " << dNdyErr/dNdy*100.0 << "%" << endl;
          if(m_currentCharge == 1){
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdy);
            m_dNdy_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdyErr);
            m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSNow);
            m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,betaSNowError);
            m_Temp_Plus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
            m_nominalFits_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
            //m_bootstrapData_Nom_Plus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
            //m_BetaS_Plus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSNow);
          }else{
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1, dNdy);
            m_dNdy_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,dNdyErr);
            m_BetaS_Minus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSNow);
            m_BetaS_Minus_Nominal[m_currentCentIndex]->SetBinError(m_liveRapidityProtonSpectra[iii]+1,betaSNowError);
            m_Temp_Minus_Nominal[m_currentPartIndex][m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,tempFinal);
            m_nominalFits_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = fitFunct;
            //m_bootstrapData_Nom_Minus[m_currentPartIndex][m_currentCentIndex][m_currentRapIndex] = integralHistoryHisto_Nom;
            //m_BetaS_Minus_Nominal[m_currentCentIndex]->SetBinContent(m_liveRapidityProtonSpectra[iii]+1,betaSFinal);
          }//is plus minus
      }//rap loop
    }// pm index
  }// cent index

}

