        double avgCent = 0.5*(m_cuts->getLowCentPercent(centIndex) + m_cuts->getHighCentPercent(centIndex));
        double centHalfWidth = fabs(m_cuts->getHighCentPercent(centIndex) - avgCent);
        int numPoints = m_FourPiYields_Nom_Plus[partIndex]->GetN();
        m_FourPiYields_Nom_Plus[partIndex]->SetPoint(numPoints, avgCent, fourPi);
        m_FourPiYields_Nom_Plus[partIndex]->SetPointError(numPoints, centHalfWidth , fourPiError);

