        m_gausFunct->SetParameter(1,mean);
        m_gausFunct->SetParLimits(1,m_dNdy_Plus_Systematic[partIndex][centIndex]->GetBinLowEdge(1),m_dNdy_Plus_Systematic[partIndex][centIndex]->GetBinLowEdge(m_dNdy_Plus_Systematic[partIndex][centIndex]->GetNbinsX()+1));
